export const generateCertificateOfLienDocument = async (caseData: Case): Promise<{ docUrl: string, title: string }> => {
    const config = await getConfig();
    // DEFENSIVE: Pull cost values from the argument case object to ensure latest values are used.
    const getReplacements = (c: Case) => {
        const cost = c.abatement?.costDetails;
        const laborCost = ((cost?.hours || 0) * (cost?.employees || 0) * (cost?.rate || 0)).toFixed(2);
        const totalCost = (cost?.total || 0).toFixed(2);

        return {
            '{{LEGAL_DESCRIPTION}}': c.abatement?.propertyInfo?.legalDescription || 'N/A',
            '{{TAX_ID}}': c.abatement?.propertyInfo?.taxId || 'N/A',
            '{{PARCEL_NUMBER}}': c.abatement?.propertyInfo?.parcelNumber || 'N/A',
            '{{STATEMENT_OF_COST_DATE}}': c.abatement?.statementOfCostDate || 'N/A',
            '{{ABATEMENT_LABOR_COST}}': laborCost,
            '{{ABATEMENT_TOTAL_COST}}': totalCost,
        };
    };
    return generateAbatementDocument(caseData, config?.google?.certificateOfLienTemplateUrl, "Certificate of Lien", "Certificate of Lien", getReplacements);
};

// --- ARCHIVE FUNCTIONALITY ---

const fetchBlobFromDrive = async (fileId: string): Promise<Blob> => {
    const token = await getAccessToken();
    const response = await fetch(`https://www.googleapis.com/drive/v3/files/${fileId}?alt=media`, {
        headers: { 'Authorization': `Bearer ${token}` }
    });
    if (!response.ok) throw new Error(`Failed to fetch file ${fileId}`);
    return response.blob();
};

const fetchDocAsPdf = async (fileId: string): Promise<Blob> => {
    const token = await getAccessToken();
    const response = await fetch(`https://www.googleapis.com/drive/v3/files/${fileId}/export?mimeType=application/pdf`, {
        headers: { 'Authorization': `Bearer ${token}` }
    });
    if (!response.ok) throw new Error(`Failed to export doc ${fileId} as PDF`);
    return response.blob();
};

// Helper: Adds a case's contents into a specific folder within a JSZip instance
const addCaseToZip = async (zipFolder: JSZip, caseData: Case) => {
    // 1. Create Case Report HTML
    let reportHtml = `
    <html>
    <head><style>body { font-family: sans-serif; padding: 2rem; } h1 { border-bottom: 1px solid #ccc; } .field { margin: 10px 0; } label { font-weight: bold; }</style></head>
    <body>
        <h1>Case Report: ${caseData.caseId}</h1>
        <div class="field"><label>Status:</label> ${caseData.status}</div>
        <div class="field"><label>Address:</label> ${caseData.address.street}</div>
        <div class="field"><label>Violation:</label> ${caseData.violation.type}</div>
        <div class="field"><label>Date Created:</label> ${caseData.dateCreated}</div>
        <hr/>
        <h3>Owner Info</h3>
        <div class="field"><label>Name:</label> ${caseData.ownerInfo.name}</div>
        <div class="field"><label>Mailing:</label> ${caseData.ownerInfo.mailingAddress}</div>
        <hr/>
        <h3>Case Notes</h3>
        <ul>
            ${caseData.evidence.notes.map(n => `<li><strong>${n.date}:</strong> ${n.text}</li>`).join('')}
        </ul>
    </body>
    </html>
    `;
    zipFolder.file("Case_Report.html", reportHtml);

    // 2. Photos
    const photoFolder = zipFolder.folder("Evidence Photos");
    const allPhotos = [...(caseData.evidence.photos || [])];
    if (caseData.abatement?.photos?.before) allPhotos.push(...caseData.abatement.photos.before);
    if (caseData.abatement?.photos?.after) allPhotos.push(...caseData.abatement.photos.after);

    const photoPromises = allPhotos.map(async (photo, i) => {
        try {
            const blob = await fetchBlobFromDrive(photo.id);
            const ext = blob.type.split('/')[1] || 'jpg';
            photoFolder?.file(`Photo_${i+1}.${ext}`, blob);
        } catch (e) {
            console.warn(`Failed to download photo ${photo.id}`, e);
            photoFolder?.file(`Photo_${i+1}_FAILED.txt`, "Could not download");
        }
    });

    // 3. Generated Documents
    const docFolder = zipFolder.folder("Documents");
    const docPromises = [];

    caseData.notices.forEach((n, i) => {
        docPromises.push(async () => {
            try {
                const docId = getDocIdFromUrl(n.docUrl);
                const blob = await fetchDocAsPdf(docId);
                docFolder?.file(`${n.title}.pdf`, blob);
            } catch (e) {
                console.warn(`Failed to download notice ${n.title}`, e);
            }
        });
    });

    if (caseData.abatement?.statementOfCostDocUrl) {
        docPromises.push(async () => {
             try {
                const docId = getDocIdFromUrl(caseData.abatement!.statementOfCostDocUrl!);
                const blob = await fetchDocAsPdf(docId);
                docFolder?.file(`Statement_of_Cost.pdf`, blob);
            } catch(e) { console.warn(e); }
        });
    }
    if (caseData.abatement?.noticeOfLienDocUrl) {
        docPromises.push(async () => {
             try {
                const docId = getDocIdFromUrl(caseData.abatement!.noticeOfLienDocUrl!);
                const blob = await fetchDocAsPdf(docId);
                docFolder?.file(`Notice_of_Lien.pdf`, blob);
            } catch(e) { console.warn(e); }
        });
    }

    await Promise.all([...photoPromises, ...docPromises.map(fn => fn())]);
};

export const downloadCaseArchive = async (caseData: Case) => {
    const zip = new JSZip();
    // For single case download, put everything in the root of the zip
    await addCaseToZip(zip, caseData); 
    const content = await zip.generateAsync({ type: "blob" });
    const filename = `${caseData.address.street.replace(/[^a-z0-9]/gi, '_')}__${caseData.caseId}.zip`;
    saveAs(content, filename);
};

export const downloadPropertyArchive = async (property: Property, cases: Case[]) => {
    const zip = new JSZip();
    const safeAddr = property.streetAddress.replace(/[^a-z0-9 ]/gi, '_');

    // Folder structure: ZipRoot -> CaseID -> Content
    for (const c of cases) {
        const caseFolder = zip.folder(`${c.caseId} - ${c.violation.type.replace(/[^a-z0-9]/gi, '_')}`);
        if (caseFolder) {
            await addCaseToZip(caseFolder, c);
        }
    }

    const content = await zip.generateAsync({ type: "blob" });
    const filename = `Property_Records_${safeAddr}.zip`;
    saveAs(content, filename);
};

export const downloadFullArchive = async (properties: Property[], cases: Case[], onProgress: (msg: string) => void) => {
    const zip = new JSZip();
    let count = 0;
    const total = properties.length;

    for (const prop of properties) {
        count++;
        onProgress(`Processing ${prop.streetAddress} (${count}/${total})...`);

        const propCases = cases.filter(c => c.address.street.toLowerCase() === prop.streetAddress.toLowerCase());
        if (propCases.length === 0) continue;

        const safeAddr = prop.streetAddress.replace(/[^a-z0-9 ]/gi, '_');
        // Folder structure: ZipRoot -> Address -> CaseID -> Content
        const propFolder = zip.folder(safeAddr);

        if (propFolder) {
             for (const c of propCases) {
                const caseFolder = propFolder.folder(`${c.caseId} - ${c.violation.type.replace(/[^a-z0-9]/gi, '_')}`);
                if (caseFolder) {
                    await addCaseToZip(caseFolder, c);
                }
            }
        }
    }

    onProgress("Compressing archive... (this may take a moment)");
    const content = await zip.generateAsync({ type: "blob" });
    const filename = `Full_Code_Enforcement_Archive_${new Date().toISOString().split('T')[0]}.zip`;
    saveAs(content, filename);
};


export const dataService = {
    getAllData: async (): Promise<SheetData> => getSheetData(),
    getAllCases: async (): Promise<Case[]> => (await getSheetData()).cases,
    getAllProperties: async (): Promise<Property[]> => (await getSheetData()).properties || [],
    getCaseById: async (id: string): Promise<Case | undefined> => (await getSheetData()).cases.find(c => c.id === id),
    saveCase: async (caseData: Case): Promise<Case> => {
        const data = await getSheetData();
        const index = data.cases.findIndex(c => c.id === caseData.id);
        if (index > -1) {
            data.cases[index] = caseData;
        } else {
            data.cases.push(caseData);
        }
        await writeSheetData(data);
        return caseData;
    },
    saveProperties: async (properties: Property[]): Promise<void> => {
        const data = await getSheetData();
        data.properties = properties;
        await writeSheetData(data);
    },
    deleteCase: async (caseId: string): Promise<void> => {
        const data = await getSheetData();
        const initialLength = data.cases.length;
        data.cases = data.cases.filter(c => c.id !== caseId);
        if (data.cases.length === initialLength) {
            console.warn(`Case with ID ${caseId} not found for deletion.`);
        }
        await writeSheetData(data);
    },
    uploadCasePhotos,
    uploadAbatementPhotos,
    downloadCaseArchive,
    downloadPropertyArchive,
    downloadFullArchive
};

import React, { useState, useEffect, useRef } from 'react';
import { Case, PhotoWithMeta, EvidencePhoto, Property } from '../types';
import { initialAddressState, initialOwnerState, initialViolationState, VIOLATIONS_LIST, COMPLIANCE_DAYS } from '../constants';
import { analyzePhotoWithAI, getAIService } from '../aiService';
import { dataService } from '../googleSheetsService';
import CameraView from './CameraView';

interface NewCaseFormProps {
    onSave: (draftCase: (Partial<Case> & { _tempPhotos?: PhotoWithMeta[] })) => void;
    onCancel: () => void;
    properties: Property[];
    draftCase: (Partial<Case> & { _tempPhotos?: PhotoWithMeta[] }) | null;
    onUpdateDraft: (draft: (Partial<Case> & { _tempPhotos?: PhotoWithMeta[] }) | null) => void;
}

const NewCaseForm: React.FC<NewCaseFormProps> = ({ onSave, onCancel, properties, draftCase, onUpdateDraft }) => {
    // UI-specific state
    const [showCamera, setShowCamera] = useState(false);
    const [isAnalyzing, setIsAnalyzing] = useState(false);
    const [aiError, setAiError] = useState('');
    const [isSaving, setIsSaving] = useState(false); 
    const [lookupMessage, setLookupMessage] = useState('');
    const fileInputRef = useRef<HTMLInputElement>(null);

    const genAI = getAIService();

    const caseId = draftCase?.caseId || '';
    const address = draftCase?.address || initialAddressState;
    const owner = draftCase?.ownerInfo || initialOwnerState;
    const ownerUnknown = draftCase?.ownerInfoStatus === 'UNKNOWN';
    const violation = draftCase?.violation || initialViolationState;
    const isVacant = draftCase?.isVacant || false;
    const photos = draftCase?._tempPhotos || [];
    const violationManual = (violation.type === 'Other (Manual Entry)' && draftCase?.violation) || initialViolationState;

    const updateDraft = (updates: Partial<Case> & { _tempPhotos?: PhotoWithMeta[] }) => {
        onUpdateDraft({ ...draftCase!, ...updates });
    };

    const handleAddressLookup = () => {
        const trimmedAddress = address.street.trim();
        if (!trimmedAddress) {
            setLookupMessage('Please enter an address to look up.');
            return;
        }
        const foundProperty = properties.find(p => p.streetAddress.toLowerCase() === trimmedAddress.toLowerCase());

        if (foundProperty) {
            updateDraft({
                ownerInfo: { ...initialOwnerState, ...foundProperty.ownerInfo },
                isVacant: foundProperty.isVacant,
                ownerInfoStatus: 'KNOWN'
            });
            setLookupMessage('Success: Owner and property info have been pre-filled from the directory.');
        } else {
            setLookupMessage('Info: No existing property found for this address.');
        }
    };

    const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
        const files = e.target.files;
        if (!files || files.length === 0) return;

        const newPhotosPromises = Array.from(files).map(file => {
            return new Promise<PhotoWithMeta>((resolve) => {
                const reader = new FileReader();
                reader.onload = () => {
                    resolve({
                        file,
                        dataUrl: reader.result as string
                    });
                };
                reader.readAsDataURL(file);
            });
        });

        Promise.all(newPhotosPromises).then(newPhotos => {
            updateDraft({ _tempPhotos: [...photos, ...newPhotos] });
            // Clear input so same file can be selected again if needed
            if (fileInputRef.current) fileInputRef.current.value = '';
        });
    };

    const handleSubmit = (e: React.FormEvent) => {
        e.preventDefault();
        if (!draftCase) return;
        setIsSaving(true);

        const finalViolation = violation.type === 'Other (Manual Entry)' ? violationManual : violation;
        const isOwnerInfoValid = ownerUnknown || (owner.name && owner.mailingAddress);

        if (!draftCase.caseId || !address.street || finalViolation.type === 'Select a Violation...' || !isOwnerInfoValid) {
            alert("Please fill in Case Number, Address, select a Violation, and provide Owner Info (or mark as unknown).");
            setIsSaving(false);
            return;
        }

        onSave(draftCase);
    };

    const handleViolationChange = (e: React.ChangeEvent<HTMLSelectElement>) => {
        const selected = VIOLATIONS_LIST.find(v => v.type === e.target.value) || initialViolationState;
        updateDraft({ violation: selected });
    };

    const handleAnalyzePhoto = async () => {
        const photoToAnalyze = photos[0]?.file;
        if (!photoToAnalyze || !genAI) return;
        setIsAnalyzing(true);
        setAiError('');
        try {
            const result = await analyzePhotoWithAI(photoToAnalyze);
            const updates: Partial<Case> = {};
            if (result.address?.street) updates.address = { ...address, street: result.address.street };
            if (result.violation) updates.violation = result.violation;
            updateDraft(updates);
        } catch (e: any) {
            setAiError(`AI Analysis Failed: ${e.message}`);
        } finally {
            setIsAnalyzing(false);
        }
    };

    return (
        <>
        {showCamera && <CameraView 
            mode="single-case"
            onDone={(p) => { 
                updateDraft({ _tempPhotos: [...photos, ...p] });
                setShowCamera(false); 
            }} 
            onCancel={() => setShowCamera(false)} 
        />}
        <form onSubmit={handleSubmit} className="tab-content">
            <div className="card">
                <h2>Property & Photos</h2>
                 <div className="form-group">
                    <label>Case Number (Firm-Specific ID)</label>
                    <input type="text" value={caseId} onChange={e => updateDraft({ caseId: e.target.value })} required />
                </div>
                 <div className="form-group">
                    <label>Street Address</label>
                    <div className="input-with-button">
                        <input type="text" value={address.street} onChange={e => { updateDraft({ address: {...address, street: e.target.value}}); setLookupMessage(''); }} required />
                        <button type="button" className="button" onClick={handleAddressLookup}>Look up</button>
                    </div>
                    {lookupMessage && <p className={`helper-text ${lookupMessage.startsWith('Success') ? 'success-message' : 'info-box'}`} style={{padding: '0.5rem', marginTop: '0.5rem'}}>{lookupMessage}</p>}
                </div>
                <div className="form-group"><label><input type="checkbox" checked={isVacant} onChange={e => updateDraft({ isVacant: e.target.checked })} /> Mark as vacant</label></div>

                <h4>Evidence Photos ({photos.length})</h4>
                <div className="photo-gallery" style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fill, minmax(80px, 1fr))', gap: '8px', margin: '1rem 0' }}>
                    {photos.map((p, i) => (
                        <div key={i} className="photo-thumbnail" style={{ aspectRatio: '1', overflow: 'hidden', borderRadius: '8px', border: '1px solid var(--border-color)' }}>
                            <img src={p.dataUrl} alt={`Evidence photo ${i+1}`} style={{ width: '100%', height: '100%', objectFit: 'cover' }}/>
                        </div>
                    ))}
                </div>

                <div className="button-group" style={{marginTop: '1rem'}}>
                    <button type="button" className="button" onClick={() => setShowCamera(true)}>Open Camera</button>
                    <button type="button" className="button secondary-action" onClick={() => fileInputRef.current?.click()}>Upload Photos</button>
                    <input 
                        type="file" 
                        ref={fileInputRef} 
                        style={{ display: 'none' }} 
                        multiple 
                        accept="image/*" 
                        onChange={handleFileUpload}
                    />
                    {genAI && <button type="button" className="button secondary-action" onClick={handleAnalyzePhoto} disabled={isAnalyzing || photos.length === 0}>{isAnalyzing ? <span className="loader"/> : 'Analyze with AI'}</button>}
                </div>
                {aiError && <p className="error-message" style={{marginTop: '1rem'}}>{aiError}</p>}
            </div>

            <div className="card">
                <h2>Owner Information</h2>
                <div className="form-group"><label><input type="checkbox" checked={ownerUnknown} onChange={e => updateDraft({ ownerInfoStatus: e.target.checked ? 'UNKNOWN' : 'KNOWN' })} /> Owner information is unknown</label></div>
                <div className="form-group"><label>Owner Name</label><input type="text" value={owner.name} onChange={e => updateDraft({ ownerInfo: {...owner, name: e.target.value}})} required={!ownerUnknown} disabled={ownerUnknown} /></div>
                <div className="form-group">
                    <label>Mailing Address</label>
                    <textarea value={owner.mailingAddress} onChange={e => updateDraft({ ownerInfo: {...owner, mailingAddress: e.target.value}})} required={!ownerUnknown} disabled={ownerUnknown}></textarea>
                    <p className="helper-text">For multi-line addresses on envelopes, use the Enter/Return key for line breaks.</p>
                </div>
            </div>

            <div className="card">
                <h2>Violation Details</h2>
                <div className="form-group"><label>Violation Type</label><select value={violation.type} onChange={handleViolationChange} required><option disabled>Select a Violation...</option>{VIOLATIONS_LIST.map(v => <option key={v.type} value={v.type}>{v.type}</option>)}</select></div>
                {violation.type === 'Other (Manual Entry)' ? (
                    <>
                        <div className="form-group"><label>Ordinance</label><input type="text" value={violationManual.ordinance} onChange={e => updateDraft({ violation: {...violationManual, ordinance: e.target.value}})} /></div>
                        <div className="form-group"><label>Description</label><textarea value={violationManual.description} onChange={e => updateDraft({ violation: {...violationManual, description: e.target.value}})} /></div>
                    </>
                ) : (
                    <>
                        <div className="form-group readonly"><label>Ordinance</label><div className="form-value">{violation.ordinance || 'N/A'}</div></div>
                        <div className="form-group readonly"><label>Description</label><div className="form-value">{violation.description || 'N/A'}</div></div>
                    </>
                )}
            </div>

            <div className="button-group" style={{ justifyContent: 'flex-end'}}><button type="button" className="button secondary-action" onClick={onCancel} disabled={isSaving}>Cancel</button>
            <button type="submit" className="button primary-action" disabled={isSaving}>
                {isSaving ? <span className="loader" /> : 'Save Case'}
            </button>
            </div>
        </form>
        </>
    );
};

export default NewCaseForm;

import React, { useState, useEffect, useRef } from 'react';
import { PhotoWithMeta } from '../types';

interface CameraViewProps {
    mode: 'single-case' | 'patrol';
    onCancel?: () => void;
    onDone?: (photos: PhotoWithMeta[]) => void;
    onSaveSet?: (photos: PhotoWithMeta[]) => void;
    onFinishPatrol?: (photos: PhotoWithMeta[]) => void;
}

const CameraView: React.FC<CameraViewProps> = ({ mode, onCancel, onDone, onSaveSet, onFinishPatrol }) => {
    const videoRef = useRef<HTMLVideoElement>(null);
    const [stream, setStream] = useState<MediaStream | null>(null);
    const [imageCapture, setImageCapture] = useState<ImageCapture | null>(null);
    const [capturedPhotos, setCapturedPhotos] = useState<PhotoWithMeta[]>([]);

    const [zoom, setZoom] = useState(1);
    const [zoomCapabilities, setZoomCapabilities] = useState<{min: number, max: number, step: number} | null>(null);
    const [torch, setTorch] = useState(false);
    const [torchAvailable, setTorchAvailable] = useState(false);

    useEffect(() => {
        let activeStream: MediaStream | null = null;
        const videoConstraints = {
            facingMode: 'environment',
            width: { ideal: 1920 },
            height: { ideal: 1080 }
        };

        navigator.mediaDevices.getUserMedia({ video: videoConstraints })
            .then(mediaStream => {
                activeStream = mediaStream;
                setStream(mediaStream);
                if (videoRef.current) {
                    videoRef.current.srcObject = mediaStream;
                    videoRef.current.play().catch(e => console.warn("Video play failed", e));
                }
                const track = mediaStream.getVideoTracks()[0];

                if (typeof ImageCapture !== 'undefined') {
                    setImageCapture(new ImageCapture(track));
                } else {
                    console.warn("ImageCapture API not supported, falling back to canvas method.");
                }

                const capabilities = track.getCapabilities();
                if (capabilities.zoom) {
                    setZoomCapabilities({
                        min: capabilities.zoom.min,
                        max: capabilities.zoom.max,
                        step: capabilities.zoom.step,
                    });
                    setZoom(capabilities.zoom.min);
                }
                if (capabilities.torch) {
                    setTorchAvailable(true);
                }
            })
            .catch(err => {
                console.error("Could not access camera.", err);
                alert("Could not access camera. Try the 'Upload' option if the camera fails to load.");
            });

        return () => { activeStream?.getTracks().forEach(track => track.stop()); };
    }, []);

    useEffect(() => {
        if (!stream || !zoomCapabilities) return;
        const track = stream.getVideoTracks()[0];
        track.applyConstraints({ advanced: [{ zoom: zoom }] }).catch(e => console.warn("Could not apply zoom", e));
    }, [zoom, stream, zoomCapabilities]);

    useEffect(() => {
        if (!stream || !torchAvailable) return;
        const track = stream.getVideoTracks()[0];
        track.applyConstraints({ advanced: [{ torch: torch }] }).catch(e => console.warn("Could not apply torch", e));
    }, [torch, stream, torchAvailable]);

    const addTimestampToBlob = (blob: Blob): Promise<Blob> => {
        return new Promise((resolve, reject) => {
            const img = new Image();
            const url = URL.createObjectURL(blob);
            img.onload = () => {
                const canvas = document.createElement('canvas');
                canvas.width = img.width;
                canvas.height = img.height;
                const ctx = canvas.getContext('2d');
                if (!ctx) {
                    URL.revokeObjectURL(url);
                    return reject(new Error('Could not get canvas context'));
                }

                ctx.drawImage(img, 0, 0);

                const timestamp = new Date().toLocaleString('en-US', {
                    year: 'numeric', month: 'short', day: 'numeric',
                    hour: '2-digit', minute: '2-digit', second: '2-digit', hour12: true,
                });

                const fontSize = Math.max(24, Math.min(96, Math.round(img.width * 0.03))); 
                const padding = fontSize * 0.5;
                ctx.font = `bold ${fontSize}px 'Roboto', sans-serif`;
                ctx.textAlign = 'right';
                ctx.textBaseline = 'bottom';

                const textMetrics = ctx.measureText(timestamp);
                const textWidth = textMetrics.width;
                const textHeight = fontSize; 

                const bgX = canvas.width - textWidth - padding * 2;
                const bgY = canvas.height - textHeight - padding * 1.5;
                const bgWidth = textWidth + padding * 2;
                const bgHeight = textHeight + padding * 1.5;

                ctx.fillStyle = 'rgba(0, 0, 0, 0.6)';
                ctx.fillRect(bgX, bgY, bgWidth, bgHeight);

                ctx.fillStyle = 'white';
                ctx.fillText(timestamp, canvas.width - padding, canvas.height - padding);

                canvas.toBlob(
                    (newBlob) => {
                        URL.revokeObjectURL(url);
                        if (newBlob) resolve(newBlob);
                        else reject(new Error('Canvas toBlob failed.'));
                    },
                    'image/jpeg',
                    0.95
                );
            };
            img.onerror = () => {
                URL.revokeObjectURL(url);
                reject(new Error('Failed to load image.'));
            };
            img.src = url;
        });
    };

    const handleCapture = async () => {
        try {
            let originalBlob: Blob;
            if (imageCapture) {
                originalBlob = await imageCapture.takePhoto();
            } else if (videoRef.current) {
                originalBlob = await new Promise<Blob>((resolve, reject) => {
                    const canvas = document.createElement('canvas');
                    canvas.width = videoRef.current!.videoWidth;
                    canvas.height = videoRef.current!.videoHeight;
                    canvas.getContext('2d')?.drawImage(videoRef.current!, 0, 0);
                    canvas.toBlob((blob) => blob ? resolve(blob) : reject(new Error("Canvas fallback failed.")), 'image/jpeg', 1.0);
                });
            } else {
                throw new Error("No video source.");
            }

            const timestampedBlob = await addTimestampToBlob(originalBlob);

            const file = new File([timestampedBlob], `capture-${Date.now()}.jpg`, { type: 'image/jpeg' });
            const reader = new FileReader();
            reader.onload = () => {
                const dataUrl = reader.result as string;
                const newPhoto: PhotoWithMeta = { file, dataUrl };
                setCapturedPhotos(prev => [...prev, newPhoto]);
            };
            reader.readAsDataURL(file);

        } catch (error) {
            console.error('Capture failed:', error);
            alert(`Capture failed: ${error instanceof Error ? error.message : String(error)}`);
        }
    };

    const handleDeletePhoto = (index: number) => {
        setCapturedPhotos(prev => prev.filter((_, i) => i !== index));
    };

    const handleSaveAndNext = () => {
        if (onSaveSet) {
            onSaveSet(capturedPhotos);
            setCapturedPhotos([]);
        }
    };

    return (
        <div className="camera-overlay">
            <div className="camera-video-wrapper">
                <video 
                    ref={videoRef} 
                    autoPlay 
                    playsInline 
                    muted 
                    className="camera-video" 
                />
            </div>

            <div className="camera-top-controls">
                {torchAvailable && (
                    <button className={`camera-icon-button ${torch ? 'active' : ''}`} onClick={() => setTorch(!torch)} aria-label="Toggle Flash">
                        <svg xmlns="http://www.w3.org/2000/svg" width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><polygon points="13 2 3 14 12 14 11 22 21 10 12 10 13 2"></polygon></svg>
                    </button>
                )}
            </div>

            {capturedPhotos.length > 0 && (
                <div className="captured-photos-bar">
                    {capturedPhotos.map((p, i) => 
                        <div key={i} className="captured-thumbnail">
                            <img src={p.dataUrl} alt={`Captured photo ${i+1}`} />
                            <button className="delete-photo" onClick={() => handleDeletePhoto(i)}>&times;</button>
                        </div>
                    )}
                </div>
            )}

            {zoomCapabilities && (
                <input type="range" className="camera-zoom-slider" min={zoomCapabilities.min} max={zoomCapabilities.max} step={zoomCapabilities.step} value={zoom} onChange={e => setZoom(parseFloat(e.target.value))} />
            )}

            <div className="camera-controls">
                {mode === 'single-case' ? (
                    <>
                        <button className="camera-action-button" onClick={onCancel}>Cancel</button>
                        <button className="capture-button" onClick={handleCapture} aria-label="Capture photo"><div className="capture-button-inner" /></button>
                        <button className="camera-action-button" onClick={() => onDone && onDone(capturedPhotos)} disabled={capturedPhotos.length === 0}>Done ({capturedPhotos.length})</button>
                    </>
                ) : (
                    <>
                        <button className="camera-action-button" onClick={() => onFinishPatrol && onFinishPatrol(capturedPhotos)}>Finish Patrol</button>
                        <button className="capture-button" onClick={handleCapture} aria-label="Capture photo"><div className="capture-button-inner" /></button>
                        <button className="camera-action-button" onClick={handleSaveAndNext} disabled={capturedPhotos.length === 0}>Save &amp; Next</button>
                    </>
                )}
            </div>
        </div>
    );
};

