import React, { useState, useEffect, useRef } from 'react';
import { PhotoWithMeta } from '../types';

interface CameraViewProps {
    mode: 'single-case' | 'patrol';
    onCancel?: () => void;
    onDone?: (photos: PhotoWithMeta[]) => void;
    onSaveSet?: (photos: PhotoWithMeta[]) => void;
    onFinishPatrol?: (photos: PhotoWithMeta[]) => void;
}

const CameraView: React.FC<CameraViewProps> = ({ mode, onCancel, onDone, onSaveSet, onFinishPatrol }) => {
    const videoRef = useRef<HTMLVideoElement>(null);
    const [stream, setStream] = useState<MediaStream | null>(null);
    const [imageCapture, setImageCapture] = useState<ImageCapture | null>(null);
    const [capturedPhotos, setCapturedPhotos] = useState<PhotoWithMeta[]>([]);

    const [zoom, setZoom] = useState(1);
    const [zoomCapabilities, setZoomCapabilities] = useState<{min: number, max: number, step: number} | null>(null);
    const [torch, setTorch] = useState(false);
    const [torchAvailable, setTorchAvailable] = useState(false);

    useEffect(() => {
        let activeStream: MediaStream | null = null;
        const videoConstraints = {
            facingMode: 'environment',
            width: { ideal: 1920 },
            height: { ideal: 1080 }
        };

        navigator.mediaDevices.getUserMedia({ video: videoConstraints })
            .then(mediaStream => {
                activeStream = mediaStream;
                setStream(mediaStream);
                if (videoRef.current) {
                    videoRef.current.srcObject = mediaStream;
                    videoRef.current.play().catch(e => console.warn("Video play failed", e));
                }
                const track = mediaStream.getVideoTracks()[0];

                if (typeof ImageCapture !== 'undefined') {
                    setImageCapture(new ImageCapture(track));
                }

                const capabilities = track.getCapabilities();
                if (capabilities.zoom) {
                    setZoomCapabilities({
                        min: capabilities.zoom.min,
                        max: capabilities.zoom.max,
                        step: capabilities.zoom.step || 0.1,
                    });
                    setZoom(capabilities.zoom.min);
                }
                if (capabilities.torch) {
                    setTorchAvailable(true);
                }
            })
            .catch(err => {
                console.error("Could not access camera.", err);
                alert("Could not access camera. Try the 'Upload' option if the camera fails to load.");
            });

        return () => { activeStream?.getTracks().forEach(track => track.stop()); };
    }, []);

    useEffect(() => {
        if (!stream || !zoomCapabilities) return;
        const track = stream.getVideoTracks()[0];
        track.applyConstraints({ advanced: [{ zoom: zoom }] }).catch(e => console.warn("Could not apply zoom", e));
    }, [zoom, stream, zoomCapabilities]);

    useEffect(() => {
        if (!stream || !torchAvailable) return;
        const track = stream.getVideoTracks()[0];
        track.applyConstraints({ advanced: [{ torch: torch }] }).catch(e => console.warn("Could not apply torch", e));
    }, [torch, stream, torchAvailable]);

    const addTimestampToBlob = (blob: Blob): Promise<Blob> => {
        return new Promise((resolve, reject) => {
            const img = new Image();
            const url = URL.createObjectURL(blob);
            img.onload = () => {
                const canvas = document.createElement('canvas');
                canvas.width = img.width;
                canvas.height = img.height;
                const ctx = canvas.getContext('2d');
                if (!ctx) {
                    URL.revokeObjectURL(url);
                    return reject(new Error('Could not get canvas context'));
                }

                ctx.drawImage(img, 0, 0);

                const timestamp = new Date().toLocaleString('en-US', {
                    year: 'numeric', month: 'short', day: 'numeric',
                    hour: '2-digit', minute: '2-digit', second: '2-digit', hour12: true,
                });

                const fontSize = Math.max(24, Math.min(96, Math.round(img.width * 0.03))); 
                const padding = fontSize * 0.5;
                ctx.font = `bold ${fontSize}px 'Roboto', sans-serif`;
                ctx.textAlign = 'right';
                ctx.textBaseline = 'bottom';

                const textMetrics = ctx.measureText(timestamp);
                const textWidth = textMetrics.width;
                const textHeight = fontSize; 

                const bgX = canvas.width - textWidth - padding * 2;
                const bgY = canvas.height - textHeight - padding * 1.5;
                const bgWidth = textWidth + padding * 2;
                const bgHeight = textHeight + padding * 1.5;

                ctx.fillStyle = 'rgba(0, 0, 0, 0.6)';
                ctx.fillRect(bgX, bgY, bgWidth, bgHeight);

                ctx.fillStyle = 'white';
                ctx.fillText(timestamp, canvas.width - padding, canvas.height - padding);

                canvas.toBlob(
                    (newBlob) => {
                        URL.revokeObjectURL(url);
                        if (newBlob) resolve(newBlob);
                        else reject(new Error('Canvas toBlob failed.'));
                    },
                    'image/jpeg',
                    0.95
                );
            };
            img.onerror = () => {
                URL.revokeObjectURL(url);
                reject(new Error('Failed to load image.'));
            };
            img.src = url;
        });
    };

    const handleCapture = async () => {
        try {
            let originalBlob: Blob;
            if (imageCapture) {
                originalBlob = await imageCapture.takePhoto();
            } else if (videoRef.current) {
                originalBlob = await new Promise<Blob>((resolve, reject) => {
                    const canvas = document.createElement('canvas');
                    canvas.width = videoRef.current!.videoWidth;
                    canvas.height = videoRef.current!.videoHeight;
                    canvas.getContext('2d')?.drawImage(videoRef.current!, 0, 0);
                    canvas.toBlob((blob) => blob ? resolve(blob) : reject(new Error("Canvas fallback failed.")), 'image/jpeg', 1.0);
                });
            } else {
                throw new Error("No video source.");
            }

            const timestampedBlob = await addTimestampToBlob(originalBlob);

            const file = new File([timestampedBlob], `capture-${Date.now()}.jpg`, { type: 'image/jpeg' });
            const reader = new FileReader();
            reader.onload = () => {
                const dataUrl = reader.result as string;
                const newPhoto: PhotoWithMeta = { file, dataUrl };
                setCapturedPhotos(prev => [...prev, newPhoto]);
            };
            reader.readAsDataURL(file);

        } catch (error) {
            console.error('Capture failed:', error);
            alert(`Capture failed: ${error instanceof Error ? error.message : String(error)}`);
        }
    };

    const handleDeletePhoto = (index: number) => {
        setCapturedPhotos(prev => prev.filter((_, i) => i !== index));
    };

    const handleSaveAndNext = () => {
        if (onSaveSet) {
            onSaveSet(capturedPhotos);
            setCapturedPhotos([]);
        }
    };

    return (
        <div className="camera-overlay">
            <div className="camera-video-wrapper">
                <video ref={videoRef} autoPlay playsInline muted className="camera-video" />

                <div className="camera-top-controls">
                    {torchAvailable && (
                        <button className={`camera-icon-button ${torch ? 'active' : ''}`} onClick={() => setTorch(!torch)} aria-label="Toggle Flash">
                            <svg xmlns="http://www.w3.org/2000/svg" width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><polygon points="13 2 3 14 12 14 11 22 21 10 12 10 13 2"></polygon></svg>
                        </button>
                    )}
                </div>
            </div>

            {capturedPhotos.length > 0 && (
                <div className="captured-photos-bar">
                    {capturedPhotos.map((p, i) => 
                        <div key={i} className="captured-thumbnail">
                            <img src={p.dataUrl} alt={`Captured photo ${i+1}`} />
                            <button className="delete-photo" onClick={() => handleDeletePhoto(i)}>&times;</button>
                        </div>
                    )}
                </div>
            )}

            <div className="camera-controls-wrapper">
                {zoomCapabilities && (
                    <div className="camera-zoom-row">
                        <svg xmlns="http://www.w3.org/2000/svg" width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="white" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><circle cx="11" cy="11" r="8"></circle><line x1="21" y1="21" x2="16.65" y2="16.65"></line><line x1="11" y1="8" x2="11" y2="14"></line><line x1="8" y1="11" x2="14" y2="11"></line></svg>
                        <input 
                            type="range" 
                            className="camera-zoom-slider" 
                            min={zoomCapabilities.min} 
                            max={zoomCapabilities.max} 
                            step={zoomCapabilities.step} 
                            value={zoom} 
                            onChange={e => setZoom(parseFloat(e.target.value))} 
                        />
                    </div>
                )}

                <div className="camera-main-controls">
                    {mode === 'single-case' ? (
                        <>
                            <button className="camera-action-button" onClick={onCancel}>Cancel</button>
                            <button className="capture-button" onClick={handleCapture} aria-label="Capture photo"><div className="capture-button-inner" /></button>
                            <button className="camera-action-button" onClick={() => onDone && onDone(capturedPhotos)} disabled={capturedPhotos.length === 0}>Done ({capturedPhotos.length})</button>
                        </>
                    ) : (
                        <>
                            <button className="camera-action-button" onClick={() => onFinishPatrol && onFinishPatrol(capturedPhotos)}>Finish Patrol</button>
                            <button className="capture-button" onClick={handleCapture} aria-label="Capture photo"><div className="capture-button-inner" /></button>
                            <button className="camera-action-button" onClick={handleSaveAndNext} disabled={capturedPhotos.length === 0}>Save &amp; Next</button>
                        </>
                    )}
                </div>
            </div>
        </div>
    );
};

export default CameraView;

import React, { useState, useEffect, useRef } from 'react';
import { Case, PhotoWithMeta, EvidencePhoto, Property } from '../types';
import { initialAddressState, initialOwnerState, initialViolationState, VIOLATIONS_LIST, COMPLIANCE_DAYS } from '../constants';
import { analyzePhotoWithAI } from '../aiService';
import { dataService } from '../googleSheetsService';
import CameraView from './CameraView';

interface NewCaseFormProps {
    onSave: (draftCase: (Partial<Case> & { _tempPhotos?: PhotoWithMeta[] })) => void;
    onCancel: () => void;
    properties: Property[];
    draftCase: (Partial<Case> & { _tempPhotos?: PhotoWithMeta[] }) | null;
    onUpdateDraft: (draft: (Partial<Case> & { _tempPhotos?: PhotoWithMeta[] }) | null) => void;
}

const NewCaseForm: React.FC<NewCaseFormProps> = ({ onSave, onCancel, properties, draftCase, onUpdateDraft }) => {
    // UI-specific state
    const [showCamera, setShowCamera] = useState(false);
    const [isAnalyzing, setIsAnalyzing] = useState(false);
    const [aiError, setAiError] = useState('');
    const [isSaving, setIsSaving] = useState(false); 
    const [lookupMessage, setLookupMessage] = useState('');
    const [validationErrors, setValidationErrors] = useState<string[]>([]);
    const fileInputRef = useRef<HTMLInputElement>(null);

    const caseId = draftCase?.caseId || '';
    const address = draftCase?.address || initialAddressState;
    const owner = draftCase?.ownerInfo || initialOwnerState;
    const ownerUnknown = draftCase?.ownerInfoStatus === 'UNKNOWN';
    const violation = draftCase?.violation || initialViolationState;
    const isVacant = draftCase?.isVacant || false;
    const photos = draftCase?._tempPhotos || [];
    const violationManual = (violation.type === 'Other (Manual Entry)' && draftCase?.violation) || initialViolationState;

    const updateDraft = (updates: Partial<Case> & { _tempPhotos?: PhotoWithMeta[] }) => {
        if (draftCase) {
            onUpdateDraft({ ...draftCase, ...updates });
        }
    };

    const handleAddressLookup = () => {
        const trimmedAddress = address.street.trim();
        if (!trimmedAddress) {
            setLookupMessage('Please enter an address to look up.');
            return;
        }
        const foundProperty = properties.find(p => p.streetAddress.toLowerCase() === trimmedAddress.toLowerCase());

        if (foundProperty) {
            const updates: Partial<Case> = {
                ownerInfo: { ...initialOwnerState, ...foundProperty.ownerInfo },
                isVacant: foundProperty.isVacant,
                ownerInfoStatus: 'KNOWN'
            };
            updateDraft(updates);
            setLookupMessage('Success: Owner and property info have been pre-filled from the directory.');
        } else {
            setLookupMessage('Info: No existing property found for this address.');
        }
    };

    const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
        const files = e.target.files;
        if (!files || files.length === 0) return;

        const newPhotosPromises = Array.from(files).map(file => {
            return new Promise<PhotoWithMeta>((resolve) => {
                const reader = new FileReader();
                reader.onload = () => {
                    resolve({
                        file,
                        dataUrl: reader.result as string
                    });
                };
                reader.readAsDataURL(file);
            });
        });

        Promise.all(newPhotosPromises).then(newPhotos => {
            updateDraft({ _tempPhotos: [...photos, ...newPhotos] });
            if (fileInputRef.current) fileInputRef.current.value = '';
        });
    };

    const handleSubmit = (e: React.FormEvent) => {
        e.preventDefault();
        if (!draftCase) return;

        const errors: string[] = [];
        const finalViolation = violation.type === 'Other (Manual Entry)' ? violationManual : violation;
        const isOwnerInfoValid = ownerUnknown || (owner.name?.trim() && owner.mailingAddress?.trim());

        if (!draftCase.caseId?.trim()) errors.push("Case Number is missing.");
        if (!address.street?.trim()) errors.push("Property Address is missing.");
        if (finalViolation.type === 'Select a Violation...') errors.push("Violation Type has not been selected.");
        if (!isOwnerInfoValid) errors.push("Owner name and mailing address are required (unless marked unknown).");

        if (errors.length > 0) {
            setValidationErrors(errors);
            window.scrollTo({ top: 0, behavior: 'smooth' });
            return;
        }

        setValidationErrors([]);
        setIsSaving(true);
        onSave(draftCase);
    };

    const handleViolationChange = (e: React.ChangeEvent<HTMLSelectElement>) => {
        const selected = VIOLATIONS_LIST.find(v => v.type === e.target.value) || initialViolationState;
        updateDraft({ violation: selected });
    };

    const handleAnalyzePhoto = async () => {
        const photoToAnalyze = photos[0]?.file;
        if (!photoToAnalyze) {
            setAiError('Please take or upload at least one photo before using AI analysis.');
            return;
        }
        setIsAnalyzing(true);
        setAiError('');
        try {
            const result = await analyzePhotoWithAI(photoToAnalyze);
            const updates: Partial<Case> = {};
            if (result.address?.street) updates.address = { ...address, street: result.address.street };
            if (result.violation) updates.violation = result.violation;
            updateDraft(updates);
        } catch (e: any) {
            setAiError(`AI Analysis Failed: ${e.message}`);
        } finally {
            setIsAnalyzing(false);
        }
    };

    return (
        <>
        {showCamera && <CameraView 
            mode="single-case"
            onDone={(p) => { 
                updateDraft({ _tempPhotos: [...photos, ...p] });
                setShowCamera(false); 
            }} 
            onCancel={() => setShowCamera(false)} 
        />}
        <form onSubmit={handleSubmit} className="tab-content">
            {validationErrors.length > 0 && (
                <div className="error-message">
                    <strong>Please correct the following:</strong>
                    <ul style={{ marginTop: '0.5rem', paddingLeft: '1.25rem' }}>
                        {validationErrors.map((err, i) => <li key={i}>{err}</li>)}
                    </ul>
                </div>
            )}

            <div className="card">
                <h2>Property & Photos</h2>
                 <div className="form-group">
                    <label>Case Number (Firm-Specific ID)</label>
                    <input type="text" value={caseId} onChange={e => updateDraft({ caseId: e.target.value })} />
                </div>
                 <div className="form-group">
                    <label>Street Address</label>
                    <div className="input-with-button">
                        <input type="text" value={address.street} onChange={e => { updateDraft({ address: {...address, street: e.target.value}}); setLookupMessage(''); }} />
                        <button type="button" className="button" onClick={handleAddressLookup}>Look up</button>
                    </div>
                    {lookupMessage && <p className={`helper-text ${lookupMessage.startsWith('Success') ? 'success-message' : 'info-box'}`} style={{padding: '0.5rem', marginTop: '0.5rem'}}>{lookupMessage}</p>}
                </div>
                <div className="form-group"><label><input type="checkbox" checked={isVacant} onChange={e => updateDraft({ isVacant: e.target.checked })} /> Mark as vacant</label></div>

                <h4>Evidence Photos ({photos.length})</h4>
                <div className="photo-gallery" style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fill, minmax(80px, 1fr))', gap: '8px', margin: '1rem 0' }}>
                    {photos.map((p, i) => (
                        <div key={i} className="photo-thumbnail" style={{ aspectRatio: '1', overflow: 'hidden', borderRadius: '8px', border: '1px solid var(--border-color)' }}>
                            <img src={p.dataUrl} alt={`Evidence photo ${i+1}`} style={{ width: '100%', height: '100%', objectFit: 'cover' }}/>
                        </div>
                    ))}
                </div>

                <div className="button-group" style={{marginTop: '1rem'}}>
                    <button type="button" className="button" onClick={() => setShowCamera(true)}>Open Camera</button>
                    <button type="button" className="button secondary-action" onClick={() => fileInputRef.current?.click()}>Upload Photos</button>
                    <input 
                        type="file" 
                        ref={fileInputRef} 
                        style={{ display: 'none' }} 
                        multiple 
                        accept="image/*" 
                        onChange={handleFileUpload}
                    />
                    <button type="button" className="button secondary-action" onClick={handleAnalyzePhoto} disabled={isAnalyzing || photos.length === 0}>{isAnalyzing ? <span className="loader"/> : 'Analyze with AI'}</button>
                </div>
                {aiError && <p className="error-message" style={{marginTop: '1rem'}}>{aiError}</p>}
            </div>

            <div className="card">
                <h2>Owner Information</h2>
                <div className="form-group"><label><input type="checkbox" checked={ownerUnknown} onChange={e => updateDraft({ ownerInfoStatus: e.target.checked ? 'UNKNOWN' : 'KNOWN' })} /> Owner information is unknown</label></div>
                <div className="form-group"><label>Owner Name</label><input type="text" value={owner.name} onChange={e => updateDraft({ ownerInfo: {...owner, name: e.target.value}})} disabled={ownerUnknown} /></div>
                <div className="form-group">
                    <label>Mailing Address</label>
                    <textarea value={owner.mailingAddress} onChange={e => updateDraft({ ownerInfo: {...owner, mailingAddress: e.target.value}})} disabled={ownerUnknown}></textarea>
                    <p className="helper-text">For multi-line addresses on envelopes, use the Enter/Return key for line breaks.</p>
                </div>
            </div>

            <div className="card">
                <h2>Violation Details</h2>
                <div className="form-group"><label>Violation Type</label><select value={violation.type} onChange={handleViolationChange}><option disabled>Select a Violation...</option>{VIOLATIONS_LIST.map(v => <option key={v.type} value={v.type}>{v.type}</option>)}</select></div>
                {violation.type === 'Other (Manual Entry)' ? (
                    <>
                        <div className="form-group"><label>Ordinance</label><input type="text" value={violationManual.ordinance} onChange={e => updateDraft({ violation: {...violationManual, ordinance: e.target.value}})} /></div>
                        <div className="form-group"><label>Description</label><textarea value={violationManual.description} onChange={e => updateDraft({ violation: {...violationManual, description: e.target.value}})} /></div>
                    </>
                ) : (
                    <>
                        <div className="form-group readonly"><label>Ordinance</label><div className="form-value">{violation.ordinance || 'N/A'}</div></div>
                        <div className="form-group readonly"><label>Description</label><div className="form-value">{violation.description || 'N/A'}</div></div>
                    </>
                )}
            </div>

            <div className="button-group" style={{ justifyContent: 'flex-end'}}>
                <button type="button" className="button secondary-action" onClick={onCancel} disabled={isSaving}>Cancel</button>
                <button type="submit" className="button primary-action" disabled={isSaving}>
                    {isSaving ? <><span className="loader" style={{ marginRight: '8px' }} /> Saving...</> : 'Save Case'}
                </button>
            </div>
        </form>
        </>
    );
};

export default NewCaseForm;

import React, { useState, useEffect, useCallback, useRef } from 'react';
import { getConfig } from './config';
import { dataService } from './googleSheetsService';
import { Case, View, Property, PhotoWithMeta, EvidencePhoto, ComplaintLogEntry } from './types';
import AdminView from './components/Admin';
import CaseList from './components/CaseList';
import NewCaseForm from './components/NewCaseForm';
import CaseDetails from './components/CaseDetails';
import TemplateManager from './components/TemplateManager';
import ComplaintLog from './components/ComplaintLog';
import Reports from './components/Reports';
import { getCaseTimeStatus } from './utils';
import PropertyDirectory from './components/PropertyDirectory';
import AbatementReport from './components/AbatementReport';
import { initialAddressState, initialOwnerState, initialViolationState, VIOLATIONS_LIST, COMPLIANCE_DAYS } from './constants';
import DailyTasks from './components/DailyTasks';
import AlleyPatrol from './components/AlleyPatrol';
import { savePendingPatrolCases, loadPendingPatrolCases } from './patrolService';
import AnimalControlDashboard from './components/AnimalControlDashboard';
import { checkAndRotatePatrol } from './dailyTaskService'; 

const COMPLAINT_LOG_KEY = 'complaint-logs-v1';

type AppStatus = 'LOADING' | 'NEEDS_CONFIG' | 'READY';

const App: React.FC = () => {
    const [appStatus, setAppStatus] = useState<AppStatus>('LOADING');
    const [view, setView] = useState<View>('TASKS');
    const [activeTab, setActiveTab] = useState('tasks');

    const [cases, setCases] = useState<Case[]>([]);
    const [properties, setProperties] = useState<Property[]>([]);
    const [complaintLogs, setComplaintLogs] = useState<ComplaintLogEntry[]>([]);
    const [selectedCaseId, setSelectedCaseId] = useState<string | null>(null);
    const [isLoading, setIsLoading] = useState(true);
    const [error, setError] = useState<string | null>(null);
    const isInitialCheck = useRef(true);
    const [showAbatementReport, setShowAbatementReport] = useState(false);

    const [draftCase, setDraftCase] = useState<(Partial<Case> & { _tempPhotos?: PhotoWithMeta[] }) | null>(null);
    const [pendingPatrolCases, setPendingPatrolCases] = useState<{id: string, photos: PhotoWithMeta[]}[]>(loadPendingPatrolCases());

    useEffect(() => {
        checkAndRotatePatrol();
    }, []);

    useEffect(() => {
        savePendingPatrolCases(pendingPatrolCases);
    }, [pendingPatrolCases]);

    useEffect(() => {
        try {
            const storedLogsReal = localStorage.getItem(COMPLAINT_LOG_KEY);
            if (storedLogsReal) {
                setComplaintLogs(JSON.parse(storedLogsReal));
            }
        } catch (error) {
            console.error("Failed to load complaint logs from local storage:", error);
        }
    }, []);

    const handleUpdateLogs = (updatedLogs: ComplaintLogEntry[]) => {
        setComplaintLogs(updatedLogs);
        try {
            localStorage.setItem(COMPLAINT_LOG_KEY, JSON.stringify(updatedLogs));
        } catch (error) {
            console.error("Failed to save complaint logs to local storage:", error);
        }
    };


    const checkConfiguration = useCallback(async () => {
        setAppStatus('LOADING');
        try {
            const config = await getConfig(isInitialCheck.current);
            isInitialCheck.current = false;

            if (config?.google?.clientId && config.google.fileId) {
                setAppStatus('READY');
                if (view === 'ADMIN') {
                    setView('TASKS');
                    setActiveTab('tasks');
                }
            } else {
                setAppStatus('NEEDS_CONFIG');
                setView('ADMIN');
                setActiveTab('admin');
            }
        } catch (err: any) {
            setError(`Failed to load configuration: ${err.message}`);
            setAppStatus('NEEDS_CONFIG');
        }
    }, [view]);

    useEffect(() => {
        checkConfiguration();
    }, [checkConfiguration]);


    const loadData = useCallback(() => {
        if (appStatus === 'READY') {
            setIsLoading(true);
            setError(null);
            dataService.getAllData()
                .then(({ cases, properties }) => {
                    setCases(cases);
                    setProperties(properties || []);
                })
                .catch(err => setError(`Failed to load data: ${err.message}`))
                .finally(() => setIsLoading(false));
        } else {
            setIsLoading(false);
        }
    }, [appStatus]);

    useEffect(() => { loadData(); }, [loadData]);

    const handleSetupComplete = () => {
        checkConfiguration();
    };

    const handleSelectCase = (caseId: string) => { setSelectedCaseId(caseId); setView('DETAILS'); };
    const handleNewCase = () => {
        if (!draftCase) {
             setDraftCase({
                id: `draft-${Date.now()}`,
                caseId: '',
                address: initialAddressState,
                ownerInfo: initialOwnerState,
                violation: initialViolationState,
                ownerInfoStatus: 'KNOWN',
                isVacant: false,
                _tempPhotos: []
            });
        }
        setView('NEW');
        setActiveTab('new');
    };

    const handleCancelNew = () => {
        if (draftCase && (draftCase._tempPhotos?.length || 0) > 0) {
            if (!window.confirm("Are you sure you want to cancel? Any photos you've taken will be lost.")) {
                return;
            }
        }
        setDraftCase(null);
        setView('TASKS');
        setActiveTab('tasks');
    };

    const handleCreateCaseFromPatrol = (patrolCase: {id: string, photos: PhotoWithMeta[]}) => {
        setDraftCase({
            id: `draft-${Date.now()}`,
            caseId: '',
            address: initialAddressState,
            ownerInfo: initialOwnerState,
            violation: initialViolationState,
            ownerInfoStatus: 'KNOWN',
            isVacant: false,
            _tempPhotos: patrolCase.photos,
        });
        setPendingPatrolCases(prev => prev.filter(p => p.id !== patrolCase.id));
        setView('NEW');
        setActiveTab('new');
    };

    const handleBackToList = () => { setSelectedCaseId(null); setView('TASKS'); setActiveTab('tasks'); };

    const handleSaveCase = (draftToSave: (Partial<Case> & { _tempPhotos?: PhotoWithMeta[] })) => {
        const today = new Date(), deadline = new Date();
        deadline.setDate(today.getDate() + COMPLIANCE_DAYS);
        const formatDate = (d: Date) => d.toLocaleDateString('en-US', { year: 'numeric', month: 'long', day: 'numeric' });

        const finalViolation = draftToSave.violation?.type === 'Other (Manual Entry)'
            ? draftToSave.violation
            : VIOLATIONS_LIST.find(v => v.type === draftToSave.violation?.type) || initialViolationState;

        const tempCase: Case = {
            id: draftToSave.id || self.crypto.randomUUID(), 
            caseId: (draftToSave.caseId || '').trim(), 
            status: 'ACTIVE',
            dateCreated: formatDate(today), 
            complianceDeadline: formatDate(deadline),
            address: draftToSave.address || initialAddressState, 
            ownerInfo: draftToSave.ownerInfo || initialOwnerState,
            ownerInfoStatus: draftToSave.ownerInfoStatus || 'KNOWN',
            violation: finalViolation, 
            isVacant: draftToSave.isVacant || false,
            evidence: { notes: [{ date: formatDate(today), text: "Case created." }], photos: [] },
            notices: [],
        };

        // Optimistically update the UI
        setCases(prev => [tempCase, ...prev]);
        setDraftCase(null);
        setError(null);
        if (view === 'NEW') { setView('TASKS'); setActiveTab('tasks'); }

        // Background Save Process
        (async () => {
            try {
                // 1. Upload Photos first
                const uploadedPhotos: EvidencePhoto[] = await dataService.uploadCasePhotos(draftToSave._tempPhotos || [], tempCase.caseId);
                const finalCase = { ...tempCase, evidence: { ...tempCase.evidence, photos: uploadedPhotos } };

                // 2. Save the full case record to Sheet
                await dataService.saveCase(finalCase);

                // 3. Update Property Directory
                const addressStr = finalCase.address.street.trim();
                const existingPropIndex = properties.findIndex(p => p.streetAddress.toLowerCase() === addressStr.toLowerCase());
                const updatedProperties = [...properties];
                let needsSave = false;

                if (existingPropIndex > -1) {
                    const prop = updatedProperties[existingPropIndex];
                    if (JSON.stringify(prop.ownerInfo) !== JSON.stringify(finalCase.ownerInfo) || prop.isVacant !== finalCase.isVacant) {
                        updatedProperties[existingPropIndex] = { ...prop, ownerInfo: finalCase.ownerInfo, isVacant: finalCase.isVacant };
                        needsSave = true;
                    }
                } else {
                    const newProperty: Property = { id: self.crypto.randomUUID(), streetAddress: addressStr, ownerInfo: finalCase.ownerInfo, isVacant: finalCase.isVacant, residentInfo: { name: '', phone: '' }, dilapidationNotes: '' };
                    updatedProperties.push(newProperty);
                    needsSave = true;
                }

                if (needsSave) {
                    await dataService.saveProperties(updatedProperties);
                    setProperties(updatedProperties);
                }

                // Refresh local data from server
                const allData = await dataService.getAllData();
                setCases(allData.cases);

            } catch (e: any) {
                console.error("Background save failed:", e);
                // On failure, remove the optimistic case and restore the draft
                setError(`CRITICAL ERROR: Failed to save case "${tempCase.caseId}". Error: ${e.message}. Please try again.`);
                setCases(prev => prev.filter(c => c.id !== tempCase.id));
                setDraftCase(draftToSave);
                setView('NEW');
                setActiveTab('new');
                window.scrollTo({ top: 0, behavior: 'smooth' });
            }
        })();
    };

    const handleUpdateCase = async (caseData: Case) => {
        setIsLoading(true);
        setError(null);
        try {
            await dataService.saveCase(caseData);
            const allData = await dataService.getAllData();
            setCases(allData.cases);
        } catch (e: any) {
            setError(`Failed to save case: ${e.message}`);
        } finally {
            setIsLoading(false);
        }
    };

    const handleDeleteCase = async (caseId: string) => {
        setIsLoading(true);
        setError(null);
        try {
            await dataService.deleteCase(caseId);
            const allData = await dataService.getAllData();
            setCases(allData.cases);
            setView('TASKS');
            setActiveTab('tasks');
            setSelectedCaseId(null);
        } catch (e: any) {
            setError(`Failed to delete case: ${e.message}`);
        } finally {
            setIsLoading(false);
        }
    };

    const handleSaveProperties = async (updatedProperties: Property[]) => {
        setIsLoading(true);
        setError(null);
        try {
            await dataService.saveProperties(updatedProperties);
            setProperties(updatedProperties);
        } catch (e: any) {
            setError(`Failed to save properties: ${e.message}`);
        } finally {
            setIsLoading(false);
        }
    };

    const changeTab = (tab: string, targetView: View) => {
        setActiveTab(tab);
        setView(targetView);
        setSelectedCaseId(null);
        if (tab !== 'abatement') {
            setShowAbatementReport(false);
        }
    };

    const selectedCase = cases.find(c => c.id === selectedCaseId);

    const abatementCases = cases.filter(c => c.status === 'PENDING_ABATEMENT');
    const continualAbatementCases = cases.filter(c => c.status === 'CONTINUAL_ABATEMENT');
    const dueCases = cases.filter(c => getCaseTimeStatus(c) === 'overdue' && c.status !== 'CLOSED' && c.status !== 'PENDING_ABATEMENT');

    const renderContent = () => {
        if (appStatus === 'LOADING') {
            return <div className="card" style={{textAlign: 'center', padding: '2rem'}}><div className="loader" style={{margin: 'auto', borderTopColor: 'var(--primary-color)', borderLeftColor: 'var(--primary-color)'}}></div><p style={{marginTop: '1rem', color: 'var(--text-secondary)'}}>Loading...</p></div>;
        }
        if (appStatus === 'NEEDS_CONFIG') return <AdminView onSetupComplete={handleSetupComplete} />;
        if (error) return <div className="error-message">{error}<p style={{ marginTop: '0.5rem', fontSize: '0.9rem' }}>Check your internet connection or Google project configuration.</p></div>;
        if (isLoading && (view === 'LIST' || view === 'TASKS')) return <div className="card" style={{textAlign: 'center', padding: '2rem'}}><div className="loader" style={{margin: 'auto', borderTopColor: 'var(--primary-color)', borderLeftColor: 'var(--primary-color)'}}></div><p style={{marginTop: '1rem', color: 'var(--text-secondary)'}}>Updating...</p></div>;

        switch (view) {
            case 'TASKS': return <DailyTasks cases={cases} onSelectCase={handleSelectCase} />;
            case 'DETAILS': return selectedCase ? <CaseDetails caseData={selectedCase} onBack={handleBackToList} onUpdate={handleUpdateCase} onDelete={handleDeleteCase} /> : <p>Case not found.</p>;
            case 'NEW': return <NewCaseForm onSave={handleSaveCase} onCancel={handleCancelNew} properties={properties} draftCase={draftCase} onUpdateDraft={setDraftCase} />;
            case 'ADMIN': return <AdminView onSetupComplete={handleSetupComplete} />;
            case 'TEMPLATES': return <TemplateManager />;
            case 'LOG': return <ComplaintLog logs={complaintLogs} onUpdateLogs={handleUpdateLogs} />;
            case 'PROPERTIES': return <PropertyDirectory cases={cases} properties={properties} onSaveProperties={handleSaveProperties} onSelectCase={handleSelectCase} />;
            case 'REPORTS': return <Reports cases={cases} />;
            case 'PATROL': return <AlleyPatrol pendingCases={pendingPatrolCases} onSetPendingCases={setPendingPatrolCases} onCreateCase={handleCreateCaseFromPatrol} />;
            case 'ANIMAL_CONTROL': return <AnimalControlDashboard logs={complaintLogs} onUpdateLogs={handleUpdateLogs} />;
            case 'LIST': default:
                if (activeTab === 'due') {
                    return <CaseList cases={dueCases} onSelectCase={handleSelectCase} onNewCase={handleNewCase} listType="due" />;
                }
                if (activeTab === 'abatement') {
                    return showAbatementReport 
                        ? <AbatementReport cases={abatementCases} onBack={() => setShowAbatementReport(false)} />
                        : <CaseList cases={abatementCases} onSelectCase={handleSelectCase} onNewCase={handleNewCase} listType="abatement" onGenerateReport={() => setShowAbatementReport(true)} />;
                }
                if (activeTab === 'continual-abatement') {
                    return <CaseList cases={continualAbatementCases} onSelectCase={handleSelectCase} onNewCase={handleNewCase} listType="continual-abatement" />;
                }
                 return <CaseList cases={cases} onSelectCase={handleSelectCase} onNewCase={handleNewCase} listType="all" />;
        }
    };

    return (
        <div className="app-container">
             <header className="app-header no-print">
                 <div style={{flex: '0 0 70px'}}>
                    <button 
                        onClick={() => { setView('PATROL'); setActiveTab('patrol'); }}
                        style={{
                            background: 'rgba(2, 132, 199, 0.1)', 
                            border: '1px solid var(--primary-color)', 
                            color: 'var(--primary-color)', 
                            padding: '0.4rem 0.8rem', 
                            borderRadius: '4px', 
                            cursor: 'pointer',
                            fontSize: '0.85rem',
                            fontWeight: 700
                        }}
                    >
                        Patrol
                    </button>
                 </div>
                <h1>Commerce Code Enf.</h1>
                <div style={{flex: '0 0 70px'}}></div>
            </header>
            <nav className="main-nav no-print">
                <button className={activeTab === 'tasks' ? 'active' : ''} onClick={() => changeTab('tasks', 'TASKS')}>Tasks</button>
                <button className={activeTab === 'all' ? 'active' : ''} onClick={() => changeTab('all', 'LIST')}>Cases</button>
                <button className={activeTab === 'due' ? 'active' : ''} onClick={() => changeTab('due', 'LIST')}>Due</button>
                <button className={activeTab === 'abatement' ? 'active' : ''} onClick={() => changeTab('abatement', 'LIST')}>Abatement</button>
                <button className={activeTab === 'continual-abatement' ? 'active' : ''} onClick={() => changeTab('continual-abatement', 'LIST')}>Continual</button>
                <button className={activeTab === 'properties' ? 'active' : ''} onClick={() => changeTab('properties', 'PROPERTIES')}>Directory</button>
                <button className={activeTab === 'log' ? 'active' : ''} onClick={() => changeTab('log', 'LOG')}>Logs</button>
                <button className={activeTab === 'animal' ? 'active' : ''} onClick={() => changeTab('animal', 'ANIMAL_CONTROL')}>Animal</button>
                <button className={activeTab === 'reports' ? 'active' : ''} onClick={() => changeTab('reports', 'REPORTS')}>Reports</button>
                <button className={activeTab === 'admin' ? 'active' : ''} onClick={() => changeTab('admin', 'ADMIN')}>Admin</button>
                <button className={activeTab === 'templates' ? 'active' : ''} onClick={() => changeTab('templates', 'TEMPLATES')}>Templates</button>
            </nav>
            <main className="main-content">
                {renderContent()}
            </main>
        </div>
    );
};

export default App;

import React, { useState, useEffect, useRef } from 'react';
import { Case, PhotoWithMeta, EvidencePhoto, Property } from '../types';
import { initialAddressState, initialOwnerState, initialViolationState, VIOLATIONS_LIST, COMPLIANCE_DAYS } from '../constants';
import { analyzePhotoWithAI } from '../aiService';
import { dataService } from '../googleSheetsService';
import CameraView from './CameraView';

interface NewCaseFormProps {
    onSave: (draftCase: (Partial<Case> & { _tempPhotos?: PhotoWithMeta[] })) => void;
    onCancel: () => void;
    properties: Property[];
    draftCase: (Partial<Case> & { _tempPhotos?: PhotoWithMeta[] }) | null;
    onUpdateDraft: (draft: (Partial<Case> & { _tempPhotos?: PhotoWithMeta[] }) | null) => void;
}

const NewCaseForm: React.FC<NewCaseFormProps> = ({ onSave, onCancel, properties, draftCase, onUpdateDraft }) => {
    // UI-specific state
    const [showCamera, setShowCamera] = useState(false);
    const [isAnalyzing, setIsAnalyzing] = useState(false);
    const [aiError, setAiError] = useState('');
    const [isSaving, setIsSaving] = useState(false); 
    const [lookupMessage, setLookupMessage] = useState('');
    const [validationErrors, setValidationErrors] = useState<string[]>([]);
    const fileInputRef = useRef<HTMLInputElement>(null);

    const caseId = draftCase?.caseId || '';
    const address = draftCase?.address || initialAddressState;
    const owner = draftCase?.ownerInfo || initialOwnerState;
    const ownerUnknown = draftCase?.ownerInfoStatus === 'UNKNOWN';
    const violation = draftCase?.violation || initialViolationState;
    const isVacant = draftCase?.isVacant || false;
    const photos = draftCase?._tempPhotos || [];
    const violationManual = (violation.type === 'Other (Manual Entry)' && draftCase?.violation) || initialViolationState;

    const updateDraft = (updates: Partial<Case> & { _tempPhotos?: PhotoWithMeta[] }) => {
        if (draftCase) {
            onUpdateDraft({ ...draftCase, ...updates });
        }
    };

    const handleAddressLookup = () => {
        const trimmedAddress = address.street.trim();
        if (!trimmedAddress) {
            setLookupMessage('Please enter an address to look up.');
            return;
        }
        const foundProperty = properties.find(p => p.streetAddress.toLowerCase() === trimmedAddress.toLowerCase());

        if (foundProperty) {
            const updates: Partial<Case> = {
                ownerInfo: { ...initialOwnerState, ...foundProperty.ownerInfo },
                isVacant: foundProperty.isVacant,
                ownerInfoStatus: 'KNOWN'
            };
            updateDraft(updates);
            setLookupMessage('Success: Owner and property info have been pre-filled from the directory.');
        } else {
            setLookupMessage('Info: No existing property found for this address.');
        }
    };

    // FIX: Added explicit File type to the map callback to resolve "Type '{}' is missing properties from type 'File'" and ensure correct Blob handling in reader.readAsDataURL.
    const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
        const files = e.target.files;
        if (!files || files.length === 0) return;

        const newPhotosPromises = Array.from(files).map((file: File) => {
            return new Promise<PhotoWithMeta>((resolve) => {
                const reader = new FileReader();
                reader.onload = () => {
                    resolve({
                        file,
                        dataUrl: reader.result as string
                    });
                };
                reader.readAsDataURL(file);
            });
        });

        Promise.all(newPhotosPromises).then(newPhotos => {
            updateDraft({ _tempPhotos: [...photos, ...newPhotos] });
            if (fileInputRef.current) fileInputRef.current.value = '';
        });
    };

    const handleSubmit = (e: React.FormEvent) => {
        e.preventDefault();
        if (!draftCase) return;

        const errors: string[] = [];
        const finalViolation = violation.type === 'Other (Manual Entry)' ? violationManual : violation;
        const isOwnerInfoValid = ownerUnknown || (owner.name?.trim() && owner.mailingAddress?.trim());

        if (!draftCase.caseId?.trim()) errors.push("Case Number is missing.");
        if (!address.street?.trim()) errors.push("Property Address is missing.");
        if (finalViolation.type === 'Select a Violation...') errors.push("Violation Type has not been selected.");
        if (!isOwnerInfoValid) errors.push("Owner name and mailing address are required (unless marked unknown).");

        if (errors.length > 0) {
            setValidationErrors(errors);
            window.scrollTo({ top: 0, behavior: 'smooth' });
            return;
        }

        setValidationErrors([]);
        setIsSaving(true);
        onSave(draftCase);
    };

    const handleViolationChange = (e: React.ChangeEvent<HTMLSelectElement>) => {
        const selected = VIOLATIONS_LIST.find(v => v.type === e.target.value) || initialViolationState;
        updateDraft({ violation: selected });
    };

    const handleAnalyzePhoto = async () => {
        const photoToAnalyze = photos[0]?.file;
        if (!photoToAnalyze) {
            setAiError('Please take or upload at least one photo before using AI analysis.');
            return;
        }
        setIsAnalyzing(true);
        setAiError('');
        try {
            const result = await analyzePhotoWithAI(photoToAnalyze);
            const updates: Partial<Case> = {};
            if (result.address?.street) updates.address = { ...address, street: result.address.street };
            if (result.violation) updates.violation = result.violation;
            updateDraft(updates);
        } catch (e: any) {
            setAiError(`AI Analysis Failed: ${e.message}`);
        } finally {
            setIsAnalyzing(false);
        }
    };

    return (
        <>
        {showCamera && <CameraView 
            mode="single-case"
            onDone={(p) => { 
                updateDraft({ _tempPhotos: [...photos, ...p] });
                setShowCamera(false); 
            }} 
            onCancel={() => setShowCamera(false)} 
        />}
        <form onSubmit={handleSubmit} className="tab-content">
            {validationErrors.length > 0 && (
                <div className="error-message">
                    <strong>Please correct the following:</strong>
                    <ul style={{ marginTop: '0.5rem', paddingLeft: '1.25rem' }}>
                        {validationErrors.map((err, i) => <li key={i}>{err}</li>)}
                    </ul>
                </div>
            )}

            <div className="card">
                <h2>Property & Photos</h2>
                 <div className="form-group">
                    <label>Case Number (Firm-Specific ID)</label>
                    <input type="text" value={caseId} onChange={e => updateDraft({ caseId: e.target.value })} />
                </div>
                 <div className="form-group">
                    <label>Street Address</label>
                    <div className="input-with-button">
                        <input type="text" value={address.street} onChange={e => { updateDraft({ address: {...address, street: e.target.value}}); setLookupMessage(''); }} />
                        <button type="button" className="button" onClick={handleAddressLookup}>Look up</button>
                    </div>
                    {lookupMessage && <p className={`helper-text ${lookupMessage.startsWith('Success') ? 'success-message' : 'info-box'}`} style={{padding: '0.5rem', marginTop: '0.5rem'}}>{lookupMessage}</p>}
                </div>
                <div className="form-group"><label><input type="checkbox" checked={isVacant} onChange={e => updateDraft({ isVacant: e.target.checked })} /> Mark as vacant</label></div>

                <h4>Evidence Photos ({photos.length})</h4>
                <div className="photo-gallery" style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fill, minmax(80px, 1fr))', gap: '8px', margin: '1rem 0' }}>
                    {photos.map((p, i) => (
                        <div key={i} className="photo-thumbnail" style={{ aspectRatio: '1', overflow: 'hidden', borderRadius: '8px', border: '1px solid var(--border-color)' }}>
                            <img src={p.dataUrl} alt={`Evidence photo ${i+1}`} style={{ width: '100%', height: '100%', objectFit: 'cover' }}/>
                        </div>
                    ))}
                </div>

                <div className="button-group" style={{marginTop: '1rem'}}>
                    <button type="button" className="button" onClick={() => setShowCamera(true)}>Open Camera</button>
                    <button type="button" className="button secondary-action" onClick={() => fileInputRef.current?.click()}>Upload Photos</button>
                    <input 
                        type="file" 
                        ref={fileInputRef} 
                        style={{ display: 'none' }} 
                        multiple 
                        accept="image/*" 
                        onChange={handleFileUpload}
                    />
                    <button type="button" className="button secondary-action" onClick={handleAnalyzePhoto} disabled={isAnalyzing || photos.length === 0}>{isAnalyzing ? <span className="loader"/> : 'Analyze with AI'}</button>
                </div>
                {aiError && <p className="error-message" style={{marginTop: '1rem'}}>{aiError}</p>}
            </div>

            <div className="card">
                <h2>Owner Information</h2>
                <div className="form-group"><label><input type="checkbox" checked={ownerUnknown} onChange={e => updateDraft({ ownerInfoStatus: e.target.checked ? 'UNKNOWN' : 'KNOWN' })} /> Owner information is unknown</label></div>
                <div className="form-group"><label>Owner Name</label><input type="text" value={owner.name} onChange={e => updateDraft({ ownerInfo: {...owner, name: e.target.value}})} disabled={ownerUnknown} /></div>
                <div className="form-group">
                    <label>Mailing Address</label>
                    <textarea value={owner.mailingAddress} onChange={e => updateDraft({ ownerInfo: {...owner, mailingAddress: e.target.value}})} disabled={ownerUnknown}></textarea>
                    <p className="helper-text">For multi-line addresses on envelopes, use the Enter/Return key for line breaks.</p>
                </div>
            </div>

            <div className="card">
                <h2>Violation Details</h2>
                <div className="form-group"><label>Violation Type</label><select value={violation.type} onChange={handleViolationChange}><option disabled>Select a Violation...</option>{VIOLATIONS_LIST.map(v => <option key={v.type} value={v.type}>{v.type}</option>)}</select></div>
                {violation.type === 'Other (Manual Entry)' ? (
                    <>
                        <div className="form-group"><label>Ordinance</label><input type="text" value={violationManual.ordinance} onChange={e => updateDraft({ violation: {...violationManual, ordinance: e.target.value}})} /></div>
                        <div className="form-group"><label>Description</label><textarea value={violationManual.description} onChange={e => updateDraft({ violation: {...violationManual, description: e.target.value}})} /></div>
                    </>
                ) : (
                    <>
                        <div className="form-group readonly"><label>Ordinance</label><div className="form-value">{violation.ordinance || 'N/A'}</div></div>
                        <div className="form-group readonly"><label>Description</label><div className="form-value">{violation.description || 'N/A'}</div></div>
                    </>
                )}
            </div>

            <div className="button-group" style={{ justifyContent: 'flex-end'}}>
                <button type="button" className="button secondary-action" onClick={onCancel} disabled={isSaving}>Cancel</button>
                <button type="submit" className="button primary-action" disabled={isSaving}>
                    {isSaving ? <><span className="loader" style={{ marginRight: '8px' }} /> Saving...</> : 'Save Case'}
                </button>
            </div>
        </form>
        </>
    );
};

export default NewCaseForm;

import { GoogleGenAI, Type } from "@google/genai";
import { Case } from './types';
import { initialAddressState, initialViolationState, VIOLATIONS_LIST } from './constants';

/**
 * Analyzes a photo using Gemini AI to extract property address and violation type.
 * @param photoFile The image file (File or Blob) to analyze.
 * @returns A partial Case object containing the extracted information.
 */
export const analyzePhotoWithAI = async (photoFile: File): Promise<Partial<Case>> => {
    // FIX: Always use a named parameter when initializing GoogleGenAI and use process.env.API_KEY directly as required.
    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

    // FIX: Enhanced toBase64 helper with proper Blob typing and error handling to avoid "Argument of type 'unknown' is not assignable to parameter of type 'Blob'" errors.
    const toBase64 = (file: Blob): Promise<string> => new Promise<string>((resolve, reject) => {
        const reader = new FileReader();
        reader.readAsDataURL(file);
        reader.onload = () => {
            const result = reader.result as string;
            if (result) {
                // Extract base64 data from the data URL.
                resolve(result.split(',')[1]);
            } else {
                reject(new Error("Failed to read file contents."));
            }
        };
        reader.onerror = () => reject(new Error("FileReader error occurred while processing the photo."));
    });

    const base64Data = await toBase64(photoFile);

    // FIX: Use the preferred contents structure { parts: [...] } for multimodal prompts.
    const imagePart = {
        inlineData: {
            mimeType: photoFile.type || 'image/jpeg',
            data: base64Data,
        },
    };

    const textPart = {
        text: `Analyze this image for a code enforcement case. 
               Identify the property address and the primary violation type from the following list: 
               ${VIOLATIONS_LIST.map(v => v.type).join(', ')}. 
               If the address is partially visible, provide the visible parts.`
    };

    // FIX: Use ai.models.generateContent directly to query GenAI with both the model name and prompt.
    // Use 'gemini-3-flash-preview' as it is optimized for basic multimodal/text tasks.
    const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: { parts: [imagePart, textPart] },
        config: {
            responseMimeType: "application/json",
            responseSchema: {
                type: Type.OBJECT,
                properties: {
                    address: {
                        type: Type.OBJECT,
                        properties: {
                            street: { type: Type.STRING }
                        },
                        required: ['street']
                    },
                    violationType: {
                        type: Type.STRING,
                        description: `One of the predefined violation types.`
                    }
                },
                required: ['address', 'violationType']
            }
        }
    });

    // FIX: Access response.text as a property (getter), not a method call.
    const jsonStr = response.text || '{}';
    try {
        const resultJson = JSON.parse(jsonStr);
        const matchedViolation = VIOLATIONS_LIST.find(v => v.type === resultJson.violationType) || initialViolationState;

        return {
            address: { 
                ...initialAddressState, 
                street: resultJson.address?.street || '' 
            },
            violation: matchedViolation,
        };
    } catch (parseError) {
        console.error("Failed to parse AI response JSON:", jsonStr);
        throw new Error("AI returned an invalid response format.");
    }
};

