import React, { useState, useEffect, useRef } from 'react';
import { PhotoWithMeta } from '../types';

interface CameraViewProps {
    mode: 'single-case' | 'patrol';
    onCancel?: () => void;
    onDone?: (photos: PhotoWithMeta[]) => void;
    onSaveSet?: (photos: PhotoWithMeta[]) => void;
    onFinishPatrol?: (photos: PhotoWithMeta[]) => void;
}

const CameraView: React.FC<CameraViewProps> = ({ mode, onCancel, onDone, onSaveSet, onFinishPatrol }) => {
    const videoRef = useRef<HTMLVideoElement>(null);
    const [stream, setStream] = useState<MediaStream | null>(null);
    const [imageCapture, setImageCapture] = useState<ImageCapture | null>(null);
    const [capturedPhotos, setCapturedPhotos] = useState<PhotoWithMeta[]>([]);

    const [zoom, setZoom] = useState(1);
    const [zoomCapabilities, setZoomCapabilities] = useState<{min: number, max: number, step: number} | null>(null);
    const [torch, setTorch] = useState(false);
    const [torchAvailable, setTorchAvailable] = useState(false);

    useEffect(() => {
        let activeStream: MediaStream | null = null;
        const videoConstraints = {
            facingMode: 'environment',
            width: { ideal: 1920 },
            height: { ideal: 1080 }
        };

        navigator.mediaDevices.getUserMedia({ video: videoConstraints })
            .then(mediaStream => {
                activeStream = mediaStream;
                setStream(mediaStream);
                if (videoRef.current) {
                    videoRef.current.srcObject = mediaStream;
                    videoRef.current.play().catch(e => console.warn("Video play failed", e));
                }
                const track = mediaStream.getVideoTracks()[0];

                if (typeof ImageCapture !== 'undefined') {
                    setImageCapture(new ImageCapture(track));
                }

                const capabilities = track.getCapabilities();
                if (capabilities.zoom) {
                    setZoomCapabilities({
                        min: capabilities.zoom.min,
                        max: capabilities.zoom.max,
                        step: capabilities.zoom.step || 0.1,
                    });
                    setZoom(capabilities.zoom.min);
                }
                if (capabilities.torch) {
                    setTorchAvailable(true);
                }
            })
            .catch(err => {
                console.error("Could not access camera.", err);
                alert("Could not access camera. Try the 'Upload' option if the camera fails to load.");
            });

        return () => { activeStream?.getTracks().forEach(track => track.stop()); };
    }, []);

    useEffect(() => {
        if (!stream || !zoomCapabilities) return;
        const track = stream.getVideoTracks()[0];
        track.applyConstraints({ advanced: [{ zoom: zoom }] }).catch(e => console.warn("Could not apply zoom", e));
    }, [zoom, stream, zoomCapabilities]);

    useEffect(() => {
        if (!stream || !torchAvailable) return;
        const track = stream.getVideoTracks()[0];
        track.applyConstraints({ advanced: [{ torch: torch }] }).catch(e => console.warn("Could not apply torch", e));
    }, [torch, stream, torchAvailable]);

    const addTimestampToBlob = (blob: Blob): Promise<Blob> => {
        return new Promise((resolve, reject) => {
            const img = new Image();
            const url = URL.createObjectURL(blob);
            img.onload = () => {
                const canvas = document.createElement('canvas');
                canvas.width = img.width;
                canvas.height = img.height;
                const ctx = canvas.getContext('2d');
                if (!ctx) {
                    URL.revokeObjectURL(url);
                    return reject(new Error('Could not get canvas context'));
                }

                ctx.drawImage(img, 0, 0);

                const timestamp = new Date().toLocaleString('en-US', {
                    year: 'numeric', month: 'short', day: 'numeric',
                    hour: '2-digit', minute: '2-digit', second: '2-digit', hour12: true,
                });

                const fontSize = Math.max(24, Math.min(96, Math.round(img.width * 0.03))); 
                const padding = fontSize * 0.5;
                ctx.font = `bold ${fontSize}px 'Roboto', sans-serif`;
                ctx.textAlign = 'right';
                ctx.textBaseline = 'bottom';

                const textMetrics = ctx.measureText(timestamp);
                const textWidth = textMetrics.width;
                const textHeight = fontSize; 

                const bgX = canvas.width - textWidth - padding * 2;
                const bgY = canvas.height - textHeight - padding * 1.5;
                const bgWidth = textWidth + padding * 2;
                const bgHeight = textHeight + padding * 1.5;

                ctx.fillStyle = 'rgba(0, 0, 0, 0.6)';
                ctx.fillRect(bgX, bgY, bgWidth, bgHeight);

                ctx.fillStyle = 'white';
                ctx.fillText(timestamp, canvas.width - padding, canvas.height - padding);

                canvas.toBlob(
                    (newBlob) => {
                        URL.revokeObjectURL(url);
                        if (newBlob) resolve(newBlob);
                        else reject(new Error('Canvas toBlob failed.'));
                    },
                    'image/jpeg',
                    0.95
                );
            };
            img.onerror = () => {
                URL.revokeObjectURL(url);
                reject(new Error('Failed to load image.'));
            };
            img.src = url;
        });
    };

    const handleCapture = async () => {
        try {
            let originalBlob: Blob;
            if (imageCapture) {
                originalBlob = await imageCapture.takePhoto();
            } else if (videoRef.current) {
                originalBlob = await new Promise<Blob>((resolve, reject) => {
                    const canvas = document.createElement('canvas');
                    canvas.width = videoRef.current!.videoWidth;
                    canvas.height = videoRef.current!.videoHeight;
                    canvas.getContext('2d')?.drawImage(videoRef.current!, 0, 0);
                    canvas.toBlob((blob) => blob ? resolve(blob) : reject(new Error("Canvas fallback failed.")), 'image/jpeg', 1.0);
                });
            } else {
                throw new Error("No video source.");
            }

            const timestampedBlob = await addTimestampToBlob(originalBlob);

            const file = new File([timestampedBlob], `capture-${Date.now()}.jpg`, { type: 'image/jpeg' });
            const reader = new FileReader();
            reader.onload = () => {
                const dataUrl = reader.result as string;
                const newPhoto: PhotoWithMeta = { file, dataUrl };
                setCapturedPhotos(prev => [...prev, newPhoto]);
            };
            reader.readAsDataURL(file);

        } catch (error) {
            console.error('Capture failed:', error);
            alert(`Capture failed: ${error instanceof Error ? error.message : String(error)}`);
        }
    };

    const handleDeletePhoto = (index: number) => {
        setCapturedPhotos(prev => prev.filter((_, i) => i !== index));
    };

    const handleSaveAndNext = () => {
        if (onSaveSet) {
            onSaveSet(capturedPhotos);
            setCapturedPhotos([]);
        }
    };

    return (
        <div className="camera-overlay">
            <div className="camera-video-wrapper">
                <video ref={videoRef} autoPlay playsInline muted className="camera-video" />

                <div className="camera-top-controls">
                    {torchAvailable && (
                        <button className={`camera-icon-button ${torch ? 'active' : ''}`} onClick={() => setTorch(!torch)} aria-label="Toggle Flash">
                            <svg xmlns="http://www.w3.org/2000/svg" width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><polygon points="13 2 3 14 12 14 11 22 21 10 12 10 13 2"></polygon></svg>
                        </button>
                    )}
                </div>
            </div>

            {capturedPhotos.length > 0 && (
                <div className="captured-photos-bar">
                    {capturedPhotos.map((p, i) => 
                        <div key={i} className="captured-thumbnail">
                            <img src={p.dataUrl} alt={`Captured photo ${i+1}`} />
                            <button className="delete-photo" onClick={() => handleDeletePhoto(i)} aria-label="Delete photo">&times;</button>
                        </div>
                    )}
                </div>
            )}

            <div className="camera-controls-wrapper">
                {zoomCapabilities && (
                    <div className="camera-zoom-row">
                        <svg xmlns="http://www.w3.org/2000/svg" width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="white" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><circle cx="11" cy="11" r="8"></circle><line x1="21" y1="21" x2="16.65" y2="16.65"></line><line x1="11" y1="8" x2="11" y2="14"></line><line x1="8" y1="11" x2="14" y2="11"></line></svg>
                        <input 
                            type="range" 
                            className="camera-zoom-slider" 
                            min={zoomCapabilities.min} 
                            max={zoomCapabilities.max} 
                            step={zoomCapabilities.step} 
                            value={zoom} 
                            onChange={e => setZoom(parseFloat(e.target.value))} 
                        />
                    </div>
                )}

                <div className="camera-main-controls">
                    {mode === 'single-case' ? (
                        <>
                            <button className="camera-action-button" onClick={onCancel}>Cancel</button>
                            <button className="capture-button" onClick={handleCapture} aria-label="Capture photo">
                                <div className="capture-button-inner" />
                            </button>
                            <button className="camera-action-button" onClick={() => onDone && onDone(capturedPhotos)} disabled={capturedPhotos.length === 0}>
                                Done ({capturedPhotos.length})
                            </button>
                        </>
                    ) : (
                        <>
                            <button className="camera-action-button" onClick={() => onFinishPatrol && onFinishPatrol(capturedPhotos)}>Finish</button>
                            <button className="capture-button" onClick={handleCapture} aria-label="Capture photo">
                                <div className="capture-button-inner" />
                            </button>
                            <button className="camera-action-button" onClick={handleSaveAndNext} disabled={capturedPhotos.length === 0}>
                                Save Set
                            </button>
                        </>
                    )}
                </div>
            </div>
        </div>
    );
};

export default CameraView;

import React, { useState, useEffect, useRef } from 'react';
import { Case, PhotoWithMeta, EvidencePhoto, Property } from '../types';
import { initialAddressState, initialOwnerState, initialViolationState, VIOLATIONS_LIST, COMPLIANCE_DAYS } from '../constants';
import { analyzePhotoWithAI } from '../aiService';
import { dataService } from '../googleSheetsService';
import CameraView from './CameraView';

interface NewCaseFormProps {
    onSave: (draftCase: (Partial<Case> & { _tempPhotos?: PhotoWithMeta[] })) => void;
    onCancel: () => void;
    properties: Property[];
    draftCase: (Partial<Case> & { _tempPhotos?: PhotoWithMeta[] }) | null;
    onUpdateDraft: (draft: (Partial<Case> & { _tempPhotos?: PhotoWithMeta[] }) | null) => void;
}

const NewCaseForm: React.FC<NewCaseFormProps> = ({ onSave, onCancel, properties, draftCase, onUpdateDraft }) => {
    // UI-specific state
    const [showCamera, setShowCamera] = useState(false);
    const [isAnalyzing, setIsAnalyzing] = useState(false);
    const [aiError, setAiError] = useState('');
    const [isSaving, setIsSaving] = useState(false); 
    const [lookupMessage, setLookupMessage] = useState('');
    const [validationErrors, setValidationErrors] = useState<string[]>([]);
    const fileInputRef = useRef<HTMLInputElement>(null);
    const formTopRef = useRef<HTMLDivElement>(null);

    const caseId = draftCase?.caseId || '';
    const address = draftCase?.address || initialAddressState;
    const owner = draftCase?.ownerInfo || initialOwnerState;
    const ownerUnknown = draftCase?.ownerInfoStatus === 'UNKNOWN';
    const violation = draftCase?.violation || initialViolationState;
    const isVacant = draftCase?.isVacant || false;
    const photos = draftCase?._tempPhotos || [];
    const violationManual = (violation.type === 'Other (Manual Entry)' && draftCase?.violation) || initialViolationState;

    const updateDraft = (updates: Partial<Case> & { _tempPhotos?: PhotoWithMeta[] }) => {
        if (draftCase) {
            onUpdateDraft({ ...draftCase, ...updates });
        }
    };

    const handleAddressLookup = () => {
        const trimmedAddress = address.street.trim();
        if (!trimmedAddress) {
            setLookupMessage('Please enter an address to look up.');
            return;
        }
        const foundProperty = properties.find(p => p.streetAddress.toLowerCase() === trimmedAddress.toLowerCase());

        if (foundProperty) {
            const updates: Partial<Case> = {
                ownerInfo: { ...initialOwnerState, ...foundProperty.ownerInfo },
                isVacant: foundProperty.isVacant,
                ownerInfoStatus: 'KNOWN'
            };
            updateDraft(updates);
            setLookupMessage('Success: Owner and property info have been pre-filled from the directory.');
        } else {
            setLookupMessage('Info: No existing property found for this address.');
        }
    };

    // FIX: Added explicit File type to the map callback to resolve "Type '{}' is missing properties from type 'File'" and ensure correct Blob handling in reader.readAsDataURL.
    const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
        const files = e.target.files;
        if (!files || files.length === 0) return;

        const newPhotosPromises = Array.from(files).map((file: File) => {
            return new Promise<PhotoWithMeta>((resolve) => {
                const reader = new FileReader();
                reader.onload = () => {
                    resolve({
                        file,
                        dataUrl: reader.result as string
                    });
                };
                reader.readAsDataURL(file);
            });
        });

        Promise.all(newPhotosPromises).then(newPhotos => {
            updateDraft({ _tempPhotos: [...photos, ...newPhotos] });
            if (fileInputRef.current) fileInputRef.current.value = '';
        });
    };

    const handleSubmit = (e: React.FormEvent) => {
        e.preventDefault();
        if (!draftCase) return;

        const errors: string[] = [];
        const finalViolation = violation.type === 'Other (Manual Entry)' ? violationManual : violation;
        const isOwnerInfoValid = ownerUnknown || (owner.name?.trim() && owner.mailingAddress?.trim());

        if (!draftCase.caseId?.trim()) errors.push("Case Number (Firm ID) is missing.");
        if (!address.street?.trim()) errors.push("Property Street Address is missing.");
        if (finalViolation.type === 'Select a Violation...') errors.push("Violation Type has not been selected.");
        if (!isOwnerInfoValid) errors.push("Owner name and mailing address are required (or mark as unknown).");

        if (errors.length > 0) {
            setValidationErrors(errors);
            // Scroll to top to show error list
            formTopRef.current?.scrollIntoView({ behavior: 'smooth' });
            return;
        }

        setValidationErrors([]);
        setIsSaving(true);
        onSave(draftCase);
    };

    const handleViolationChange = (e: React.ChangeEvent<HTMLSelectElement>) => {
        const selected = VIOLATIONS_LIST.find(v => v.type === e.target.value) || initialViolationState;
        updateDraft({ violation: selected });
    };

    const handleAnalyzePhoto = async () => {
        const photoToAnalyze = photos[0]?.file;
        if (!photoToAnalyze) {
            setAiError('Please take or upload at least one photo before using AI analysis.');
            return;
        }
        setIsAnalyzing(true);
        setAiError('');
        try {
            const result = await analyzePhotoWithAI(photoToAnalyze);
            const updates: Partial<Case> = {};
            if (result.address?.street) updates.address = { ...address, street: result.address.street };
            if (result.violation) updates.violation = result.violation;
            updateDraft(updates);
        } catch (e: any) {
            setAiError(`AI Analysis Failed: ${e.message}`);
        } finally {
            setIsAnalyzing(false);
        }
    };

    return (
        <div ref={formTopRef}>
        {showCamera && <CameraView 
            mode="single-case"
            onDone={(p) => { 
                updateDraft({ _tempPhotos: [...photos, ...p] });
                setShowCamera(false); 
            }} 
            onCancel={() => setShowCamera(false)} 
        />}
        <form onSubmit={handleSubmit} className="tab-content">
            {validationErrors.length > 0 && (
                <div className="error-message">
                    <strong>Incomplete Form:</strong>
                    <ul style={{ marginTop: '0.5rem', paddingLeft: '1.25rem' }}>
                        {validationErrors.map((err, i) => <li key={i}>{err}</li>)}
                    </ul>
                </div>
            )}

            <div className="card">
                <h2>Property & Photos</h2>
                 <div className="form-group">
                    <label>Case Number (Firm-Specific ID)</label>
                    <input type="text" value={caseId} onChange={e => updateDraft({ caseId: e.target.value })} />
                </div>
                 <div className="form-group">
                    <label>Street Address</label>
                    <div className="input-with-button">
                        <input type="text" value={address.street} onChange={e => { updateDraft({ address: {...address, street: e.target.value}}); setLookupMessage(''); }} />
                        <button type="button" className="button" onClick={handleAddressLookup}>Look up</button>
                    </div>
                    {lookupMessage && <p className={`helper-text ${lookupMessage.startsWith('Success') ? 'success-message' : 'info-box'}`} style={{padding: '0.5rem', marginTop: '0.5rem'}}>{lookupMessage}</p>}
                </div>
                <div className="form-group"><label style={{display: 'flex', alignItems: 'center', gap: '0.5rem', cursor: 'pointer'}}><input type="checkbox" checked={isVacant} onChange={e => updateDraft({ isVacant: e.target.checked })} style={{width: '1.2rem', height: '1.2rem'}} /> Mark as vacant</label></div>

                <h4>Evidence Photos ({photos.length})</h4>
                <div className="photo-gallery" style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fill, minmax(80px, 1fr))', gap: '8px', margin: '1rem 0' }}>
                    {photos.map((p, i) => (
                        <div key={i} className="photo-thumbnail" style={{ aspectRatio: '1', overflow: 'hidden', borderRadius: '8px', border: '1px solid var(--border-color)' }}>
                            <img src={p.dataUrl} alt={`Evidence photo ${i+1}`} style={{ width: '100%', height: '100%', objectFit: 'cover' }}/>
                        </div>
                    ))}
                </div>

                <div className="button-group" style={{marginTop: '1rem'}}>
                    <button type="button" className="button" onClick={() => setShowCamera(true)}>Open Camera</button>
                    <button type="button" className="button secondary-action" onClick={() => fileInputRef.current?.click()}>Upload Photos</button>
                    <input 
                        type="file" 
                        ref={fileInputRef} 
                        style={{ display: 'none' }} 
                        multiple 
                        accept="image/*" 
                        onChange={handleFileUpload}
                    />
                    <button type="button" className="button secondary-action" onClick={handleAnalyzePhoto} disabled={isAnalyzing || photos.length === 0}>{isAnalyzing ? <span className="loader"/> : 'Analyze with AI'}</button>
                </div>
                {aiError && <p className="error-message" style={{marginTop: '1rem'}}>{aiError}</p>}
            </div>

            <div className="card">
                <h2>Owner Information</h2>
                <div className="form-group"><label style={{display: 'flex', alignItems: 'center', gap: '0.5rem', cursor: 'pointer'}}><input type="checkbox" checked={ownerUnknown} onChange={e => updateDraft({ ownerInfoStatus: e.target.checked ? 'UNKNOWN' : 'KNOWN' })} style={{width: '1.2rem', height: '1.2rem'}} /> Owner information is unknown</label></div>
                <div className="form-group"><label>Owner Name</label><input type="text" value={owner.name} onChange={e => updateDraft({ ownerInfo: {...owner, name: e.target.value}})} disabled={ownerUnknown} /></div>
                <div className="form-group">
                    <label>Mailing Address</label>
                    <textarea value={owner.mailingAddress} onChange={e => updateDraft({ ownerInfo: {...owner, mailingAddress: e.target.value}})} disabled={ownerUnknown} style={{minHeight: '80px'}}></textarea>
                    <p className="helper-text">For multi-line addresses on envelopes, use the Enter/Return key for line breaks.</p>
                </div>
            </div>

            <div className="card">
                <h2>Violation Details</h2>
                <div className="form-group"><label>Violation Type</label><select value={violation.type} onChange={handleViolationChange}><option disabled>Select a Violation...</option>{VIOLATIONS_LIST.map(v => <option key={v.type} value={v.type}>{v.type}</option>)}</select></div>
                {violation.type === 'Other (Manual Entry)' ? (
                    <>
                        <div className="form-group"><label>Ordinance</label><input type="text" value={violationManual.ordinance} onChange={e => updateDraft({ violation: {...violationManual, ordinance: e.target.value}})} /></div>
                        <div className="form-group"><label>Description</label><textarea value={violationManual.description} onChange={e => updateDraft({ violation: {...violationManual, description: e.target.value}})} style={{minHeight: '80px'}} /></div>
                    </>
                ) : (
                    <>
                        <div className="form-group readonly"><label>Ordinance</label><div className="form-value">{violation.ordinance || 'N/A'}</div></div>
                        <div className="form-group readonly"><label>Description</label><div className="form-value">{violation.description || 'N/A'}</div></div>
                    </>
                )}
            </div>

            <div className="button-group" style={{ justifyContent: 'flex-end'}}>
                <button type="button" className="button secondary-action" onClick={onCancel} disabled={isSaving}>Cancel</button>
                <button type="submit" className="button primary-action" disabled={isSaving}>
                    {isSaving ? <><span className="loader" style={{ marginRight: '8px' }} /> Saving...</> : 'Save Case'}
                </button>
            </div>
        </form>
        </div>
    );
};

export default NewCaseForm;

:root {
  --primary-color: #0284c7; /* Sky 600 */
  --primary-dark: #0369a1;
  --primary-light: #e0f2fe;

  --bg-color: #f1f5f9;      /* Slate 100 */
  --card-bg: #ffffff;

  --text-main: #1e293b;     /* Slate 800 */
  --text-secondary: #64748b; /* Slate 500 */
  --text-light: #94a3b8;    /* Slate 400 */

  --border-color: #e2e8f0;  /* Slate 200 */

  --danger-color: #ef4444;
  --success-color: #10b981;
  --warning-color: #f59e0b;
  --abatement-color: #8b5cf6;

  --shadow-sm: 0 1px 3px 0 rgb(0 0 0 / 0.1);
  --shadow-md: 0 4px 6px -1px rgb(0 0 0 / 0.1);
  --shadow-lg: 0 10px 15px -3px rgb(0 0 0 / 0.1);

  --radius-md: 12px;
  --radius-lg: 16px;
  --radius-full: 9999px;

  --header-height: 64px;
}

* {
  box-sizing: border-box;
  margin: 0;
  padding: 0;
  -webkit-tap-highlight-color: transparent;
}

body {
  font-family: 'Roboto', system-ui, -apple-system, sans-serif;
  background-color: var(--bg-color);
  color: var(--text-main);
  line-height: 1.6;
  font-size: 16px;
  padding-bottom: 40px;
  overscroll-behavior-y: none; /* Prevent pull-to-refresh during camera use */
}

/* --- Header & Nav --- */
.app-header {
  background: white;
  height: var(--header-height);
  display: flex;
  align-items: center;
  padding: 0 1.5rem;
  position: sticky;
  top: 0;
  z-index: 100;
  border-bottom: 1px solid var(--border-color);
  box-shadow: var(--shadow-sm);
}

.app-header h1 {
  font-size: 1.25rem;
  font-weight: 700;
  color: var(--text-main);
  flex-grow: 1;
  text-align: center;
}

.main-nav {
  display: flex;
  flex-wrap: wrap;
  justify-content: center;
  padding: 1rem;
  gap: 0.5rem;
  background-color: var(--bg-color);
  position: sticky;
  top: var(--header-height);
  z-index: 90;
}

.main-nav button {
  padding: 0.5rem 1rem;
  border: 1px solid transparent;
  background: white;
  color: var(--text-secondary);
  font-size: 0.9rem;
  font-weight: 600;
  cursor: pointer;
  border-radius: var(--radius-full);
  transition: all 0.2s;
  box-shadow: var(--shadow-sm);
  white-space: nowrap;
}

.main-nav button.active {
  background-color: var(--primary-color);
  color: white;
  box-shadow: var(--shadow-md);
}

/* --- Layout --- */
.app-container {
  display: flex;
  flex-direction: column;
  min-height: 100vh;
}

#root {
  max-width: 800px;
  margin: 0 auto;
  width: 100%;
}

.main-content {
  padding: 1rem 1.25rem;
}

.tab-content {
  display: flex;
  flex-direction: column;
  gap: 1.5rem;
  animation: fadeIn 0.3s ease-out;
}

@keyframes fadeIn {
  from { opacity: 0; transform: translateY(10px); }
  to { opacity: 1; transform: translateY(0); }
}

/* --- Cards --- */
.card {
  background: white;
  border-radius: var(--radius-lg);
  box-shadow: var(--shadow-sm);
  padding: 1.5rem;
  border: 1px solid var(--border-color);
}

.card h2 {
  font-size: 1.25rem;
  margin-bottom: 1.25rem;
  font-weight: 700;
  display: flex;
  align-items: center;
  gap: 0.5rem;
}

/* --- Buttons --- */
.button {
  display: inline-flex;
  align-items: center;
  justify-content: center;
  padding: 0.75rem 1.5rem;
  border-radius: var(--radius-md);
  border: none;
  background: var(--primary-color);
  color: white;
  font-weight: 700;
  cursor: pointer;
  transition: all 0.2s;
  min-height: 48px;
}
.button:hover { background: var(--primary-dark); transform: translateY(-1px); }
.button:active { transform: translateY(0); }
.button:disabled { background: var(--text-light); opacity: 0.5; cursor: not-allowed; }

.button.secondary-action {
  background: white;
  color: var(--text-main);
  border: 1px solid var(--border-color);
}
.button.danger-action { background: var(--danger-color); }

.button-group {
  display: flex;
  gap: 1rem;
  flex-wrap: wrap;
}

/* --- Forms --- */
.form-group { margin-bottom: 1.5rem; }
.form-group label {
  display: block;
  font-size: 0.85rem;
  font-weight: 700;
  color: var(--text-secondary);
  margin-bottom: 0.5rem;
  text-transform: uppercase;
  letter-spacing: 0.05em;
}
input, textarea, select {
  width: 100%;
  padding: 0.75rem 1rem;
  border: 1px solid var(--border-color);
  border-radius: var(--radius-md);
  font-size: 1rem;
  background: white;
  transition: border-color 0.2s, box-shadow 0.2s;
}
input:focus { outline: none; border-color: var(--primary-color); }

input.invalid, textarea.invalid, select.invalid {
  border-color: var(--danger-color);
  background-color: #fff1f2;
  box-shadow: 0 0 0 2px rgba(239, 68, 68, 0.2);
}

.success-message { background: #dcfce7; color: #166534; padding: 1rem; border-radius: var(--radius-md); border: 1px solid #bbf7d0; }
.error-message { background: #fee2e2; color: #991b1b; padding: 1rem; border-radius: var(--radius-md); border: 1px solid #fecaca; }
.info-box { background: #e0f2fe; color: #075985; padding: 1rem; border-radius: var(--radius-md); }

/* --- Camera Interface --- */
.camera-overlay {
  position: fixed;
  top: 0;
  left: 0;
  right: 0;
  bottom: 0;
  background: #000;
  z-index: 2000;
  display: flex;
  flex-direction: column;
  height: 100dvh;
  touch-action: none;
}

.camera-video-wrapper {
  flex-grow: 1;
  position: relative;
  display: flex;
  align-items: center;
  justify-content: center;
  overflow: hidden;
  background: #000;
}

.camera-video {
  width: 100%;
  height: 100%;
  object-fit: cover;
  transition: transform 0.2s ease-out; /* For digital zoom fallback */
}

.camera-controls-wrapper {
  background: rgba(0, 0, 0, 0.95);
  padding: 1.5rem 1rem;
  padding-bottom: calc(1.5rem + env(safe-area-inset-bottom));
  display: flex;
  flex-direction: column;
  gap: 1.25rem;
  z-index: 20;
}

.camera-zoom-row {
  display: flex;
  align-items: center;
  gap: 0.75rem;
  padding: 0 0.5rem;
}

.zoom-btn {
  background: rgba(255, 255, 255, 0.2);
  border: none;
  color: white;
  width: 36px;
  height: 36px;
  border-radius: 50%;
  font-size: 1.25rem;
  font-weight: bold;
  display: flex;
  align-items: center;
  justify-content: center;
}

.camera-zoom-slider {
  flex-grow: 1;
  height: 32px;
  background: transparent;
  cursor: pointer;
  accent-color: var(--primary-color);
  -webkit-appearance: none;
}

.camera-zoom-slider::-webkit-slider-runnable-track {
  height: 6px;
  background: rgba(255, 255, 255, 0.3);
  border-radius: 3px;
}

.camera-zoom-slider::-webkit-slider-thumb {
  -webkit-appearance: none;
  height: 28px;
  width: 28px;
  border-radius: 50%;
  background: #fff;
  margin-top: -11px;
  box-shadow: 0 2px 6px rgba(0,0,0,0.8);
