.camera-main-controls {
  display: flex;
  align-items: center;
  justify-content: space-between;
  max-width: 400px;
  margin: 0 auto;
  width: 100%;
}

.capture-button {
  width: 80px;
  height: 80px;
  border-radius: 50%;
  border: 6px solid white;
  background: transparent;
  display: flex;
  align-items: center;
  justify-content: center;
  padding: 0;
  transition: transform 0.1s;
}

.capture-button:active {
