}

.capture-button-inner {
  width: 58px;
  height: 58px;
  border-radius: 50%;
  background: white;
}

.camera-action-button {
  background: transparent;
  border: none;
  color: white;
  font-weight: 700;
  font-size: 0.95rem;
  cursor: pointer;
  min-width: 80px;
  text-align: center;
  padding: 10px;
}

.loading-overlay {
  position: fixed;
  top: 0;
  left: 0;
  right: 0;
  bottom: 0;
  background: rgba(255, 255, 255, 0.8);
  backdrop-filter: blur(4px);
  z-index: 3000;
  display: flex;
  flex-direction: column;
  align-items: center;
  justify-content: center;
