import React, { useState, useMemo } from 'react';
import { Case, AbatementStatus } from '../types';
import { getCaseTimeStatus, compareStreets } from '../utils';

const getStatusClass = (c: Case): string => {
    if (c.status === 'CLOSED') return 'closed';
    if (c.status === 'PENDING_ABATEMENT') return 'abatement';
    if (c.status === 'CONTINUAL_ABATEMENT') return 'continual-abatement';
    return getCaseTimeStatus(c);
};

interface CaseListProps {
    cases: Case[];
    onSelectCase: (caseId: string) => void;
    onNewCase: () => void;
    listType?: 'all' | 'due' | 'abatement' | 'continual-abatement';
    onGenerateReport?: () => void;
}

const CaseItemRow: React.FC<{ c: Case; onSelect: () => void; showExpiry?: boolean; subtitle?: string; badge?: string; badgeClass?: string }> = ({ c, onSelect, showExpiry, subtitle, badge, badgeClass }) => {
    const statusClass = getStatusClass(c);

    let displayStatus = '';
    if (c.status === 'PENDING_ABATEMENT') displayStatus = 'Abatement';
    else if (c.status === 'CONTINUAL_ABATEMENT') displayStatus = 'Continual';
    else if (c.status === 'CLOSED') displayStatus = 'Closed';
    else displayStatus = 'Active';

    let expiryDateText = '';
    if (showExpiry && c.abatement?.workDate) {
        const workDate = new Date(c.abatement.workDate.replace(/-/g, '\/'));
        if (!isNaN(workDate.getTime())) {
            workDate.setMonth(workDate.getMonth() + 6);
            expiryDateText = `Expires: ${workDate.toLocaleDateString()}`;
        }
    }

    return (
        <div className={`case-item ${statusClass}`} onClick={onSelect} role="button" tabIndex={0} aria-label={`View case ${c.caseId}`}>
            <div className="case-info">
                <div style={{display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '0.2rem'}}>
                    <strong>{c.address.street}</strong>
                    {badge ? (
                        <span style={{ 
                            fontSize: '0.75rem', 
                            padding: '2px 8px', 
                            borderRadius: '99px', 
                            fontWeight: 700, 
                            textTransform: 'uppercase',
                            backgroundColor: badgeClass ? `var(${badgeClass})` : 'var(--primary-color)',
                            color: 'white'
                        }}>{badge}</span>
                    ) : (
                        <span style={{ fontSize: '0.8rem', color: 'var(--text-light)', fontWeight: 600 }}>{displayStatus.toUpperCase()}</span>
                    )}
                </div>

                {c.ownerInfoStatus === 'UNKNOWN' && (
                     <span style={{ fontSize: '0.75rem', backgroundColor: '#fef08a', color: '#854d0e', padding: '2px 6px', borderRadius: '4px', fontWeight: 600, display: 'inline-block', marginBottom: '0.25rem' }}>Owner Unknown</span>
                )}

                <span>{subtitle ? subtitle : (c.ownerInfo?.name || 'No Owner Listed')}</span>

                <div style={{ display: 'flex', justifyContent: 'space-between', marginTop: '0.5rem', fontSize: '0.85rem', color: 'var(--text-light)' }}>
                    <span>#{c.caseId}</span>
                    <span>{expiryDateText}</span>
                </div>
            </div>
        </div>
    );
};

const CaseList: React.FC<CaseListProps> = ({ cases, onSelectCase, onNewCase, listType = 'all', onGenerateReport }) => {
    const [searchTerm, setSearchTerm] = useState('');
    const [filter, setFilter] = useState('ALL');
    const [sortOrder, setSortOrder] = useState('street');

    const filterOptions = [
        { value: 'ALL', label: 'All Open & Closed Cases' },
        { value: 'OPEN', label: 'All Open Cases' },
        { value: 'ABATEMENT', label: 'Ready for Abatement' },
        { value: 'VACANT', label: 'Vacant Properties' },
        { value: 'DILAPIDATED', label: 'Dilapidated Structures' },
        { value: 'UNKNOWN_OWNER', label: 'Unknown Owner' },
        { value: 'TALL_GRASS', label: 'Tall Grass / Weeds' },
        { value: 'INOPERABLE_VEHICLE', label: 'Inoperable Vehicles' },
    ];

    const filteredCases = useMemo(() => {
        let intermediateCases = [...cases];

        const filterFunctions: Record<string, (c: Case) => boolean> = {
            'OPEN': c => c.status !== 'CLOSED',
            'ABATEMENT': c => c.status === 'PENDING_ABATEMENT',
            'VACANT': c => c.isVacant,
            'DILAPIDATED': c => c.violation.type === 'Dilapidated Structure',
            'UNKNOWN_OWNER': c => c.ownerInfoStatus === 'UNKNOWN',
            'TALL_GRASS': c => c.violation.type === 'Tall Grass / Weeds',
            'INOPERABLE_VEHICLE': c => c.violation.type === 'Inoperable / Abandoned Vehicle'
        };

        if (filter !== 'ALL' && filterFunctions[filter]) {
            intermediateCases = intermediateCases.filter(filterFunctions[filter]);
        }

        const sortedCases = intermediateCases.sort((a, b) => {
            if (listType === 'abatement') {
                const statusOrder: Record<string, number> = { 'NEEDS_ABATEMENT': 0, 'STATEMENT_FILED': 1, 'LIEN_FILED': 2, 'LIEN_CERTIFIED': 3 };
                const statA = a.abatement?.status || 'NEEDS_ABATEMENT';
                const statB = b.abatement?.status || 'NEEDS_ABATEMENT';
                if (statusOrder[statA] !== statusOrder[statB]) return statusOrder[statA] - statusOrder[statB];
                return compareStreets(a.address.street, b.address.street); 
            }

            if (sortOrder === 'recent') {
                return new Date(b.dateCreated).getTime() - new Date(a.dateCreated).getTime();
            }

            // Default 'street' sort
            if (a.status === 'CLOSED' && b.status !== 'CLOSED') return 1;
            if (a.status !== 'CLOSED' && b.status === 'CLOSED') return -1;
            return compareStreets(a.address.street, b.address.street);
        });

        if (!searchTerm) return sortedCases;
        return sortedCases.filter(c => 
            c.address.street.toLowerCase().includes(searchTerm.toLowerCase()) ||
            c.caseId.toLowerCase().includes(searchTerm.toLowerCase()) ||
            c.ownerInfo.name?.toLowerCase().includes(searchTerm.toLowerCase())
        );
    }, [cases, searchTerm, filter, listType, sortOrder]);

    const getLienWaitStatus = (dateStr?: string): { daysLeft: number, ready: boolean } => {
        if (!dateStr) return { daysLeft: 30, ready: false };
        const start = new Date(dateStr);
        const now = new Date();
        start.setHours(0,0,0,0);
        now.setHours(0,0,0,0);
        const diffTime = now.getTime() - start.getTime();
        const diffDays = Math.floor(diffTime / (1000 * 60 * 60 * 24));
        const daysLeft = 30 - diffDays;
        return { 
            daysLeft: Math.max(0, daysLeft),
            ready: diffDays >= 30 
        };
    };

    const renderAbatementGroups = () => {
        const groups: Record<string, { cases: Case[], info: string, colorClass: string }> = {
            'Needs Abatement': { cases: [], info: 'Work needs to be performed or documented.', colorClass: '--danger-color' },
            'Statement Filed': { cases: [], info: 'Work done. Waiting to file Lien.', colorClass: '--primary-color' },
            'Lien Waiting Period': { cases: [], info: 'Notice of Lien filed. Waiting 30 days.', colorClass: '--warning-color' },
            'Action Required': { cases: [], info: '30-day period expired. Ready for Certificate of Lien.', colorClass: '--abatement-color' },
            'Finalized': { cases: [], info: 'Lien Certified or Released.', colorClass: '--success-color' }
        };

        filteredCases.forEach(c => {
            const status = c.abatement?.status || 'NEEDS_ABATEMENT';
            if (status === 'NEEDS_ABATEMENT') {
                groups['Needs Abatement'].cases.push(c);
            } else if (status === 'STATEMENT_FILED') {
                groups['Statement Filed'].cases.push(c);
            } else if (status === 'LIEN_FILED') {
                const { ready } = getLienWaitStatus(c.abatement?.noticeOfLienDate);
                if (ready) {
                    groups['Action Required'].cases.push(c);
                } else {
                    groups['Lien Waiting Period'].cases.push(c);
                }
            } else if (status === 'LIEN_CERTIFIED' || status === 'LIEN_RELEASED') {
                groups['Finalized'].cases.push(c);
            } else {
                groups['Needs Abatement'].cases.push(c);
            }
        });

        return (
            <div className="abatement-groups">
                {Object.entries(groups).map(([groupName, data]) => (
                    <div key={groupName} style={{marginBottom: '2rem'}}>
                        <h3 style={{
                            fontSize: '1rem',
                            borderBottom: '2px solid var(--border-color)', 
                            paddingBottom: '0.5rem',
                            color: `var(${data.colorClass})`,
                            display: 'flex',
                            justifyContent: 'space-between',
                            alignItems: 'center',
                            marginBottom: '1rem',
                            textTransform: 'uppercase',
                            letterSpacing: '0.05em'
                        }}>
                            {groupName} 
                            <span style={{
                                fontSize: '0.85rem', 
                                backgroundColor: data.cases.length > 0 ? `var(${data.colorClass})` : 'var(--bg-color)', 
                                color: data.cases.length > 0 ? 'white' : 'var(--text-secondary)', 
                                padding: '2px 10px', 
                                borderRadius: '99px'
                            }}>
                                {data.cases.length}
                            </span>
                        </h3>

                        {data.cases.length > 0 ? (
                            data.cases.map(c => {
                                let subtitle = c.ownerInfo?.name || 'Unknown Owner';
                                let badge = undefined;
                                let badgeClass = undefined;

                                if (groupName === 'Lien Waiting Period') {
                                    const { daysLeft } = getLienWaitStatus(c.abatement?.noticeOfLienDate);
                                    badge = `${daysLeft} Days Left`;
                                    badgeClass = '--warning-color';
                                    subtitle = `Filed: ${c.abatement?.noticeOfLienDate || 'Unknown'}`;
                                } else if (groupName === 'Action Required') {
                                    badge = 'READY TO CERTIFY';
                                    badgeClass = '--success-color';
                                }

                                return (
                                    <CaseItemRow 
                                        key={c.id} 
                                        c={c} 
                                        onSelect={() => onSelectCase(c.id)} 
                                        showExpiry={listType === 'continual-abatement'}
                                        subtitle={subtitle}
                                        badge={badge}
                                        badgeClass={badgeClass}
                                    />
                                );
                            })
                        ) : (
                            <p style={{color: 'var(--text-secondary)', fontStyle: 'italic', fontSize: '0.95rem', padding: '0.5rem'}}>No cases in this stage.</p>
                        )}
                    </div>
                ))}
            </div>
        );
    };

    return (
        <div className="tab-content">
            <div className="search-bar">
                 <svg className="search-icon" xmlns="http://www.w3.org/2000/svg" width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><circle cx="11" cy="11" r="8"></circle><line x1="21" y1="21" x2="16.65" y2="16.65"></line></svg>
                <input type="text" placeholder="Search cases..." value={searchTerm} onChange={e => setSearchTerm(e.target.value)} />
            </div>

            <div className="filters-container">
                {listType === 'all' && (
                    <div className="form-group">
                        <label htmlFor="case-filter">Filter By</label>
                        <select id="case-filter" value={filter} onChange={e => setFilter(e.target.value)}>
                            {filterOptions.map(opt => <option key={opt.value} value={opt.value}>{opt.label}</option>)}
                        </select>
                    </div>
                )}
                 {listType !== 'abatement' && (
                    <div className="form-group">
                        <label htmlFor="case-sort">Sort By</label>
                        <select id="case-sort" value={sortOrder} onChange={e => setSortOrder(e.target.value)}>
                            <option value="street">Street Address</option>
                            <option value="recent">Most Recent</option>
                        </select>
                    </div>
                )}
            </div>


             {listType === 'abatement' && onGenerateReport && (
                 <button className="button full-width" onClick={onGenerateReport} style={{marginBottom: '1rem', backgroundColor: 'var(--abatement-color)'}}>Generate Abatement Report</button>
            )}

            <button className="button primary-action full-width" onClick={onNewCase} style={{ boxShadow: 'var(--shadow-md)' }}>Create New Case</button>

            <div style={{marginTop: '2rem'}}>
                {filteredCases.length > 0 ? (
                    listType === 'abatement' ? (
                        renderAbatementGroups()
                    ) : (
                        filteredCases.map(c => (
                            <CaseItemRow 
                                key={c.id} 
                                c={c} 
                                onSelect={() => onSelectCase(c.id)} 
                                showExpiry={listType === 'continual-abatement'} 
                            />
                        ))
                    )
                ) : ( <div className="card empty-state"><p style={{textAlign: 'center', color: 'var(--text-secondary)'}}>No cases found matching your criteria.</p></div> )}
            </div>
        </div>
    );
};

export default CaseList;

import React, { useState, useEffect, useRef } from 'react';
import { Case, NoticePurpose, PhotoWithMeta, EvidencePhoto } from '../types';
import { generateNoticeDocument } from '../googleSheetsService';
import { VIOLATIONS_LIST, COMMON_NOTES } from '../constants';
import { getCaseTimeStatus } from '../utils';
import { dataService } from '../googleSheetsService';
import AbatementManager from './AbatementManager';
import CameraView from './CameraView';
import QuickInput from './QuickInput';
import * as dailyTaskService from '../dailyTaskService';

const CaseDetails: React.FC<{ caseData: Case; onBack: () => void; onUpdate: (updatedCase: Case) => void; onDelete: (caseId: string) => void; }> = ({ caseData, onBack, onUpdate, onDelete }) => {
    const [currentCase, setCurrentCase] = useState(caseData);
    const [isGenerating, setIsGenerating] = useState(false);
    const [genError, setGenError] = useState('');
    const [genMsg, setGenMsg] = useState('');

    // State for editing case details
    const [isEditing, setIsEditing] = useState(false);
    const [editableCase, setEditableCase] = useState<Case>(caseData);

    // State for adding new evidence
    const [isSaving, setIsSaving] = useState(false);
    const [newNoteText, setNewNoteText] = useState('');
    const [newPhotos, setNewPhotos] = useState<PhotoWithMeta[]>([]);
    const [showCamera, setShowCamera] = useState(false);
    const fileInputRef = useRef<HTMLInputElement>(null);

    useEffect(() => {
        setCurrentCase(caseData);
        setEditableCase(caseData);
    }, [caseData]);

    const statusClass = getCaseTimeStatus(currentCase);

    const handleGenerate = async (purpose: NoticePurpose) => {
        setIsGenerating(true);
        setGenError('');
        setGenMsg('');
        try {
            const docs = await generateNoticeDocument(purpose, currentCase);
            docs.forEach(d => window.open(d.docUrl, '_blank'));

            const today = new Date().toLocaleDateString('en-US', { year: 'numeric', month: 'long', day: 'numeric' });
            const updatedCase = { ...currentCase };
            updatedCase.notices.unshift({ title: docs[0].title, docUrl: docs[0].docUrl, date: today });

            if (purpose === 'FAILURE') updatedCase.status = 'FAILURE-NOTICED';

            onUpdate(updatedCase);
            dailyTaskService.addToCertMailQueue(updatedCase.id);
            setGenMsg(`Success! Case #${updatedCase.caseId} has been added to the mailing queue.`);

        } catch (e: any) {
            setGenError(`Failed: ${e.message}`);
        } finally {
            setIsGenerating(false);
        }
    };

    const handleStartAbatement = () => {
        if (window.confirm("Forward this case for City Abatement? This will start the Statement of Cost and Lien process.")) {
            const updatedCase: Case = { ...currentCase, status: 'PENDING_ABATEMENT', abatement: { ...currentCase.abatement, status: 'NEEDS_ABATEMENT' } };
            onUpdate(updatedCase);
        }
    };

    const handleSaveChanges = () => {
        onUpdate(editableCase);
        setIsEditing(false);
    };

    const handleCancelEdit = () => {
        setEditableCase(currentCase);
        setIsEditing(false);
    };

    const handleSaveEvidence = async () => {
        if (!newNoteText.trim() && newPhotos.length === 0) return;
        setIsSaving(true);
        setGenError('');
        try {
            const uploadedPhotos: EvidencePhoto[] = await dataService.uploadCasePhotos(newPhotos, currentCase);
            const newNote = { date: new Date().toLocaleDateString('en-US', { year: 'numeric', month: 'long', day: 'numeric' }), text: newNoteText.trim() };
            const updatedCase = { ...currentCase, evidence: { ...currentCase.evidence, photos: [...(currentCase.evidence.photos || []), ...uploadedPhotos], notes: [...currentCase.evidence.notes, newNote] } };
            onUpdate(updatedCase);
            setNewNoteText('');
            setNewPhotos([]);
        } catch (e: any) {
            setGenError(`Failed to save evidence: ${e.message}`);
        } finally {
            setIsSaving(false);
        }
    };

    const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
        const files = e.target.files;
        if (!files) return;
        // FIX: Explicitly type 'file' as File to prevent type inference errors.
        // This resolves issues where 'file' was being incorrectly typed as '{}' or 'unknown',
        // causing errors in both the Promise resolution and the readAsDataURL call.
        const newPhotosPromises = Array.from(files).map((file: File) => new Promise<PhotoWithMeta>(res => {
            const reader = new FileReader();
            reader.onload = () => res({ file, dataUrl: reader.result as string });
            reader.readAsDataURL(file);
        }));
        Promise.all(newPhotosPromises).then(newPs => setNewPhotos(prev => [...prev, ...newPs]));
    };

    const handleDeleteNewPhoto = (index: number) => {
        setNewPhotos(prev => prev.filter((_, i) => i !== index));
    };

    return (
        <div className="tab-content">
            {showCamera && <CameraView mode="single-case" onDone={(p) => { setNewPhotos(prev => [...prev, ...p]); setShowCamera(false); }} onCancel={() => setShowCamera(false)} />}

            <button onClick={onBack} className="button secondary-action no-print">&larr; Back to List</button>

            <div className={`card ${statusClass}`} style={{ borderLeft: '8px solid' }}>
                <h1 style={{ marginBottom: '0.5rem' }}>{currentCase.address.street}</h1>
                <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', flexWrap: 'wrap', gap: '0.5rem' }}>
                    <p style={{ color: 'var(--text-secondary)' }}>Case #{currentCase.caseId} | {currentCase.status.replace('-', ' ')}</p>
                    {currentCase.status !== 'PENDING_ABATEMENT' && currentCase.status !== 'CLOSED' && (
                        <button className="button" style={{ backgroundColor: 'var(--abatement-color)', minHeight: '36px', padding: '0.4rem 0.8rem', fontSize: '0.85rem' }} onClick={handleStartAbatement}>
                            Forward to Abatement &rarr;
                        </button>
                    )}
                </div>
            </div>

            {currentCase.status === 'PENDING_ABATEMENT' && <AbatementManager caseData={currentCase} onUpdate={onUpdate} />}

            <div className="card">
                {isEditing ? (
                    <>
                        <div className="editing-header">
                            <h3>Editing Case Details</h3>
                            <div className="button-group">
                                <button className="button secondary-action" onClick={handleCancelEdit}>Cancel</button>
                                <button className="button primary-action" onClick={handleSaveChanges}>Save</button>
                            </div>
                        </div>
                        <div className="form-group">
                            <label>Street Address</label>
                            <input type="text" value={editableCase.address.street} onChange={e => setEditableCase({...editableCase, address: {...editableCase.address, street: e.target.value}})} />
                        </div>
                        <div className="form-group"><label style={{display: 'flex', alignItems: 'center', gap: '0.5rem'}}><input type="checkbox" checked={editableCase.isVacant} onChange={e => setEditableCase({...editableCase, isVacant: e.target.checked})} /> Mark as vacant</label></div>

                        <h4>Owner Information</h4>
                        <div className="form-group"><label style={{display: 'flex', alignItems: 'center', gap: '0.5rem'}}><input type="checkbox" checked={editableCase.ownerInfoStatus === 'UNKNOWN'} onChange={e => setEditableCase({...editableCase, ownerInfoStatus: e.target.checked ? 'UNKNOWN' : 'KNOWN' })} /> Owner information is unknown</label></div>
                        <div className="form-group">
                            <label>Owner Name</label>
                            <input type="text" value={editableCase.ownerInfo.name} onChange={e => setEditableCase({...editableCase, ownerInfo: {...editableCase.ownerInfo, name: e.target.value}})} disabled={editableCase.ownerInfoStatus === 'UNKNOWN'} />
                        </div>
                        <div className="form-group">
                            <label>Mailing Address</label>
                            <textarea value={editableCase.ownerInfo.mailingAddress} onChange={e => setEditableCase({...editableCase, ownerInfo: {...editableCase.ownerInfo, mailingAddress: e.target.value}})} disabled={editableCase.ownerInfoStatus === 'UNKNOWN'} />
                        </div>

                        <h4>Violation Details</h4>
                        <div className="form-group">
                            <label>Violation Type</label>
                            <select value={editableCase.violation.type} onChange={e => setEditableCase({...editableCase, violation: VIOLATIONS_LIST.find(v => v.type === e.target.value) || editableCase.violation})}>
                                {VIOLATIONS_LIST.map(v => <option key={v.type} value={v.type}>{v.type}</option>)}
                            </select>
                        </div>
                    </>
                ) : (
                    <>
                        <div style={{display: 'flex', justifyContent: 'space-between', alignItems: 'center'}}>
                            <h2>Owner & Property Details</h2>
                            <button className="button" onClick={() => setIsEditing(true)}>Edit Case Details</button>
                        </div>
                        <div className="form-group readonly"><label>Owner Info</label><div className="form-value">{currentCase.ownerInfo.name}<br/>{currentCase.ownerInfo.mailingAddress}</div></div>
                        <div className="form-group readonly"><label>Violation</label><div className="form-value"><strong>{currentCase.violation.type}</strong><br/>{currentCase.violation.description}</div></div>
                    </>
                )}
            </div>

            <div className="card">
                <h2>Evidence Locker</h2>
                <h4>Notes ({currentCase.evidence.notes.length})</h4>
                <div className="notes-list">
                    {currentCase.evidence.notes.map((note, i) => <div key={i} className="note"><div className="note-date">{note.date}</div>{note.text}</div>)}
                </div>
                <h4 style={{marginTop: '1.5rem'}}>Photos ({(currentCase.evidence.photos || []).length})</h4>
                <div className="photo-gallery">
                    {(currentCase.evidence.photos || []).map(p => <div key={p.id} className="photo-thumbnail"><a href={p.webViewLink} target="_blank" rel="noopener noreferrer"><img src={p.url} alt="Evidence" /></a></div>)}
                </div>

                {currentCase.notices && currentCase.notices.length > 0 && (
                    <>
                        <h4 style={{marginTop: '1.5rem'}}>Generated Notices ({currentCase.notices.length})</h4>
                        <div className="notices-list">
                            {currentCase.notices.map((notice, index) => (
                                <a 
                                    key={index} 
                                    href={notice.docUrl} 
                                    target="_blank" 
                                    rel="noopener noreferrer" 
                                    className="notice-item"
                                >
                                    <div className="notice-info">
                                        <strong>{notice.title}</strong>
                                        <span>Generated: {notice.date}</span>
                                    </div>
                                    <div className="notice-action">
                                        <svg xmlns="http://www.w3.org/2000/svg" width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><path d="M18 13v6a2 2 0 0 1-2 2H5a2 2 0 0 1-2-2V8a2 2 0 0 1 2-2h6"></path><polyline points="15 3 21 3 21 9"></polyline><line x1="10" y1="14" x2="21" y2="3"></line></svg>
                                    </div>
                                </a>
                            ))}
                        </div>
                    </>
                )}
            </div>

            <div className="card no-print">
                <h2>Add Evidence</h2>
                <div className="form-group">
                    <label>New Note</label>
                    <QuickInput value={newNoteText} onChange={setNewNoteText} options={COMMON_NOTES} placeholder="Add a note..."/>
                </div>
                <h4>Add Photos ({newPhotos.length})</h4>
                 <div className="photo-gallery">
                    {newPhotos.map((p, i) => (
                        <div key={i} className="photo-thumbnail-container">
                            <button type="button" className="delete-photo-btn" onClick={() => handleDeleteNewPhoto(i)}>&times;</button>
                            <div className="photo-thumbnail"><img src={p.dataUrl} alt="New evidence" /></div>
                        </div>
                    ))}
                </div>
                <div className="button-group" style={{marginTop: '1rem'}}>
                    <button className="button" onClick={() => setShowCamera(true)}>Open Camera</button>
                    <button className="button secondary-action" onClick={() => fileInputRef.current?.click()}>Upload File</button>
                    <input type="file" ref={fileInputRef} style={{ display: 'none' }} multiple accept="image/*" onChange={handleFileUpload} />
                </div>
                 <button className="button primary-action full-width" onClick={handleSaveEvidence} disabled={isSaving || (!newNoteText.trim() && newPhotos.length === 0)} style={{marginTop: '1.5rem'}}>
                    {isSaving ? <span className="loader" /> : 'Save Evidence'}
                </button>
            </div>

            <div className="card no-print">
                <h2>Generate Notices</h2>
                <div className="button-group">
                    <button className="button" onClick={() => handleGenerate('INITIAL')} disabled={isGenerating}>Initial Notice</button>
                    <button className="button danger-action" onClick={() => handleGenerate('FAILURE')} disabled={isGenerating}>Issue Abatement Notice</button>
                </div>
                 {genError && <div className="error-message" style={{marginTop: '1rem'}}>{genError}</div>}
                 {genMsg && <div className="success-message" style={{marginTop: '1rem'}}>{genMsg}</div>}
            </div>

            <div className="card no-print">
                <button className="button danger-action full-width" onClick={() => onDelete(currentCase.id)}>Delete Entire Case File</button>
            </div>
        </div>
    );
};

export default CaseDetails;

