/**
 * Parses the raw CSV string of tax roll data into an array of objects.
 * This is a simple parser tailored to the specific format of the provided data.
 */
const parseCSV = (csv: string): any[] => {
    const lines = csv.trim().split('\n');
    const headers = lines.shift()?.split(',') || [];

    return lines.map(line => {
        if (!line.includes(',')) return null;

        const values = line.split('","');
        const obj: { [key: string]: string } = {};

        if (values.length === headers.length) {
            headers.forEach((header, i) => {
                let value = values[i];
                if (i === 0) value = value.replace(/^"/, ''); // First value
                if (i === values.length - 1) value = value.replace(/"$/, ''); // Last value
                obj[header.trim()] = value.trim();
            });
            return obj;
        }
        return null; // Line doesn't match expected format
    }).filter(Boolean);
};

/**
 * Returns a structured array of Property objects from the tax roll data.
 */
export const getTaxRollProperties = (): Property[] => {
    const parsedData = parseCSV(rawCsvData);

    return parsedData
        .map((row: any): Property | null => {
            const propertyAddress = (row['Property Address'] || '').trim();

            // Filter out entries that are not valid street addresses.
            if (!propertyAddress || propertyAddress.toLowerCase() === 'commerce' || propertyAddress.startsWith('School District ')) {
                return null;
            }

            // Further clean mailing address
            let mailingAddress = (row['Mailing Address'] || '').trim();
            mailingAddress = mailingAddress.replace(/^% |^C\/O /i, '').replace(/\s+/g, ' ');

            // Remove duplicated headers
            if (row['Owner Name'] === 'Owner Name') {
                return null;
            }

            return {
                id: self.crypto.randomUUID(),
                streetAddress: propertyAddress,
                ownerInfo: {
                    name: (row['Owner Name'] || '').trim(),
                    mailingAddress: mailingAddress,
                    phone: '',
                },
                residentInfo: { name: '', phone: '' },
                isVacant: false,
                dilapidationNotes: '',
            };
        })
        .filter((p): p is Property => p !== null);
};
