                    setView('TASKS');
                    setActiveTab('tasks');
                }
            } else {
                setAppStatus('NEEDS_CONFIG');
                setView('ADMIN');
                setActiveTab('admin');
            }
        } catch (err: any) {
            setError(`Failed to load configuration: ${err.message}`);
            setAppStatus('NEEDS_CONFIG');
        }
    }, [view]);

    useEffect(() => {
        checkConfiguration();
    }, [checkConfiguration]);


    const loadData = useCallback(() => {
        if (appStatus === 'READY') {
            setIsLoading(true);
            setError(null);
            // Only fetch cases now, properties are static
            dataService.getAllData()
                .then(({ cases }) => {
                    setCases(cases);
                })
                .catch(err => setError(`Failed to load data: ${err.message}`))
                .finally(() => setIsLoading(false));
        } else {
            setIsLoading(false);
        }
    }, [appStatus]);

    useEffect(() => { loadData(); }, [loadData]);

    const handleSetupComplete = () => {
        checkConfiguration();
    };

    const handleSelectCase = (caseId: string) => { setSelectedCaseId(caseId); setView('DETAILS'); };

    // Helper to generate the auto-incrementing Case Number: MM-NNN-YY
    const generateNextCaseId = () => {
        const now = new Date();
        const mm = String(now.getMonth() + 1).padStart(2, '0');
        const yy = String(now.getFullYear()).slice(-2);

        // Find all cases from the current month and year
        // We look for patterns like "03-001-24"
        const monthPrefix = `${mm}-`;
        const yearSuffix = `-${yy}`;

        const monthCases = cases.filter(c => 
            c.caseId.startsWith(monthPrefix) && c.caseId.endsWith(yearSuffix)
        );

        let nextNum = 1;
        if (monthCases.length > 0) {
            const nums = monthCases.map(c => {
                const parts = c.caseId.split('-');
                return parts.length === 3 ? parseInt(parts[1], 10) : 0;
            }).filter(n => !isNaN(n));

            if (nums.length > 0) {
                nextNum = Math.max(...nums) + 1;
            }
        }

        const nnn = String(nextNum).padStart(3, '0');
        return `${mm}-${nnn}-${yy}`;
    };

    const handleNewCase = () => {
        if (!draftCase) {
             setDraftCase({
                id: `draft-${Date.now()}`,
                caseId: generateNextCaseId(), // Automatically set the next ID
                address: initialAddressState,
                ownerInfo: initialOwnerState,
                violation: initialViolationState,
                ownerInfoStatus: 'KNOWN',
                isVacant: false,
                _tempPhotos: []
            });
        }
        setView('NEW');
        setActiveTab('new');
    };

    const handleCancelNew = () => {
