// Helper to convert a number to an A1-style column name (e.g., 1 -> A, 27 -> AA)
const toColumnName = (num: number): string => {
    let columnName = '';
    while (num > 0) {
        const remainder = (num - 1) % 26;
        columnName = String.fromCharCode(65 + remainder) + columnName;
        num = Math.floor((num - 1) / 26);
    }
    return columnName;
};

// Helper to provide detailed, user-friendly error messages for Google API failures.
const handleGoogleApiError = async (response: Response, context: string): Promise<Error> => {
    let message = context;
    let details = '';
    try {
        const errorJson = await response.json();
        details = errorJson?.error?.message || JSON.stringify(errorJson);
    } catch {
        // If the response is not JSON, fall back to text.
        details = await response.text();
    }

    if (response.status === 404) {
        message += " The requested file was not found. This can happen if a template URL is incorrect, the document was deleted, or it has not been shared with your Google account. Please verify the URL on the 'Templates' tab and check the 'Share' settings on the Google Doc.";
    } else if (response.status === 403) {
        message += " Permission denied. Your Google account does not have permission to access or modify the requested file. Please check the 'Share' settings on the Google Doc/Sheet and ensure your account has at least 'Viewer' access for templates and 'Editor' access for the main data sheet.";
    } else {
        message += ` An unexpected error occurred (Status: ${response.status}).`;
    }

    return new Error(`${message}\n\nGoogle API Details: ${details}`);
};


// Helper to extract Doc ID from URL
const getDocIdFromUrl = (url: string): string => {
    const match = /\/document\/d\/([a-zA-Z0-9-_]+)/.exec(url);
    if (!match || !match[1]) throw new Error("Invalid Google Doc URL provided. It should look like '.../document/d/DOC_ID/edit'.");
    return match[1];
};

// Helper to map case data to simplified, user-friendly placeholders.
const getNoticeReplacements = (caseData: Case, photoEvidenceLink: string = ''): { [key: string]: string } => {
    const today = new Date().toLocaleDateString('en-US', { year: 'numeric', month: 'long', day: 'numeric' });

    // Combine all notes into a single string for the {{NOTES}} placeholder.
    const notesText = caseData.evidence.notes
        .map(note => `${note.date}: ${note.text}`)
        .join('\n');

    return {
        // General Placeholders
        '{{DATE_TODAY}}': today,
        '{{OWNER_NAME}}': caseData.ownerInfo.name || 'N/A',
        '{{OWNER_MAILING}}': caseData.ownerInfo.mailingAddress || 'N/A',
        '{{CASE_ID}}': caseData.caseId,
        '{{ADDRESS}}': caseData.address.street,
        '{{CITY}}': caseData.address.city,
        '{{STATE}}': caseData.address.province,
        '{{ZIP}}': caseData.address.postalCode,
        '{{NOTES}}': notesText || 'No notes for this case.',
        '{{DUE_DATE}}': caseData.complianceDeadline,
        '{{STATUS}}': caseData.status,
        '{{DATE_CREATED}}': caseData.dateCreated,

        // Violation-specific placeholders from user's template
        '{{VIOLATION}}': caseData.violation.type,
        '{{SECTION}}': caseData.violation.ordinance,
        '{{VIOLATION_DESCRIPTION}}': caseData.violation.description,
        '{{VIOLATION_CORRECTIVE_ACTION}}': caseData.violation.correctiveAction,
        '{{VIOLATION_NOTICE_CLAUSE}}': caseData.violation.noticeClause,

        // Photo Evidence Link
        '{{PHOTO_EVIDENCE_LINK}}': photoEvidenceLink || 'No photographic evidence was attached to this notice.',
    };
};

const findOrCreateFolder = async (name: string, parentId?: string): Promise<string> => {
    const token = await getAccessToken();
    // Sanitize name for Drive query (single quotes must be escaped)
    const safeName = name.replace(/'/g, "\\'");

    let query = `name='${safeName}' and mimeType='application/vnd.google-apps.folder' and trashed=false`;
    if (parentId) {
        query += ` and '${parentId}' in parents`;
    }

    const searchResponse = await fetch(`https://www.googleapis.com/drive/v3/files?q=${encodeURIComponent(query)}&fields=files(id)`, {
        headers: { 'Authorization': `Bearer ${token}` }
    });
    if (!searchResponse.ok) throw await handleGoogleApiError(searchResponse, `Failed to search for folder '${name}'.`);
    const searchData = await searchResponse.json();
    if (searchData.files && searchData.files.length > 0) {
        return searchData.files[0].id;
    }

    // Create folder if not found
    const metadata: { name: string; mimeType: string; parents?: string[] } = {
        name,
        mimeType: 'application/vnd.google-apps.folder',
    };
    if (parentId) {
        metadata.parents = [parentId];
    }
    const createResponse = await fetch('https://www.googleapis.com/drive/v3/files', {
        method: 'POST',
        headers: { 'Authorization': `Bearer ${token}`, 'Content-Type': 'application/json' },
        body: JSON.stringify(metadata)
    });
    if (!createResponse.ok) throw await handleGoogleApiError(createResponse, `Failed to create folder '${name}'.`);
    const file = await createResponse.json();
    return file.id;
};

// Ensures the hierarchical folder structure exists: Records Root > Address > Case
// Returns the ID of the specific Case folder.
const ensureCaseFolderStructure = async (caseData: Case, subfolder?: string): Promise<string> => {
    // 1. Find/Create Root
    const rootId = await findOrCreateFolder(EVIDENCE_PHOTO_FOLDER_NAME);

    // 2. Find/Create Address Folder (sanitize address to prevent empty names)
    const addressName = caseData.address.street.trim() || 'Unlisted Address';
    const addressFolderId = await findOrCreateFolder(addressName, rootId);

    // 3. Find/Create Case Folder
    // Naming convention: "CaseID - ViolationType"
    const caseFolderName = `${caseData.caseId} - ${caseData.violation.type.replace(/\//g, '-')}`; 
    const caseFolderId = await findOrCreateFolder(caseFolderName, addressFolderId);

    if (subfolder) {
        return await findOrCreateFolder(subfolder, caseFolderId);
    }

    return caseFolderId;
};


// Finds the location of a placeholder text within a Google Doc's content structure
const findPlaceholderLocation = (docContent: any, placeholder: string): { startIndex: number; endIndex: number } | null => {
    const content = docContent?.body?.content;
    if (!content) return null;

    // First, get the full text of the document to easily find the placeholder.
    let fullText = '';
    content.forEach((element: any) => {
        if (element.paragraph) {
            element.paragraph.elements.forEach((pElement: any) => {
                if (pElement.textRun) {
                    fullText += pElement.textRun.content;
                }
            });
        }
    });

    const placeholderStartIndexInFullText = fullText.indexOf(placeholder);
    if (placeholderStartIndexInFullText === -1) {
        return null; // Placeholder not found at all.
    }
    const placeholderEndIndexInFullText = placeholderStartIndexInFullText + placeholder.length;

    // Now, map the string indices back to the document's structural indices.
    let docStartIndex = -1;
    let docEndIndex = -1;
    let currentIndex = 0;

    for (const element of content) {
        if (element.paragraph) {
            for (const pElement of element.paragraph.elements) {
                if (pElement.textRun && pElement.textRun.content) {
                    const runText = pElement.textRun.content;
                    const runStartIndex = currentIndex;
                    const runEndIndex = currentIndex + runText.length;

                    // Check if the placeholder starts within this run.
                    if (docStartIndex === -1 && placeholderStartIndexInFullText >= runStartIndex && placeholderStartIndexInFullText < runEndIndex) {
                        docStartIndex = pElement.startIndex + (placeholderStartIndexInFullText - runStartIndex);
                    }

                    // Check if the placeholder ends within this run.
                    if (docEndIndex === -1 && placeholderEndIndexInFullText > runStartIndex && placeholderEndIndexInFullText <= runEndIndex) {
                        docEndIndex = pElement.startIndex + (placeholderEndIndexInFullText - runStartIndex);
                    }

                    currentIndex = runEndIndex;

                    if (docStartIndex !== -1 && docEndIndex !== -1) {
                        return { startIndex: docStartIndex, endIndex: docEndIndex };
                    }
                }
            }
        }
    }

    return null;
};


// Sets a file's permission in Google Drive to be publicly readable by anyone with the link.
const makeFilePubliclyReadable = async (fileId: string): Promise<void> => {
    const token = await getAccessToken();
    const permission = {
        type: 'anyone',
        role: 'reader'
    };
    const response = await fetch(`https://www.googleapis.com/drive/v3/files/${fileId}/permissions?supportsAllDrives=true`, {
        method: 'POST',
        headers: { 'Authorization': `Bearer ${token}`, 'Content-Type': 'application/json' },
        body: JSON.stringify(permission)
    });

    if (!response.ok) {
        const clonedResponse = response.clone();
        try {
            const errorText = await clonedResponse.text();
             if (errorText.includes('permission already exists')) {
                return;
            }
        } catch {}
        throw await handleGoogleApiError(response, `Failed to make file ${fileId} public.`);
    }
};

export const generateCertificateOfMail = async (casesForMailing: Case[]): Promise<{ docUrl: string, title: string }[]> => {
    const token = await getAccessToken();
    const config = await getConfig();
    const templateUrl = config?.google?.certificateOfMailTemplateUrl;

    if (!templateUrl) throw new Error(`No Certificate of Mail template URL configured on the Templates tab.`);

    const templateId = getDocIdFromUrl(templateUrl);

    const fileMetaResponse = await fetch(`https://www.googleapis.com/drive/v3/files/${templateId}?fields=mimeType`, {
        headers: { 'Authorization': `Bearer ${token}` }
    });
    if (!fileMetaResponse.ok) throw await handleGoogleApiError(fileMetaResponse, `Could not fetch metadata for the Certificate of Mail template.`);
    const fileMeta = await fileMetaResponse.json();

    if (fileMeta.mimeType !== 'application/vnd.google-apps.document') {
        throw new Error(`Invalid Template Format: The Certificate of Mail template is not a Google Doc.`);
    }

    const today = new Date().toLocaleDateString('en-US', { year: 'numeric', month: 'long', day: 'numeric' });
    const todayFilename = new Date().toISOString().split('T')[0];

    const CHUNK_SIZE = 6;
    const chunks: Case[][] = [];
    for (let i = 0; i < casesForMailing.length; i += CHUNK_SIZE) {
        chunks.push(casesForMailing.slice(i, i + CHUNK_SIZE));
    }

    const generatedDocs: { docUrl: string, title: string }[] = [];

    for (let i = 0; i < chunks.length; i++) {
        const chunk = chunks[i];
        const pageNum = i + 1;
        const newDocName = `Certificate of Mail - ${todayFilename} - Page ${pageNum}`;

        const copyResponse = await fetch(`https://www.googleapis.com/drive/v3/files/${templateId}/copy?supportsAllDrives=true`, {
            method: 'POST',
            headers: { 'Authorization': `Bearer ${token}`, 'Content-Type': 'application/json' },
            body: JSON.stringify({ name: newDocName }),
        });
        if (!copyResponse.ok) throw await handleGoogleApiError(copyResponse, `Failed to copy certificate template for page ${pageNum}.`);
        const newFile = await copyResponse.json();
        const newDocId = newFile.id;

        const requests: any[] = [];

        requests.push({
            replaceAllText: {
                replaceText: today,
                containsText: { text: '{{DATE_TODAY}}', matchCase: false },
            },
        });

        for (let j = 1; j <= CHUNK_SIZE; j++) {
            const caseIndex = j - 1;
            const caseData = chunk[caseIndex];
            const namePlaceholder = `{{OWNER_NAME_${j}}}`;
            const addressPlaceholder = `{{MAILING_ADDRESS_${j}}}`;
            const caseIdPlaceholder = `{{CASE_ID_${j}}}`;

            requests.push({
                replaceAllText: {
                    replaceText: caseData?.ownerInfo?.name || '', 
                    containsText: { text: namePlaceholder, matchCase: false },
                }
            });
            requests.push({
                replaceAllText: {
                    replaceText: caseData?.ownerInfo?.mailingAddress || '',
                    containsText: { text: addressPlaceholder, matchCase: false },
                }
            });
            requests.push({
                replaceAllText: {
                    replaceText: caseData?.caseId || '',
                    containsText: { text: caseIdPlaceholder, matchCase: false },
                }
            });
        }

        const updateResponse = await fetch(`https://docs.googleapis.com/v1/documents/${newDocId}:batchUpdate`, {
            method: 'POST',
            headers: { 'Authorization': `Bearer ${token}`, 'Content-Type': 'application/json' },
            body: JSON.stringify({ requests: requests.reverse() }),
        });
        if (!updateResponse.ok) throw await handleGoogleApiError(updateResponse, `Failed to update new certificate document for page ${pageNum}.`);

        generatedDocs.push({ docUrl: `https://docs.google.com/document/d/${newDocId}/edit`, title: newDocName });
    }

    return generatedDocs;
};

export const generateEnvelopeDocument = async (caseData: Case): Promise<{ docUrl: string }> => {
    const token = await getAccessToken();
    const config = await getConfig();
    const templateUrl = config?.google?.envelopeTemplateUrl;

    if (!templateUrl) throw new Error(`No envelope template URL configured on the Templates tab.`);

    const templateId = getDocIdFromUrl(templateUrl);

    const fileMetaResponse = await fetch(`https://www.googleapis.com/drive/v3/files/${templateId}?fields=mimeType`, {
        headers: { 'Authorization': `Bearer ${token}` }
    });
    if (!fileMetaResponse.ok) throw await handleGoogleApiError(fileMetaResponse, `Could not fetch metadata for the envelope template.`);
    const fileMeta = await fileMetaResponse.json();

    if (fileMeta.mimeType !== 'application/vnd.google-apps.document') {
        throw new Error(`Invalid Template Format: The envelope template is not a Google Doc.`);
    }

    const templateResponse = await fetch(`https://docs.googleapis.com/v1/documents/${templateId}?fields=body`, {
        headers: { 'Authorization': `Bearer ${token}` }
    });
    if (!templateResponse.ok) throw await handleGoogleApiError(templateResponse, "Could not read template document.");
    const templateContent = await templateResponse.json();

    let addressPlaceholder: string | null = null;
    let addressLocation: { startIndex: number; endIndex: number } | null = null;

    const possiblePlaceholders = ['{{MAILING_ADDRESS}}', '{{OWNER_MAILING}}'];
    for (const p of possiblePlaceholders) {
        const location = findPlaceholderLocation(templateContent, p);
        if (location) {
            addressPlaceholder = p;
            addressLocation = location;
            break;
        }
    }

    const today = new Date().toISOString().split('T')[0];
    const newDocName = `Envelope - Case ${caseData.caseId} - ${today}`;
    const copyResponse = await fetch(`https://www.googleapis.com/drive/v3/files/${templateId}/copy?supportsAllDrives=true`, {
        method: 'POST',
        headers: { 'Authorization': `Bearer ${token}`, 'Content-Type': 'application/json' },
        body: JSON.stringify({ name: newDocName }),
    });
    if (!copyResponse.ok) throw await handleGoogleApiError(copyResponse, "Failed to copy envelope template.");
    const newFile = await copyResponse.json();
    const newDocId = newFile.id;

    const requests: any[] = [];
    const mailingAddress = caseData.ownerInfo.mailingAddress || '';

    if (addressLocation) {
        requests.push({ deleteContentRange: { range: addressLocation } });
        requests.push({
            insertText: {
                location: { index: addressLocation.startIndex },
                text: mailingAddress,
            }
        });
    }

    const textReplacements = {
        '{{OWNER_NAME}}': caseData.ownerInfo.name || 'N/A',
    };

    for (const [placeholder, value] of Object.entries(textReplacements)) {
        requests.push({
            replaceAllText: {
                replaceText: value,
                containsText: { text: placeholder, matchCase: false },
            },
        });
    }

    if (!addressLocation) {
        const flatAddress = mailingAddress.replace(/\n/g, ' ');
        requests.push({
            replaceAllText: {
                replaceText: flatAddress,
                containsText: { text: '{{MAILING_ADDRESS}}', matchCase: false },
            }
        });
        requests.push({
            replaceAllText: {
                replaceText: flatAddress,
                containsText: { text: '{{OWNER_MAILING}}', matchCase: false },
            }
        });
    }

    if (requests.length > 0) {
        const updateResponse = await fetch(`https://docs.googleapis.com/v1/documents/${newDocId}:batchUpdate`, {
            method: 'POST',
            headers: { 'Authorization': `Bearer ${token}`, 'Content-Type': 'application/json' },
            body: JSON.stringify({ requests }),
        });
        if (!updateResponse.ok) throw await handleGoogleApiError(updateResponse, "Failed to update new envelope document.");
    }

    const docUrl = `https://docs.google.com/document/d/${newDocId}/edit`;
    return { docUrl };
};

export const generateNoticeDocument = async (purpose: NoticePurpose, caseData: Case): Promise<{ docUrl: string, title: string }[]> => {
    const token = await getAccessToken();
    const config = await getConfig();
    const templateUrl = config?.google?.templateUrls?.[purpose];

    if (!templateUrl) throw new Error(`No template URL configured for "${purpose}" notices on the Templates tab.`);

    const templateId = getDocIdFromUrl(templateUrl);

    const fileMetaResponse = await fetch(`https://www.googleapis.com/drive/v3/files/${templateId}?fields=mimeType`, {
        headers: { 'Authorization': `Bearer ${token}` }
    });
    if (!fileMetaResponse.ok) throw await handleGoogleApiError(fileMetaResponse, `Could not fetch metadata for the ${purpose} notice template.`);
    const fileMeta = await fileMetaResponse.json();

    if (fileMeta.mimeType !== 'application/vnd.google-apps.document') {
        throw new Error(`Invalid Template Format: The template for "${purpose}" notices is not a Google Doc.`);
    }

    const templateResponse = await fetch(`https://docs.googleapis.com/v1/documents/${templateId}?fields=body`, {
        headers: { 'Authorization': `Bearer ${token}` }
    });
    if (!templateResponse.ok) throw await handleGoogleApiError(templateResponse, "Could not read template document.");
    const templateContent = await templateResponse.json();
    const photoBlockLocation = findPlaceholderLocation(templateContent, '{{PHOTO_EVIDENCE_BLOCK}}');
    const today = new Date().toISOString().split('T')[0];

    const createSingleNotice = async (
        targetName: string,
        targetMailingAddress: string,
        titleSuffix: string,
        includePhotos: boolean
    ): Promise<{ docUrl: string, title: string }> => {
        const newDocName = `Notice - Case ${caseData.caseId} - ${today} - ${titleSuffix}`;
        // Target the specific case folder if possible, otherwise default root
        let parentFolderId: string | undefined;
        try { parentFolderId = await ensureCaseFolderStructure(caseData, 'Notices'); } catch {}

        const copyPayload: any = { name: newDocName };
        if (parentFolderId) copyPayload.parents = [parentFolderId];

        const copyResponse = await fetch(`https://www.googleapis.com/drive/v3/files/${templateId}/copy?supportsAllDrives=true`, {
            method: 'POST',
            headers: { 'Authorization': `Bearer ${token}`, 'Content-Type': 'application/json' },
            body: JSON.stringify(copyPayload),
        });
        if (!copyResponse.ok) throw await handleGoogleApiError(copyResponse, `Failed to copy template document for ${titleSuffix}.`);
        const newFile = await copyResponse.json();
        const newDocId = newFile.id;

        const requests: any[] = [];
        let photoEvidenceLink = '';

        if (includePhotos && photoBlockLocation && caseData.evidence.photos && caseData.evidence.photos.length > 0) {
            photoEvidenceLink = 'Photographic evidence is embedded in this document.';
            try {
                await Promise.all(caseData.evidence.photos.map(p => makeFilePubliclyReadable(p.id)));
            } catch (e: any) {
                throw new Error(`Failed to set photo permissions in Google Drive: ${e.message}`);
            }

            requests.push({ deleteContentRange: { range: photoBlockLocation } });

            const photoDetails = await Promise.all(caseData.evidence.photos.map(p =>
                fetch(`https://www.googleapis.com/drive/v3/files/${p.id}?fields=id,imageMediaMetadata`, {
                    headers: { 'Authorization': `Bearer ${token}` }
                }).then(async res => {
                    if (!res.ok) throw await handleGoogleApiError(res, `Failed to fetch photo details for file ID ${p.id}.`);
                    return res.json();
                })
            ));

            const insertionRequests: any[] = [];
            for (let i = 0; i < photoDetails.length; i++) {
                const detail = photoDetails[i];
                if (!detail.imageMediaMetadata) continue;

                if (i > 0) {
                    const separator = (i % 3 === 0) ? '\n' : ' '; // Newline after every 3rd image
                    insertionRequests.push({ insertText: { location: { index: photoBlockLocation.startIndex }, text: separator } });
                }

                const { width, height } = detail.imageMediaMetadata;
                const targetWidth = 180; // Reduced size for more compact layout
                const scaledHeight = targetWidth * (height / width);
                insertionRequests.push({ insertInlineImage: { location: { index: photoBlockLocation.startIndex }, uri: `https://drive.google.com/uc?export=download&id=${detail.id}`, objectSize: { width: { magnitude: targetWidth, unit: 'PT' }, height: { magnitude: scaledHeight, unit: 'PT' } } } });
            }
            requests.push(...insertionRequests.reverse());
        } else if (caseData.evidence.photos && caseData.evidence.photos.length > 0) {
            try {
                // Get web link for the folder
                const caseFolderId = await ensureCaseFolderStructure(caseData);
                const folderDetailsResponse = await fetch(`https://www.googleapis.com/drive/v3/files/${caseFolderId}?fields=webViewLink`, {
                    headers: { 'Authorization': `Bearer ${token}` }
                });
                if (folderDetailsResponse.ok) photoEvidenceLink = (await folderDetailsResponse.json()).webViewLink;
            } catch (e: any) { console.error("Could not find/create evidence folder.", e); }
        }

        const baseReplacements = getNoticeReplacements(caseData, photoEvidenceLink);
        const finalReplacements = { ...baseReplacements, '{{OWNER_NAME}}': targetName, '{{OWNER_MAILING}}': targetMailingAddress };
        Object.entries(finalReplacements).forEach(([placeholder, value]) => {
            requests.push({ replaceAllText: { replaceText: value, containsText: { text: placeholder, matchCase: false } } });
        });

        if (requests.length > 0) {
            const updateResponse = await fetch(`https://docs.googleapis.com/v1/documents/${newDocId}:batchUpdate`, {
                method: 'POST',
                headers: { 'Authorization': `Bearer ${token}`, 'Content-Type': 'application/json' },
                body: JSON.stringify({ requests }),
            });
            if (!updateResponse.ok) throw await handleGoogleApiError(updateResponse, `Failed to update new document for ${titleSuffix}.`);
        }
        return { docUrl: `https://docs.google.com/document/d/${newDocId}/edit`, title: newDocName };
    };

    const generatedDocs: { docUrl: string, title: string }[] = [];

    // 1. Generate Owner Notice
    generatedDocs.push(await createSingleNotice(caseData.ownerInfo.name || 'Property Owner', caseData.ownerInfo.mailingAddress || 'N/A', 'Owner', true));

    // 2. Generate Occupant Notice if addresses differ
    const ownerMailing = (caseData.ownerInfo.mailingAddress || '').trim().toLowerCase();
    const propertyAddress = (caseData.address.street || '').trim().toLowerCase();
    if (ownerMailing && propertyAddress && !ownerMailing.includes(propertyAddress)) {
        generatedDocs.push(await createSingleNotice('Occupant', caseData.address.street, 'Occupant', true));
    }

    return generatedDocs;
};

const getSheetData = async (): Promise<{ cases: Case[] }> => {
    const token = await getAccessToken();
    const config = await getConfig();
    const fileId = config?.google?.fileId;
    if (!fileId) throw new Error("Google Sheet File ID not configured.");

    const metaResponse = await fetch(`https://sheets.googleapis.com/v4/spreadsheets/${fileId}/values/A1`, {
        headers: { 'Authorization': `Bearer ${token}` }
    });

    if (metaResponse.status === 404) {
        return { cases: [] };
    }
    if (!metaResponse.ok) throw await handleGoogleApiError(metaResponse, "Failed to read metadata from Google Sheet.");

    const metaData = await metaResponse.json();
    const metaCell = metaData.values?.[0]?.[0];

    if (!metaCell) {
        return { cases: [] };
    }

    let chunkCount = 0;
    try {
        const metadata = JSON.parse(metaCell);
        chunkCount = metadata?.chunkCount || 0;
    } catch (e) {
        const fullRowResponse = await fetch(`https://sheets.googleapis.com/v4/spreadsheets/${fileId}/values/1:1`, {
            headers: { 'Authorization': `Bearer ${token}` }
        });
        if (!fullRowResponse.ok) throw await handleGoogleApiError(fullRowResponse, "Failed to read full row for old data format.");
        const fullRowData = await fullRowResponse.json();
        const row = fullRowData.values?.[0];
        if (row && row.length > 0) {
            const joinedContent = row.join('');
            try {
                const { cases } = JSON.parse(joinedContent);
                return { cases: cases || [] };
            } catch (parseError) {
                 throw new Error( "Failed to parse data from Google Sheet. The data is likely corrupt.");
            }
        }
        return { cases: [] };
    }

    if (chunkCount === 0) {
        return { cases: [] };
    }

    const endCol = toColumnName(chunkCount + 1); 
    const dataRange = `B1:${endCol}1`;
    const dataResponse = await fetch(`https://sheets.googleapis.com/v4/spreadsheets/${fileId}/values/${dataRange}`, {
        headers: { 'Authorization': `Bearer ${token}` }
    });
    if (!dataResponse.ok) throw await handleGoogleApiError(dataResponse, `Failed to read data chunks from range ${dataRange}.`);

    const dataSheet = await dataResponse.json();
    const row = dataSheet.values?.[0];

    if (row && row.length > 0) {
        const jsonString = row.join('');
        try {
            const { cases } = JSON.parse(jsonString);
            return { cases: cases || [] };
        } catch (e) {
            throw new Error("Failed to parse data from Google Sheet. The data is likely corrupt.");
        }
    }

    return { cases: [] };
};

const writeSheetData = async (data: { cases: Case[] }) => {
    const token = await getAccessToken();
    const config = await getConfig();
    const fileId = config?.google?.fileId;
    if (!fileId) throw new Error("Google Sheet File ID not configured.");

    const jsonString = JSON.stringify(data);

    const CHUNK_SIZE = 49000;
    const dataChunks: string[] = [];
    for (let i = 0; i < jsonString.length; i += CHUNK_SIZE) {
        dataChunks.push(jsonString.substring(i, i + CHUNK_SIZE));
    }
    const newChunkCount = dataChunks.length;

    const metadata = { chunkCount: newChunkCount };
    const values = [[JSON.stringify(metadata), ...dataChunks]];

    const body = { values };
    const writeResponse = await fetch(`https://sheets.googleapis.com/v4/spreadsheets/${fileId}/values/A1?valueInputOption=RAW`, {
        method: 'PUT',
        headers: { 'Authorization': `Bearer ${token}`, 'Content-Type': 'application/json' },
        body: JSON.stringify(body)
    });

    if (!writeResponse.ok) {
        throw await handleGoogleApiError(writeResponse, "Failed to write to Google Sheet.");
    }

    const startClearColIndex = newChunkCount + 2;
    const startClearColName = toColumnName(startClearColIndex);
    const clearRange = `${startClearColName}1:1`;

    await fetch(`https://sheets.googleapis.com/v4/spreadsheets/${fileId}/values/${clearRange}:clear`, {
        method: 'POST',
        headers: { 'Authorization': `Bearer ${token}`, 'Content-Type': 'application/json' },
        body: JSON.stringify({})
    });
};

export const uploadCasePhotos = async (photos: PhotoWithMeta[], caseData: Case): Promise<EvidencePhoto[]> => {
    if (photos.length === 0) return [];
    const token = await getAccessToken();

    // FIX: Acceptance of full Case object to avoid race conditions with un-synced data.
    // Hierarchical folder structure: Root > Address > Case
    const caseFolderId = await ensureCaseFolderStructure(caseData, 'Photos');

    const uploadPromises = photos.map(async (photo) => {
        const metadata = {
            name: photo.file.name,
            parents: [caseFolderId]
        };
        const form = new FormData();
        form.append('metadata', new Blob([JSON.stringify(metadata)], { type: 'application/json' }));
        form.append('file', photo.file);

        const response = await fetch('https://www.googleapis.com/upload/drive/v3/files?uploadType=multipart&fields=id,webViewLink,thumbnailLink', {
            method: 'POST',
            headers: { 'Authorization': `Bearer ${token}` },
            body: form
        });
        if (!response.ok) {
            throw await handleGoogleApiError(response, `Failed to upload photo ${photo.file.name}.`);
        }
        const fileData = await response.json();
        return {
            id: fileData.id,
            url: fileData.thumbnailLink, 
            webViewLink: fileData.webViewLink,
        };
    });

    return Promise.all(uploadPromises);
};

export const uploadAbatementPhotos = async (photos: PhotoWithMeta[], caseId: string, type: 'before' | 'after'): Promise<EvidencePhoto[]> => {
    if (photos.length === 0) return [];
    const token = await getAccessToken();

    const { cases } = await getSheetData();
    const caseData = cases.find(c => c.caseId === caseId);
    if (!caseData) throw new Error(`Cannot upload photos: Case ${caseId} not found.`);

    // Create folder hierarchy
    const caseFolderId = await ensureCaseFolderStructure(caseData);
    const subfolderId = await findOrCreateFolder(`Abatement - ${type}`, caseFolderId);

    const uploadPromises = photos.map(async (photo) => {
        const metadata = {
            name: photo.file.name,
            parents: [subfolderId]
        };
        const form = new FormData();
        form.append('metadata', new Blob([JSON.stringify(metadata)], { type: 'application/json' }));
        form.append('file', photo.file);

        const response = await fetch('https://www.googleapis.com/upload/drive/v3/files?uploadType=multipart&fields=id,webViewLink,thumbnailLink', {
            method: 'POST',
            headers: { 'Authorization': `Bearer ${token}` },
            body: form
        });
        if (!response.ok) throw await handleGoogleApiError(response, `Failed to upload abatement photo ${photo.file.name}.`);
        const fileData = await response.json();
        return {
            id: fileData.id,
            url: fileData.thumbnailLink,
            webViewLink: fileData.webViewLink,
        };
    });
    return Promise.all(uploadPromises);
};


const generateAbatementDocument = async (
    caseData: Case, 
    templateUrl: string | undefined, 
    docType: string, 
    titlePrefix: string,
    getReplacements: (caseData: Case) => { [key:string]: string}
): Promise<{ docUrl: string, title: string }> => {
    if (!templateUrl) throw new Error(`No template URL configured for "${docType}" on the Templates tab.`);

    const token = await getAccessToken();
    const templateId = getDocIdFromUrl(templateUrl);

    const fileMetaResponse = await fetch(`https://www.googleapis.com/drive/v3/files/${templateId}?fields=mimeType`, {
        headers: { 'Authorization': `Bearer ${token}` }
    });
    if (!fileMetaResponse.ok) throw await handleGoogleApiError(fileMetaResponse, `Could not fetch metadata for template document.`);
    const fileMeta = await fileMetaResponse.json();

    if (fileMeta.mimeType !== 'application/vnd.google-apps.document') {
        throw new Error(`Invalid Template Format: The template for "${docType}" is not a Google Doc.`);
    }

    const today = new Date().toISOString().split('T')[0];
    const newDocName = `${titlePrefix} - Case ${caseData.caseId} - ${today}`;

    const copyResponse = await fetch(`https://www.googleapis.com/drive/v3/files/${templateId}/copy?supportsAllDrives=true`, {
        method: 'POST',
        headers: { 'Authorization': `Bearer ${token}`, 'Content-Type': 'application/json' },
        body: JSON.stringify({ name: newDocName }),
    });
    if (!copyResponse.ok) throw await handleGoogleApiError(copyResponse, `Failed to copy ${docType} template.`);
    const newFile = await copyResponse.json();
    const newDocId = newFile.id;

    const baseReplacements = getNoticeReplacements(caseData); 
    const specificReplacements = getReplacements(caseData);
    const allReplacements = { ...baseReplacements, ...specificReplacements };

    const requests = Object.entries(allReplacements).map(([placeholder, value]) => ({
        replaceAllText: {
            replaceText: value,
            containsText: { text: placeholder, matchCase: false },
        },
    }));

    if (requests.length > 0) {
        const updateResponse = await fetch(`https://docs.googleapis.com/v1/documents/${newDocId}:batchUpdate`, {
            method: 'POST',
            headers: { 'Authorization': `Bearer ${token}`, 'Content-Type': 'application/json' },
            body: JSON.stringify({ requests }),
        });
        if (!updateResponse.ok) throw await handleGoogleApiError(updateResponse, `Failed to update new ${docType} document.`);
    }

    return { docUrl: `https://docs.google.com/document/d/${newDocId}/edit`, title: newDocName };
};


