    </html>
    `;
    zipFolder.file("Case_Report.html", reportHtml);

    // 2. Photos
    const photoFolder = zipFolder.folder("Evidence Photos");
    const allPhotos = [...(caseData.evidence.photos || [])];
    if (caseData.abatement?.photos?.before) allPhotos.push(...caseData.abatement.photos.before);
    if (caseData.abatement?.photos?.after) allPhotos.push(...caseData.abatement.photos.after);

    const photoPromises = allPhotos.map(async (photo, i) => {
        try {
            const blob = await fetchBlobFromDrive(photo.id);
            const ext = blob.type.split('/')[1] || 'jpg';
            photoFolder?.file(`Photo_${i+1}.${ext}`, blob);
        } catch (e) {
            console.warn(`Failed to download photo ${photo.id}`, e);
            photoFolder?.file(`Photo_${i+1}_FAILED.txt`, "Could not download");
        }
    });

    // 3. Generated Documents
    const docFolder = zipFolder.folder("Documents");
    const docPromises = [];

    caseData.notices.forEach((n, i) => {
        docPromises.push(async () => {
            try {
                const docId = getDocIdFromUrl(n.docUrl);
                const blob = await fetchDocAsPdf(docId);
                docFolder?.file(`${n.title}.pdf`, blob);
            } catch (e) {
                console.warn(`Failed to download notice ${n.title}`, e);
            }
        });
    });

    if (caseData.abatement?.statementOfCostDocUrl) {
        docPromises.push(async () => {
             try {
                const docId = getDocIdFromUrl(caseData.abatement!.statementOfCostDocUrl!);
                const blob = await fetchDocAsPdf(docId);
                docFolder?.file(`Statement_of_Cost.pdf`, blob);
            } catch(e) { console.warn(e); }
        });
    }
    if (caseData.abatement?.noticeOfLienDocUrl) {
        docPromises.push(async () => {
             try {
                const docId = getDocIdFromUrl(caseData.abatement!.noticeOfLienDocUrl!);
                const blob = await fetchDocAsPdf(docId);
                docFolder?.file(`Notice_of_Lien.pdf`, blob);
            } catch(e) { console.warn(e); }
        });
    }

    await Promise.all([...photoPromises, ...docPromises.map(fn => fn())]);
};

export const downloadCaseArchive = async (caseData: Case) => {
    const zip = new JSZip();
    // For single case download, put everything in the root of the zip
    await addCaseToZip(zip, caseData); 
    const content = await zip.generateAsync({ type: "blob" });
    const filename = `${caseData.address.street.replace(/[^a-z0-9]/gi, '_')}__${caseData.caseId}.zip`;
    saveAs(content, filename);
};

export const downloadPropertyArchive = async (property: Property, cases: Case[]) => {
    const zip = new JSZip();
    const safeAddr = property.streetAddress.replace(/[^a-z0-9 ]/gi, '_');

    // Folder structure: ZipRoot -> CaseID -> Content
    for (const c of cases) {
        const caseFolder = zip.folder(`${c.caseId} - ${c.violation.type.replace(/[^a-z0-9]/gi, '_')}`);
        if (caseFolder) {
            await addCaseToZip(caseFolder, c);
        }
    }

    const content = await zip.generateAsync({ type: "blob" });
    const filename = `Property_Records_${safeAddr}.zip`;
    saveAs(content, filename);
};

export const downloadFullArchive = async (properties: Property[], cases: Case[], onProgress: (msg: string) => void) => {
    const zip = new JSZip();
    let count = 0;
    const total = properties.length;

    for (const prop of properties) {
        count++;
        onProgress(`Processing ${prop.streetAddress} (${count}/${total})...`);

        const propCases = cases.filter(c => c.address.street.toLowerCase() === prop.streetAddress.toLowerCase());
        if (propCases.length === 0) continue;

        const safeAddr = prop.streetAddress.replace(/[^a-z0-9 ]/gi, '_');
        // Folder structure: ZipRoot -> Address -> CaseID -> Content
        const propFolder = zip.folder(safeAddr);

        if (propFolder) {
             for (const c of propCases) {
                const caseFolder = propFolder.folder(`${c.caseId} - ${c.violation.type.replace(/[^a-z0-9]/gi, '_')}`);
                if (caseFolder) {
                    await addCaseToZip(caseFolder, c);
                }
            }
        }
    }

    onProgress("Compressing archive... (this may take a moment)");
    const content = await zip.generateAsync({ type: "blob" });
    const filename = `Full_Code_Enforcement_Archive_${new Date().toISOString().split('T')[0]}.zip`;
    saveAs(content, filename);
};


export const dataService = {
    getAllData: async (): Promise<{ cases: Case[] }> => getSheetData(),
    getAllCases: async (): Promise<Case[]> => (await getSheetData()).cases,
    getCaseById: async (id: string): Promise<Case | undefined> => (await getSheetData()).cases.find(c => c.id === id),
    saveCase: async (caseData: Case): Promise<Case> => {
        const data = await getSheetData();
        const index = data.cases.findIndex(c => c.id === caseData.id);
        if (index > -1) {
            data.cases[index] = caseData;
        } else {
            data.cases.push(caseData);
        }
        await writeSheetData(data);
        return caseData;
    },
    deleteCase: async (caseId: string): Promise<void> => {
        const data = await getSheetData();
        const initialLength = data.cases.length;
        data.cases = data.cases.filter(c => c.id !== caseId);
        if (data.cases.length === initialLength) {
            console.warn(`Case with ID ${caseId} not found for deletion.`);
        }
        await writeSheetData(data);
    },
    uploadCasePhotos,
    uploadAbatementPhotos,
    downloadCaseArchive,
    downloadPropertyArchive,
    downloadFullArchive
};

import React, { useState, useMemo } from 'react';
import { Property, Case } from '../types';
import { compareStreets } from '../utils';
import { dataService } from '../googleSheetsService';

const PropertyDirectory: React.FC<{
    cases: Case[];
    properties: Property[];
    onSelectCase: (caseId: string) => void;
}> = ({ cases, properties, onSelectCase }) => {
    const [searchTerm, setSearchTerm] = useState('');
    const [isArchiving, setIsArchiving] = useState(false);
    const [archiveProgress, setArchiveProgress] = useState('');

    const filteredProperties = useMemo(() => {
        const sorted = [...properties].sort((a, b) => compareStreets(a.streetAddress, b.streetAddress));
        if (!searchTerm) return sorted;
        const lowerSearch = searchTerm.toLowerCase();
        return sorted.filter(p =>
            p.streetAddress.toLowerCase().includes(lowerSearch) ||
            p.ownerInfo.name?.toLowerCase().includes(lowerSearch)
        );
    }, [properties, searchTerm]);

    const handleDownloadFullArchive = async () => {
        if (!window.confirm("Download Full Archive? This will gather photos and documents for ALL properties and may take several minutes. Please do not close the tab.")) return;
        setIsArchiving(true);
        setArchiveProgress('Starting archive...');
        try {
            await dataService.downloadFullArchive(filteredProperties, cases, (msg) => setArchiveProgress(msg));
            setArchiveProgress('Download started.');
        } catch (e: any) {
            alert(`Archive failed: ${e.message}`);
            setArchiveProgress('');
        } finally {
            setIsArchiving(false);
        }
    };

    const handleDownloadPropertyArchive = async (prop: Property, linkedCases: Case[]) => {
        if (!window.confirm(`Download all records for ${prop.streetAddress}?`)) return;
        setIsArchiving(true);
        setArchiveProgress(`Archiving ${prop.streetAddress}...`);
        try {
            await dataService.downloadPropertyArchive(prop, linkedCases);
            setArchiveProgress('');
        } catch (e: any) {
            alert(`Archive failed: ${e.message}`);
        } finally {
            setIsArchiving(false);
        }
    };

    return (
        <div className="tab-content">
            <div className="card" style={{backgroundColor: '#f0f7ff', borderColor: 'var(--secondary-color)'}}>
                <div style={{display: 'flex', flexDirection: 'column', gap: '0.5rem'}}>
                    <h3 style={{margin: 0}}>Data & Archives</h3>
                    <p className="helper-text">Download a complete backup of all case files, organized by address folders.</p>
                    <button 
                        className="button primary-action full-width" 
                        onClick={handleDownloadFullArchive}
                        disabled={isArchiving}
                    >
                        {isArchiving ? <span className="loader" /> : 'Download Full Database Archive (ZIP)'}
                    </button>
                    {archiveProgress && <div className="status-message ok" style={{marginTop: '0.5rem'}}>{archiveProgress}</div>}
                </div>
            </div>

            <div className="search-bar">
                <svg className="search-icon" xmlns="http://www.w3.org/2000/svg" width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><circle cx="11" cy="11" r="8"></circle><line x1="21" y1="21" x2="16.65" y2="16.65"></line></svg>
                <input type="text" placeholder="Search by address or owner..." value={searchTerm} onChange={e => setSearchTerm(e.target.value)} />
            </div>

            {filteredProperties.length > 0 ? (
                filteredProperties.map(prop => {
                    const linkedCases = cases.filter(c => c.address.street.toLowerCase() === prop.streetAddress.toLowerCase());
                    return (
                        <div key={prop.id} className="card" style={{marginTop: '1.5rem'}}>
                            <div style={{display: 'flex', justifyContent: 'space-between', alignItems: 'center'}}>
                                <div>
                                    <h3 style={{marginTop: 0, marginBottom: '0.25rem'}}>{prop.streetAddress}</h3>
                                    <span style={{color: 'var(--dark-gray)'}}>Owner: {prop.ownerInfo.name || 'N/A'}</span>
                                </div>
                            </div>
                            <div className="note" style={{marginTop: '1rem'}}>
                                <p><strong>Mailing Address:</strong> {prop.ownerInfo.mailingAddress || 'N/A'}</p>
                            </div>

                            <div style={{marginTop: '1rem', display: 'flex', justifyContent: 'space-between', alignItems: 'center', flexWrap: 'wrap', gap: '1rem'}}>
                                <button 
                                    className="button secondary-action" 
                                    style={{fontSize: '0.85rem', padding: '0.5rem 1rem'}}
                                    onClick={() => handleDownloadPropertyArchive(prop, linkedCases)}
                                    disabled={isArchiving}
                                >
                                    Download Records (ZIP)
                                </button>
                            </div>

                            {linkedCases.length > 0 && (
                                <>
                                    <h4 style={{marginTop: '1.5rem'}}>Linked Cases ({linkedCases.length})</h4>
                                    {linkedCases.map(c => (
                                        <div key={c.id} className="report-case-item" onClick={() => onSelectCase(c.id)} style={{cursor: 'pointer'}}>
                                            <div className="info"><strong>{c.caseId}:</strong> {c.violation.type}</div>
                                            <div className="details">
                                                <span><strong>Created:</strong> {c.dateCreated}</span>
                                                <span><strong>Status:</strong> {c.status}</span>
                                            </div>
                                        </div>
                                    ))}
                                </>
                            )}
                        </div>
                    );
                })
            ) : (
                <div className="card empty-state" style={{marginTop: '1.5rem'}}>
                    <p>{searchTerm ? 'No properties match your search.' : 'No properties found.'}</p>
                </div>
            )}
        </div>
    );
};

