const COMPLAINT_LOG_KEY = 'complaint-logs-v1';

type AppStatus = 'LOADING' | 'NEEDS_CONFIG' | 'READY';

const App: React.FC = () => {
    const [appStatus, setAppStatus] = useState<AppStatus>('LOADING');
    const [view, setView] = useState<View>('TASKS');
    const [activeTab, setActiveTab] = useState('tasks');

    const [cases, setCases] = useState<Case[]>([]);
    const [properties, setProperties] = useState<Property[]>([]);
    const [complaintLogs, setComplaintLogs] = useState<ComplaintLogEntry[]>([]);
    const [selectedCaseId, setSelectedCaseId] = useState<string | null>(null);
    const [isLoading, setIsLoading] = useState(true);
    const [error, setError] = useState<string | null>(null);
    const isInitialCheck = useRef(true);
    const [showAbatementReport, setShowAbatementReport] = useState(false);

    const [draftCase, setDraftCase] = useState<(Partial<Case> & { _tempPhotos?: PhotoWithMeta[] }) | null>(null);
    const [pendingPatrolCases, setPendingPatrolCases] = useState<{id: string, photos: PhotoWithMeta[]}[]>(loadPendingPatrolCases());

    useEffect(() => {
        checkAndRotatePatrol();
    }, []);

    useEffect(() => {
        savePendingPatrolCases(pendingPatrolCases);
    }, [pendingPatrolCases]);

    useEffect(() => {
        try {
            const storedLogsReal = localStorage.getItem(COMPLAINT_LOG_KEY);
            if (storedLogsReal) {
                setComplaintLogs(JSON.parse(storedLogsReal));
            }
        } catch (error) {
            console.error("Failed to load complaint logs from local storage:", error);
        }
    }, []);

    const handleUpdateLogs = (updatedLogs: ComplaintLogEntry[]) => {
        setComplaintLogs(updatedLogs);
        try {
            localStorage.setItem(COMPLAINT_LOG_KEY, JSON.stringify(updatedLogs));
        } catch (error) {
            console.error("Failed to save complaint logs to local storage:", error);
        }
    };


    const checkConfiguration = useCallback(async () => {
        setAppStatus('LOADING');
        try {
            const config = await getConfig(isInitialCheck.current);
            isInitialCheck.current = false;

            if (config?.google?.clientId && config.google.fileId) {
                setAppStatus('READY');
                if (view === 'ADMIN') {
                    setView('TASKS');
                    setActiveTab('tasks');
                }
            } else {
                setAppStatus('NEEDS_CONFIG');
                setView('ADMIN');
                setActiveTab('admin');
            }
        } catch (err: any) {
            setError(`Failed to load configuration: ${err.message}`);
            setAppStatus('NEEDS_CONFIG');
        }
    }, [view]);

    useEffect(() => {
        checkConfiguration();
    }, [checkConfiguration]);


    const loadData = useCallback(() => {
        if (appStatus === 'READY') {
            setIsLoading(true);
            setError(null);

            const baseProperties = getTaxRollProperties();

            dataService.getAllData()
                .then(({ cases, properties: savedProperties }) => {
                    // Merge tax roll data with user-saved data
                    const mergedProperties: Property[] = [];
                    const savedPropertiesMap = new Map<string, Property>();

                    (savedProperties || []).forEach(p => {
                        savedPropertiesMap.set(p.streetAddress.toLowerCase(), p);
                    });

                    baseProperties.forEach(baseProp => {
                        const savedProp = savedPropertiesMap.get(baseProp.streetAddress.toLowerCase());
                        if (savedProp) {
                            mergedProperties.push(savedProp);
                            savedPropertiesMap.delete(baseProp.streetAddress.toLowerCase());
                        } else {
                            mergedProperties.push(baseProp);
                        }
                    });

                    mergedProperties.push(...Array.from(savedPropertiesMap.values()));

                    setProperties(mergedProperties);
                    setCases(cases);
                })
                .catch(err => setError(`Failed to load data: ${err.message}`))
                .finally(() => setIsLoading(false));
        } else {
            setIsLoading(false);
        }
    }, [appStatus]);


    useEffect(() => { loadData(); }, [loadData]);

    const handleSetupComplete = () => {
        checkConfiguration();
    };

    const handleSelectCase = (caseId: string) => { setSelectedCaseId(caseId); setView('DETAILS'); };

    // Helper to generate the auto-incrementing Case Number: MM-NNN-YY
    const generateNextCaseId = () => {
        const now = new Date();
        const mm = String(now.getMonth() + 1).padStart(2, '0');
        const yy = String(now.getFullYear()).slice(-2);

        const monthPrefix = `${mm}-`;
        const yearSuffix = `-${yy}`;

        const monthCases = cases.filter(c => 
            c.caseId.startsWith(monthPrefix) && c.caseId.endsWith(yearSuffix)
        );

        let nextNum = 1;
        if (monthCases.length > 0) {
            const nums = monthCases.map(c => {
                const parts = c.caseId.split('-');
                return parts.length === 3 ? parseInt(parts[1], 10) : 0;
            }).filter(n => !isNaN(n));

            if (nums.length > 0) {
                nextNum = Math.max(...nums) + 1;
            }
        }

        const nnn = String(nextNum).padStart(3, '0');
        return `${mm}-${nnn}-${yy}`;
    };

    const handleNewCase = () => {
        if (!draftCase) {
             setDraftCase({
                id: `draft-${Date.now()}`,
                caseId: generateNextCaseId(), // Automatically set the next ID
                address: initialAddressState,
                ownerInfo: initialOwnerState,
                violation: initialViolationState,
                ownerInfoStatus: 'KNOWN',
                isVacant: false,
                _tempPhotos: []
            });
        }
        setView('NEW');
        setActiveTab('new');
    };

    const handleCancelNew = () => {
        if (draftCase && (draftCase._tempPhotos?.length || 0) > 0) {
            if (!window.confirm("Are you sure you want to cancel? Any photos you've taken will be lost.")) {
                return;
            }
        }
        setDraftCase(null);
        setView('TASKS');
        setActiveTab('tasks');
    };

    const handleCreateCaseFromPatrol = (patrolCase: {id: string, photos: PhotoWithMeta[]}) => {
        setDraftCase({
            id: `draft-${Date.now()}`,
            caseId: generateNextCaseId(),
            address: initialAddressState,
            ownerInfo: initialOwnerState,
            violation: initialViolationState,
            ownerInfoStatus: 'KNOWN',
            isVacant: false,
            _tempPhotos: patrolCase.photos,
        });
        setPendingPatrolCases(prev => prev.filter(p => p.id !== patrolCase.id));
        setView('NEW');
        setActiveTab('new');
    };

    const handleBackToList = () => { setSelectedCaseId(null); setView('TASKS'); setActiveTab('tasks'); };

    const handleSaveCase = (draftToSave: (Partial<Case> & { _tempPhotos?: PhotoWithMeta[] })) => {
        const today = new Date(), deadline = new Date();
        deadline.setDate(today.getDate() + COMPLIANCE_DAYS);
        const formatDate = (d: Date) => d.toLocaleString('en-US', { year: 'numeric', month: 'long', day: 'numeric' });

        const finalViolation = draftToSave.violation?.type === 'Other (Manual Entry)'
            ? draftToSave.violation
            : VIOLATIONS_LIST.find(v => v.type === draftToSave.violation?.type) || initialViolationState;

        const tempCase: Case = {
            id: draftToSave.id || self.crypto.randomUUID(), 
            caseId: (draftToSave.caseId || '').trim(), 
            status: 'ACTIVE',
            dateCreated: formatDate(today), 
            complianceDeadline: formatDate(deadline),
            address: draftToSave.address || initialAddressState, 
            ownerInfo: draftToSave.ownerInfo || initialOwnerState,
            ownerInfoStatus: draftToSave.ownerInfoStatus || 'KNOWN',
            violation: finalViolation, 
            isVacant: draftToSave.isVacant || false,
            evidence: { notes: [{ date: formatDate(today), text: "Case created." }], photos: [] },
            notices: [],
        };

        setCases(prev => [tempCase, ...prev]);
        setDraftCase(null);
        setError(null);

        setSelectedCaseId(tempCase.id);
        setView('DETAILS');
        setActiveTab('all');

        (async () => {
            try {
                const uploadedPhotos: EvidencePhoto[] = await dataService.uploadCasePhotos(draftToSave._tempPhotos || [], tempCase);
                const finalCase = { ...tempCase, evidence: { ...tempCase.evidence, photos: uploadedPhotos } };

                await dataService.saveCase(finalCase, properties);

                const allData = await dataService.getAllData();
                setCases(allData.cases);

            } catch (e: any) {
                console.error("Background save failed:", e);
                setError(`CRITICAL ERROR: Failed to save case "${tempCase.caseId}". Error: ${e.message}. Please check your connection and try again.`);
                setCases(prev => prev.filter(c => c.id !== tempCase.id));
                setDraftCase(draftToSave);
                setSelectedCaseId(null);
                setView('NEW');
                setActiveTab('new');
                window.scrollTo({ top: 0, behavior: 'smooth' });
            }
        })();
    };

    const handleUpdateCase = async (caseData: Case) => {
        setIsLoading(true);
        setError(null);
        try {
            await dataService.saveCase(caseData, properties);
            const allData = await dataService.getAllData();
            setCases(allData.cases);
        } catch (e: any) {
            setError(`Failed to save case: ${e.message}`);
        } finally {
            setIsLoading(false);
        }
    };

    const handleDeleteCase = async (caseId: string) => {
        setIsLoading(true);
        setError(null);
        try {
            await dataService.deleteCase(caseId, properties);
            const allData = await dataService.getAllData();
            setCases(allData.cases);
            setView('TASKS');
            setActiveTab('tasks');
            setSelectedCaseId(null);
        } catch (e: any) {
            setError(`Failed to delete case: ${e.message}`);
        } finally {
            setIsLoading(false);
        }
    };

    const handleSaveProperty = async (propData: Property) => {
        setIsLoading(true);
        setError(null);
        try {
            await dataService.saveProperty(propData, cases);
            loadData();
        } catch (e: any) {
            setError(`Failed to save property: ${e.message}`);
        } finally {
            setIsLoading(false);
        }
    };

    const handleDeleteProperty = async (propId: string) => {
        setIsLoading(true);
        setError(null);
        try {
            await dataService.deleteProperty(propId, cases);
            loadData();
        } catch (e: any) {
            setError(`Failed to delete property: ${e.message}`);
        } finally {
            setIsLoading(false);
        }
    };

    const changeTab = (tab: string, targetView: View) => {
        setActiveTab(tab);
        setView(targetView);
        setSelectedCaseId(null);
        if (tab !== 'abatement') {
            setShowAbatementReport(false);
        }
    };

    const selectedCase = cases.find(c => c.id === selectedCaseId);

    const abatementCases = cases.filter(c => c.status === 'PENDING_ABATEMENT');
    const continualAbatementCases = cases.filter(c => c.status === 'CONTINUAL_ABATEMENT');
    const dueCases = cases.filter(c => getCaseTimeStatus(c) === 'overdue' && c.status !== 'CLOSED' && c.status !== 'PENDING_ABATEMENT');

    const renderContent = () => {
        if (appStatus === 'LOADING') {
            return <div className="card" style={{textAlign: 'center', padding: '2rem'}}><div className="loader" style={{margin: 'auto', borderTopColor: 'var(--primary-color)', borderLeftColor: 'var(--primary-color)'}}></div><p style={{marginTop: '1rem', color: 'var(--text-secondary)'}}>Loading...</p></div>;
        }
        if (appStatus === 'NEEDS_CONFIG') return <AdminView onSetupComplete={handleSetupComplete} />;
        if (error) return <div className="error-message">{error}<p style={{ marginTop: '0.5rem', fontSize: '0.9rem' }}>Check your internet connection or Google project configuration.</p></div>;
        if (isLoading && (view === 'LIST' || view === 'TASKS' || view === 'PROPERTIES')) return <div className="card" style={{textAlign: 'center', padding: '2rem'}}><div className="loader" style={{margin: 'auto', borderTopColor: 'var(--primary-color)', borderLeftColor: 'var(--primary-color)'}}></div><p style={{marginTop: '1rem', color: 'var(--text-secondary)'}}>Updating...</p></div>;

        switch (view) {
            case 'TASKS': return <DailyTasks cases={cases} onSelectCase={handleSelectCase} />;
            case 'DETAILS': return selectedCase ? <CaseDetails caseData={selectedCase} onBack={handleBackToList} onUpdate={handleUpdateCase} onDelete={handleDeleteCase} /> : <p>Case not found.</p>;
            case 'NEW': return <NewCaseForm onSave={handleSaveCase} onCancel={handleCancelNew} properties={properties} draftCase={draftCase} onUpdateDraft={setDraftCase} />;
            case 'ADMIN': return <AdminView onSetupComplete={handleSetupComplete} />;
            case 'TEMPLATES': return <TemplateManager />;
            case 'LOG': return <ComplaintLog logs={complaintLogs} onUpdateLogs={handleUpdateLogs} />;
            case 'PROPERTIES': return <PropertyDirectory cases={cases} properties={properties} onSelectCase={handleSelectCase} onSaveProperty={handleSaveProperty} onDeleteProperty={handleDeleteProperty} />;
            case 'REPORTS': return <Reports cases={cases} />;
            case 'PATROL': return <AlleyPatrol pendingCases={pendingPatrolCases} onSetPendingCases={setPendingPatrolCases} onCreateCase={handleCreateCaseFromPatrol} />;
            case 'ANIMAL_CONTROL': return <AnimalControlDashboard logs={complaintLogs} onUpdateLogs={handleUpdateLogs} />;
            case 'MAIL': return <MailingView cases={cases} />;
            case 'LIST': default:
                if (activeTab === 'due') {
                    return <CaseList cases={dueCases} onSelectCase={handleSelectCase} onNewCase={handleNewCase} listType="due" />;
                }
                if (activeTab === 'abatement') {
                    return showAbatementReport 
                        ? <AbatementReport cases={abatementCases} onBack={() => setShowAbatementReport(false)} />
                        : <CaseList cases={abatementCases} onSelectCase={handleSelectCase} onNewCase={handleNewCase} listType="abatement" onGenerateReport={() => setShowAbatementReport(true)} />;
                }
                if (activeTab === 'continual-abatement') {
                    return <CaseList cases={continualAbatementCases} onSelectCase={handleSelectCase} onNewCase={handleNewCase} listType="continual-abatement" />;
                }
                 return <CaseList cases={cases} onSelectCase={handleSelectCase} onNewCase={handleNewCase} listType="all" />;
        }
    };

    return (
        <div className="app-container">
             <header className="app-header no-print">
                 <div style={{flex: '0 0 70px'}}>
                    <button 
                        onClick={() => { setView('PATROL'); setActiveTab('patrol'); }}
                        style={{
                            background: 'rgba(2, 132, 199, 0.1)', 
                            border: '1px solid var(--primary-color)', 
                            color: 'var(--primary-color)', 
                            padding: '0.4rem 0.8rem', 
                            borderRadius: '4px', 
                            cursor: 'pointer',
                            fontSize: '0.85rem',
                            fontWeight: 700
                        }}
                    >
                        Patrol
                    </button>
                 </div>
                <h1>Commerce Code Enf.</h1>
                <div style={{flex: '0 0 70px'}}></div>
            </header>
            <nav className="main-nav no-print">
                <button className={activeTab === 'tasks' ? 'active' : ''} onClick={() => changeTab('tasks', 'TASKS')}>Tasks</button>
                <button className={activeTab === 'all' ? 'active' : ''} onClick={() => changeTab('all', 'LIST')}>Cases</button>
                <button className={activeTab === 'due' ? 'active' : ''} onClick={() => changeTab('due', 'LIST')}>Due</button>
                <button className={activeTab === 'abatement' ? 'active' : ''} onClick={() => changeTab('abatement', 'LIST')}>Abatement</button>
                <button className={activeTab === 'mail' ? 'active' : ''} onClick={() => changeTab('mail', 'MAIL')}>Mail</button>
                <button className={activeTab === 'continual-abatement' ? 'active' : ''} onClick={() => changeTab('continual-abatement', 'LIST')}>Continual</button>
                <button className={activeTab === 'properties' ? 'active' : ''} onClick={() => changeTab('properties', 'PROPERTIES')}>Directory</button>
                <button className={activeTab === 'log' ? 'active' : ''} onClick={() => changeTab('log', 'LOG')}>Logs</button>
                <button className={activeTab === 'animal' ? 'active' : ''} onClick={() => changeTab('animal', 'ANIMAL_CONTROL')}>Animal</button>
                <button className={activeTab === 'reports' ? 'active' : ''} onClick={() => changeTab('reports', 'REPORTS')}>Reports</button>
                <button className={activeTab === 'admin' ? 'active' : ''} onClick={() => changeTab('admin', 'ADMIN')}>Admin</button>
                <button className={activeTab === 'templates' ? 'active' : ''} onClick={() => changeTab('templates', 'TEMPLATES')}>Templates</button>
            </nav>
            <main className="main-content">
                {renderContent()}
            </main>
        </div>
    );
};

export default App;

import React, { useState, useMemo } from 'react';
import { Property, Case } from '../types';
import { compareStreets } from '../utils';
import { dataService } from '../googleSheetsService';

const PropertyEditor: React.FC<{
    property: Property;
    onSave: (property: Property) => void;
    onCancel: () => void;
}> = ({ property, onSave, onCancel }) => {
    const [edited, setEdited] = useState(property);

    const handleChange = (field: keyof Property, value: any) => {
        setEdited(prev => ({ ...prev, [field]: value }));
    };

    const handleOwnerChange = (field: keyof Property['ownerInfo'], value: string) => {
        setEdited(prev => ({ ...prev, ownerInfo: { ...prev.ownerInfo, [field]: value } }));
    };

    const handleResidentChange = (field: keyof Property['residentInfo'], value: string) => {
        setEdited(prev => ({ ...prev, residentInfo: { ...prev.residentInfo, [field]: value } }));
    };

    return (
        <div className="card-editor">
            <div className="form-group">
                <label>Street Address</label>
                <input value={edited.streetAddress} onChange={e => handleChange('streetAddress', e.target.value)} />
            </div>
            <h4 style={{marginTop: '1.5rem'}}>Owner Information</h4>
            <div className="form-group">
                <label>Owner Name</label>
                <input value={edited.ownerInfo.name} onChange={e => handleOwnerChange('name', e.target.value)} />
            </div>
            <div className="form-group">
                <label>Owner Mailing Address</label>
                <textarea value={edited.ownerInfo.mailingAddress} onChange={e => handleOwnerChange('mailingAddress', e.target.value)} />
            </div>
            <div className="form-group">
                <label>Owner Phone</label>
                <input value={edited.ownerInfo.phone} onChange={e => handleOwnerChange('phone', e.target.value)} />
            </div>
             <h4 style={{marginTop: '1.5rem'}}>Resident Information</h4>
             <div className="form-group">
                <label>Resident Name</label>
                <input value={edited.residentInfo.name} onChange={e => handleResidentChange('name', e.target.value)} />
            </div>
            <div className="form-group">
                <label>Resident Phone</label>
                <input value={edited.residentInfo.phone} onChange={e => handleResidentChange('phone', e.target.value)} />
            </div>
            <div className="button-group" style={{ justifyContent: 'flex-end', marginTop: '1.5rem' }}>
                <button className="button secondary-action" onClick={onCancel}>Cancel</button>
                <button className="button primary-action" onClick={() => onSave(edited)}>Save Changes</button>
            </div>
        </div>
    );
};

const PropertyDirectory: React.FC<{
    cases: Case[];
    properties: Property[];
    onSelectCase: (caseId: string) => void;
    onSaveProperty: (property: Property) => void;
    onDeleteProperty: (propertyId: string) => void;
}> = ({ cases, properties, onSelectCase, onSaveProperty, onDeleteProperty }) => {
    const [searchTerm, setSearchTerm] = useState('');
    const [isArchiving, setIsArchiving] = useState(false);
    const [archiveProgress, setArchiveProgress] = useState('');
    const [editingPropertyId, setEditingPropertyId] = useState<string | null>(null);

    const filteredProperties = useMemo(() => {
        const sorted = [...properties].sort((a, b) => compareStreets(a.streetAddress, b.streetAddress));
        if (!searchTerm) return sorted;
        const lowerSearch = searchTerm.toLowerCase();
        return sorted.filter(p =>
            p.streetAddress.toLowerCase().includes(lowerSearch) ||
            p.ownerInfo.name?.toLowerCase().includes(lowerSearch)
        );
    }, [properties, searchTerm]);

    const handleDownloadFullArchive = async () => {
        if (!window.confirm("Download Full Archive? This will gather photos and documents for ALL properties and may take several minutes. Please do not close the tab.")) return;
        setIsArchiving(true);
        setArchiveProgress('Starting archive...');
        try {
            await dataService.downloadFullArchive(filteredProperties, cases, (msg) => setArchiveProgress(msg));
            setArchiveProgress('Download started.');
        } catch (e: any) {
            alert(`Archive failed: ${e.message}`);
            setArchiveProgress('');
        } finally {
            setIsArchiving(false);
        }
    };

    const handleDownloadPropertyArchive = async (prop: Property, linkedCases: Case[]) => {
        if (!window.confirm(`Download all records for ${prop.streetAddress}?`)) return;
        setIsArchiving(true);
        setArchiveProgress(`Archiving ${prop.streetAddress}...`);
        try {
            await dataService.downloadPropertyArchive(prop, linkedCases);
            setArchiveProgress('');
        } catch (e: any) {
            alert(`Archive failed: ${e.message}`);
        } finally {
            setIsArchiving(false);
        }
    };

    const handleSave = (prop: Property) => {
        onSaveProperty(prop);
        setEditingPropertyId(null);
    };

    const handleAddNew = () => {
        const newProp: Property = {
            id: `prop-${self.crypto.randomUUID()}`,
            streetAddress: '',
            ownerInfo: { name: '', mailingAddress: '', phone: '' },
            residentInfo: { name: '', phone: '' },
            isVacant: false,
            dilapidationNotes: ''
        };
        onSaveProperty(newProp);
        setEditingPropertyId(newProp.id);
    };

    const handleDelete = (id: string) => {
        if (window.confirm("Are you sure you want to delete this property record?")) {
            onDeleteProperty(id);
        }
    };

    return (
        <div className="tab-content">
            <div className="card" style={{backgroundColor: '#f0f7ff', borderColor: 'var(--secondary-color)'}}>
                <div style={{display: 'flex', flexDirection: 'column', gap: '0.5rem'}}>
                    <h3 style={{margin: 0}}>Data Management</h3>
                    <div className="button-group">
                        <button className="button primary-action" onClick={handleAddNew}>Add New Property</button>
                        <button className="button secondary-action" onClick={handleDownloadFullArchive} disabled={isArchiving}>
                            {isArchiving ? <span className="loader" /> : 'Download Archive (ZIP)'}
                        </button>
                    </div>
                    {archiveProgress && <div className="status-message ok" style={{marginTop: '0.5rem'}}>{archiveProgress}</div>}
                </div>
            </div>

            <div className="search-bar">
                <svg className="search-icon" xmlns="http://www.w3.org/2000/svg" width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><circle cx="11" cy="11" r="8"></circle><line x1="21" y1="21" x2="16.65" y2="16.65"></line></svg>
                <input type="text" placeholder="Search by address or owner..." value={searchTerm} onChange={e => setSearchTerm(e.target.value)} />
            </div>

            {filteredProperties.length > 0 ? (
                filteredProperties.map(prop => {
                    const linkedCases = cases.filter(c => c.address.street.toLowerCase() === prop.streetAddress.toLowerCase());
                    if (editingPropertyId === prop.id) {
                        return <div key={prop.id} className="card editing"><PropertyEditor property={prop} onSave={handleSave} onCancel={() => setEditingPropertyId(null)} /></div>
                    }
                    return (
                        <div key={prop.id} className="card" style={{marginTop: '1.5rem'}}>
                            <div style={{display: 'flex', justifyContent: 'space-between', alignItems: 'center'}}>
                                <div>
                                    <h3 style={{marginTop: 0, marginBottom: '0.25rem'}}>{prop.streetAddress}</h3>
                                    <span style={{color: 'var(--dark-gray)'}}>Owner: {prop.ownerInfo.name || 'N/A'}</span>
                                </div>
                                <div className="button-group">
                                    <button className="button" onClick={() => setEditingPropertyId(prop.id)}>Edit</button>
                                </div>
                            </div>
                            <div className="note" style={{marginTop: '1rem'}}>
                                <p><strong>Mailing Address:</strong> {prop.ownerInfo.mailingAddress || 'N/A'}</p>
                                <p><strong>Owner Phone:</strong> {prop.ownerInfo.phone || 'N/A'}</p>
                            </div>

                            <div style={{marginTop: '1rem', display: 'flex', justifyContent: 'space-between', alignItems: 'center', flexWrap: 'wrap', gap: '1rem'}}>
                                <button 
                                    className="button secondary-action" 
                                    style={{fontSize: '0.85rem', padding: '0.5rem 1rem'}}
                                    onClick={() => handleDownloadPropertyArchive(prop, linkedCases)}
                                    disabled={isArchiving}
                                >
                                    Download Records (ZIP)
                                </button>
                                 <button className="button danger-action" style={{fontSize: '0.85rem', padding: '0.5rem 1rem'}} onClick={() => handleDelete(prop.id)}>Delete Property</button>
                            </div>

                            {linkedCases.length > 0 && (
                                <>
                                    <h4 style={{marginTop: '1.5rem'}}>Linked Cases ({linkedCases.length})</h4>
                                    {linkedCases.map(c => (
                                        <div key={c.id} className="report-case-item" onClick={() => onSelectCase(c.id)} style={{cursor: 'pointer'}}>
                                            <div className="info"><strong>{c.caseId}:</strong> {c.violation.type}</div>
                                            <div className="details">
                                                <span><strong>Created:</strong> {c.dateCreated}</span>
                                                <span><strong>Status:</strong> {c.status}</span>
                                            </div>
                                        </div>
                                    ))}
                                </>
                            )}
                        </div>
                    );
                })
            ) : (
                <div className="card empty-state" style={{marginTop: '1.5rem'}}>
                    <p>{searchTerm ? 'No properties match your search.' : 'No properties found.'}</p>
                </div>
            )}
        </div>
    );
};

export default PropertyDirectory;

