        dataChunks.push(jsonString.substring(i, i + CHUNK_SIZE));
    }
    const newChunkCount = dataChunks.length;

    const metadata = { chunkCount: newChunkCount };
    const values = [[JSON.stringify(metadata), ...dataChunks]];

    const body = { values };
    const writeResponse = await fetch(`https://sheets.googleapis.com/v4/spreadsheets/${fileId}/values/A1?valueInputOption=RAW`, {
        method: 'PUT',
        headers: { 'Authorization': `Bearer ${token}`, 'Content-Type': 'application/json' },
        body: JSON.stringify(body)
    });

    if (!writeResponse.ok) {
        throw await handleGoogleApiError(writeResponse, "Failed to write to Google Sheet.");
    }

    const startClearColIndex = newChunkCount + 2;
    const startClearColName = toColumnName(startClearColIndex);
    const clearRange = `${startClearColName}1:1`;

    await fetch(`https://sheets.googleapis.com/v4/spreadsheets/${fileId}/values/${clearRange}:clear`, {
        method: 'POST',
        headers: { 'Authorization': `Bearer ${token}`, 'Content-Type': 'application/json' },
        body: JSON.stringify({})
    });
};

