// Helper: Adds a case's contents into a specific folder within a JSZip instance
const addCaseToZip = async (zipFolder: JSZip, caseData: Case) => {
    // 1. Create Case Report HTML
    let reportHtml = `
    <html>
    <head><style>body { font-family: sans-serif; padding: 2rem; } h1 { border-bottom: 1px solid #ccc; } .field { margin: 10px 0; } label { font-weight: bold; }</style></head>
    <body>
        <h1>Case Report: ${caseData.caseId}</h1>
        <div class="field"><label>Status:</label> ${caseData.status}</div>
        <div class="field"><label>Address:</label> ${caseData.address.street}</div>
        <div class="field"><label>Violation:</label> ${caseData.violation.type}</div>
        <div class="field"><label>Date Created:</label> ${caseData.dateCreated}</div>
        <hr/>
        <h3>Owner Info</h3>
        <div class="field"><label>Name:</label> ${caseData.ownerInfo.name}</div>
        <div class="field"><label>Mailing:</label> ${caseData.ownerInfo.mailingAddress}</div>
        <hr/>
        <h3>Case Notes</h3>
        <ul>
            ${caseData.evidence.notes.map(n => `<li><strong>${n.date}:</strong> ${n.text}</li>`).join('')}
        </ul>
    </body>
    </html>
    `;
    zipFolder.file("Case_Report.html", reportHtml);

    // 2. Photos
    const photoFolder = zipFolder.folder("Evidence Photos");
    const allPhotos = [...(caseData.evidence.photos || [])];
    if (caseData.abatement?.photos?.before) allPhotos.push(...caseData.abatement.photos.before);
    if (caseData.abatement?.photos?.after) allPhotos.push(...caseData.abatement.photos.after);

    const photoPromises = allPhotos.map(async (photo, i) => {
        try {
            const blob = await fetchBlobFromDrive(photo.id);
            const ext = blob.type.split('/')[1] || 'jpg';
            photoFolder?.file(`Photo_${i+1}.${ext}`, blob);
        } catch (e) {
            console.warn(`Failed to download photo ${photo.id}`, e);
            photoFolder?.file(`Photo_${i+1}_FAILED.txt`, "Could not download");
        }
    });

    // 3. Generated Documents
    const docFolder = zipFolder.folder("Documents");
    const docPromises = [];

    caseData.notices.forEach((n, i) => {
        docPromises.push(async () => {
            try {
                const docId = getDocIdFromUrl(n.docUrl);
                const blob = await fetchDocAsPdf(docId);
                docFolder?.file(`${n.title}.pdf`, blob);
            } catch (e) {
                console.warn(`Failed to download notice ${n.title}`, e);
            }
        });
    });

    if (caseData.abatement?.statementOfCostDocUrl) {
        docPromises.push(async () => {
             try {
                const docId = getDocIdFromUrl(caseData.abatement!.statementOfCostDocUrl!);
                const blob = await fetchDocAsPdf(docId);
                docFolder?.file(`Statement_of_Cost.pdf`, blob);
            } catch(e) { console.warn(e); }
        });
    }
    if (caseData.abatement?.noticeOfLienDocUrl) {
        docPromises.push(async () => {
             try {
                const docId = getDocIdFromUrl(caseData.abatement!.noticeOfLienDocUrl!);
                const blob = await fetchDocAsPdf(docId);
                docFolder?.file(`Notice_of_Lien.pdf`, blob);
            } catch(e) { console.warn(e); }
        });
    }

    await Promise.all([...photoPromises, ...docPromises.map(fn => fn())]);
};

export const downloadCaseArchive = async (caseData: Case) => {
    const zip = new JSZip();
    // For single case download, put everything in the root of the zip
    await addCaseToZip(zip, caseData); 
    const content = await zip.generateAsync({ type: "blob" });
    const filename = `${caseData.address.street.replace(/[^a-z0-9]/gi, '_')}__${caseData.caseId}.zip`;
    saveAs(content, filename);
};

export const downloadPropertyArchive = async (property: Property, cases: Case[]) => {
    const zip = new JSZip();
    const safeAddr = property.streetAddress.replace(/[^a-z0-9 ]/gi, '_');

    // Folder structure: ZipRoot -> CaseID -> Content
    for (const c of cases) {
        const caseFolder = zip.folder(`${c.caseId} - ${c.violation.type.replace(/[^a-z0-9]/gi, '_')}`);
        if (caseFolder) {
            await addCaseToZip(caseFolder, c);
        }
    }

    const content = await zip.generateAsync({ type: "blob" });
    const filename = `Property_Records_${safeAddr}.zip`;
    saveAs(content, filename);
};

export const downloadFullArchive = async (properties: Property[], cases: Case[], onProgress: (msg: string) => void) => {
    const zip = new JSZip();
    let count = 0;
    const total = properties.length;

    for (const prop of properties) {
        count++;
        onProgress(`Processing ${prop.streetAddress} (${count}/${total})...`);

        const propCases = cases.filter(c => c.address.street.toLowerCase() === prop.streetAddress.toLowerCase());
        if (propCases.length === 0) continue;

        const safeAddr = prop.streetAddress.replace(/[^a-z0-9 ]/gi, '_');
        // Folder structure: ZipRoot -> Address -> CaseID -> Content
        const propFolder = zip.folder(safeAddr);

        if (propFolder) {
             for (const c of propCases) {
                const caseFolder = propFolder.folder(`${c.caseId} - ${c.violation.type.replace(/[^a-z0-9]/gi, '_')}`);
                if (caseFolder) {
                    await addCaseToZip(caseFolder, c);
                }
            }
        }
    }

    onProgress("Compressing archive... (this may take a moment)");
    const content = await zip.generateAsync({ type: "blob" });
    const filename = `Full_Code_Enforcement_Archive_${new Date().toISOString().split('T')[0]}.zip`;
    saveAs(content, filename);
};


export const dataService = {
    // FIX: Update signature to reflect that it returns properties as well.
    getAllData: async (): Promise<{ cases: Case[]; properties: Property[] }> => getSheetData(),
    getAllCases: async (): Promise<Case[]> => (await getSheetData()).cases,
    getCaseById: async (id: string): Promise<Case | undefined> => (await getSheetData()).cases.find(c => c.id === id),
    saveCase: async (caseData: Case): Promise<Case> => {
        const data = await getSheetData();
        const index = data.cases.findIndex(c => c.id === caseData.id);
        if (index > -1) {
            data.cases[index] = caseData;
        } else {
            data.cases.push(caseData);
        }
        await writeSheetData(data);
        return caseData;
    },
    deleteCase: async (caseId: string): Promise<void> => {
        const data = await getSheetData();
        const initialLength = data.cases.length;
        data.cases = data.cases.filter(c => c.id !== caseId);
        if (data.cases.length === initialLength) {
            console.warn(`Case with ID ${caseId} not found for deletion.`);
        }
        await writeSheetData(data);
    },
    // FIX: Implement the missing saveProperty method.
    saveProperty: async (propData: Property): Promise<void> => {
        const data = await getSheetData();
        const index = data.properties.findIndex(p => p.id === propData.id);
        if (index > -1) {
            data.properties[index] = propData;
        } else {
            data.properties.push(propData);
        }
        await writeSheetData(data);
    },
    // FIX: Implement the missing deleteProperty method.
    deleteProperty: async (propId: string): Promise<void> => {
        const data = await getSheetData();
        data.properties = data.properties.filter(p => p.id !== propId);
        await writeSheetData(data);
    },
    uploadCasePhotos,
    uploadAbatementPhotos,
    downloadCaseArchive,
    downloadPropertyArchive,
    downloadFullArchive
};

